{
  "name": "SonoAudit Pro: Fetal Medicine Report Assistant",
  "description": "A high-level clinical audit and reporting tool for fetal ultrasound images, following ISUOG, ACOG, and FMF guidelines. It extracts biometric data, evaluates anatomical landmarks, and generates structured medical reports using Gemini 3 Pro.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface AnalysisResult {
  reportMarkdown: string;
  timestamp: string;
}

export interface ProcessingState {
  isAnalyzing: boolean;
  progressMessage: string;
  error: string | null;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are an expert Fetal Medicine Consultant and technical auditor. 
Analyze the provided fetal ultrasound image in strict accordance with ISUOG, ACOG, and FMF guidelines.

EXACT PIPELINE:
Phase 1: Data Extraction (OCR & Metadata)
- Extract visible biometric measurements (BPD, HC, AC, FL, NT).
- Gestational Age (GA), EDD, Exam Date, and Machine Settings (Frequency/MI/TI).

Phase 2: Anatomical & Quality Quality Assessment (The "Audit")
1. Plane Identification: Identify the plane (Transthalmic, Transabdominal, etc.).
2. Landmark Verification:
   - Head: Check for Falx cerebri, CSP, Thalami.
   - Abdomen: Stomach bubble, Portal vein (J-shape), circular outline.
   - Femur: Horizontal orientation, diaphysis ends.
3. Technical Scoring:
   - Magnification: >75% of screen? (Pass/Fail).
   - Caliper Placement: On-to-On for NT; Outer-to-Outer for BPD; Outer-to-Bone for FL.
   - Angle of Insonation: Optimal (<15 deg) or steep.

Phase 3: Clinical Report Generation
Generate a structured report in Markdown.
CRITICAL: 
- If landmarks (e.g. CSP) are missing in BPD view, state "Image does not meet ISUOG criteria for accurate BPD measurement due to missing CSP."
- Do not hallucinate values.
- Maintain a formal, academic medical tone.
`;

export async function analyzeUltrasound(image64: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Using gemini-3-pro-preview as it's the strongest reasoning model with multimodal support
  const model = 'gemini-3-pro-preview';

  const prompt = "Please execute the full fetal medicine audit and report generation pipeline on this ultrasound image.";

  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: image64,
    },
  };

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: model,
      contents: { 
        parts: [
          { text: prompt },
          imagePart
        ] 
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1, // Keep it deterministic for medical reporting
      },
    });

    if (!response.text) {
      throw new Error("No analysis generated from the model.");
    }

    return response.text;
  } catch (error: any) {
    console.error("Gemini Analysis Error:", error);
    throw new Error(error.message || "Failed to analyze image. Please check your API configuration.");
  }
}

import React, { useState, useCallback } from 'react';
import { analyzeUltrasound } from './services/geminiService';
import { AnalysisResult, ProcessingState } from './types';
import Header from './components/Header';
import ImageUploader from './components/ImageUploader';
import ReportDisplay from './components/ReportDisplay';
import LoadingOverlay from './components/LoadingOverlay';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  const handleImageUpload = (base64: string) => {
    setImage(base64);
    setAnalysis(null);
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (!image) return;

    setStatus({
      isAnalyzing: true,
      progressMessage: 'Initializing high-level clinical audit...',
      error: null,
    });

    try {
      // Step-by-step progress simulation for better UX
      const messages = [
        'Extracting OCR metadata and biometrics...',
        'Verifying anatomical landmarks (ISUOG/FMF)...',
        'Scoring image quality and caliper placement...',
        'Compiling clinical impression and report...',
      ];

      let msgIndex = 0;
      const interval = setInterval(() => {
        if (msgIndex < messages.length) {
          setStatus(prev => ({ ...prev, progressMessage: messages[msgIndex++] }));
        }
      }, 2000);

      const reportMarkdown = await analyzeUltrasound(image.split(',')[1]);

      clearInterval(interval);
      setAnalysis({
        reportMarkdown,
        timestamp: new Date().toLocaleString(),
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      setStatus({
        isAnalyzing: false,
        progressMessage: '',
        error: err.message || 'An unexpected error occurred during analysis.',
      });
    }
  };

  const reset = () => {
    setImage(null);
    setAnalysis(null);
    setStatus({ isAnalyzing: false, progressMessage: '', error: null });
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-5xl">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Upload & Actions */}
          <div className="lg:col-span-5 space-y-6">
            <section className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 overflow-hidden">
              <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
                <i className="fas fa-upload text-blue-600"></i>
                Ultrasound Image Upload
              </h2>
              <ImageUploader 
                onUpload={handleImageUpload} 
                currentImage={image} 
                disabled={status.isAnalyzing}
              />

              {image && !analysis && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-6 bg-blue-600 hover:bg-blue-700 disabled:bg-blue-300 text-white font-semibold py-3 px-4 rounded-lg transition-all flex items-center justify-center gap-2"
                >
                  <i className="fas fa-microscope"></i>
                  {status.isAnalyzing ? 'Analyzing...' : 'Generate Clinical Audit'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={reset}
                  className="w-full mt-4 text-slate-500 hover:text-slate-800 text-sm font-medium transition-colors"
                >
                  Start New Audit
                </button>
              )}
            </section>

            <section className="bg-blue-50 border border-blue-100 rounded-xl p-6">
              <h3 className="text-sm font-bold text-blue-800 uppercase tracking-wider mb-2">Audit Guidelines</h3>
              <ul className="text-sm text-blue-700 space-y-2 list-disc pl-4">
                <li>ISUOG Practice Guidelines (2nd Trimester)</li>
                <li>Fetal Medicine Foundation (NT criteria)</li>
                <li>ACOG Committee Opinion No. 700</li>
              </ul>
            </section>
          </div>

          {/* Right Column: Results */}
          <div className="lg:col-span-7">
            {status.error && (
              <div className="bg-red-50 border border-red-200 text-red-700 p-4 rounded-xl mb-6 flex gap-3 items-start">
                <i className="fas fa-exclamation-circle mt-1"></i>
                <p>{status.error}</p>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="bg-slate-100 border-2 border-dashed border-slate-300 rounded-xl p-12 text-center flex flex-col items-center justify-center min-h-[400px]">
                <div className="w-16 h-16 bg-slate-200 rounded-full flex items-center justify-center mb-4 text-slate-400">
                  <i className="fas fa-file-medical text-2xl"></i>
                </div>
                <h3 className="text-slate-600 font-medium mb-1">Waiting for Analysis</h3>
                <p className="text-slate-400 text-sm max-w-xs">
                  Upload an ultrasound image to generate a high-level clinical report following ISUOG/FMF standards.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay 
                analysis={analysis} 
              />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="bg-slate-900 text-slate-400 py-6 text-center text-xs">
        <div className="container mx-auto">
          <p className="mb-2">SonoAudit Pro &copy; {new Date().getFullYear()} - Professional Clinical Decision Support System</p>
          <p className="max-w-xl mx-auto opacity-60">
            Disclaimer: This tool is for educational and auditing purposes for medical professionals only. 
            It is not a substitute for expert clinical judgment. Always verify findings manually.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

