import React, { useRef } from 'react';

interface Props {
  onUpload: (base64: string) => void;
  currentImage: string | null;
  disabled: boolean;
}

const ImageUploader: React.FC<Props> = ({ onUpload, currentImage, disabled }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        onUpload(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const triggerUpload = () => {
    if (!disabled) {
      fileInputRef.current?.click();
    }
  };

  return (
    <div className="space-y-4">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        accept="image/*"
        className="hidden"
        disabled={disabled}
      />

      {!currentImage ? (
        <div 
          onClick={triggerUpload}
          className={`group border-2 border-dashed border-slate-200 rounded-xl p-8 transition-all cursor-pointer flex flex-col items-center justify-center bg-slate-50 hover:bg-blue-50 hover:border-blue-300 ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
        >
          <div className="w-14 h-14 bg-white rounded-full shadow-sm flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
            <i className="fas fa-image text-slate-400 group-hover:text-blue-500"></i>
          </div>
          <p className="text-sm font-semibold text-slate-600">Browse Image File</p>
          <p className="text-xs text-slate-400 mt-1">Standard Ultrasound Snapshot (JPEG, PNG)</p>
        </div>
      ) : (
        <div className="relative rounded-lg overflow-hidden border border-slate-200 shadow-inner bg-slate-100 aspect-[4/3] flex items-center justify-center group">
          <img 
            src={currentImage} 
            alt="Ultrasound Preview" 
            className="max-w-full max-h-full object-contain"
          />
          {!disabled && (
            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
              <button 
                onClick={triggerUpload}
                className="bg-white text-slate-900 px-4 py-2 rounded-full text-xs font-bold hover:bg-blue-50 flex items-center gap-2"
              >
                <i className="fas fa-sync-alt"></i> Replace Image
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

export default ImageUploader;

import React from 'react';
import { AnalysisResult } from '../types';

interface Props {
  analysis: AnalysisResult;
}

const ReportDisplay: React.FC<Props> = ({ analysis }) => {
  // Simple markdown-to-html approach for common report elements
  // This avoids heavy dependencies while maintaining formatting
  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Bold headers
      if (line.startsWith('#### ')) {
        return <h4 key={i} className="text-md font-bold text-slate-800 mt-6 mb-2 uppercase tracking-wide border-b border-slate-100 pb-1">{line.replace('#### ', '')}</h4>;
      }
      if (line.startsWith('### ')) {
        return <h3 key={i} className="text-lg font-bold text-blue-900 mt-8 mb-4 border-l-4 border-blue-600 pl-3">{line.replace('### ', '')}</h3>;
      }

      // List items
      if (line.trim().startsWith('* ')) {
        return <li key={i} className="ml-4 text-slate-700 leading-relaxed mb-1">{line.trim().substring(2)}</li>;
      }

      // Table handling (Basic)
      if (line.includes('|') && !line.includes('---')) {
        const cells = line.split('|').filter(c => c.trim().length > 0);
        const isHeader = i === 0 || text.split('\n')[i-1]?.startsWith('####'); // Simple heuristic

        return (
          <div key={i} className={`flex border-b border-slate-100 py-2 ${isHeader ? 'bg-slate-50 font-bold' : ''}`}>
            {cells.map((cell, idx) => (
              <span key={idx} className="flex-1 px-2 text-sm text-slate-700">{cell.trim()}</span>
            ))}
          </div>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-2" />;

      return <p key={i} className="text-slate-700 leading-relaxed mb-2">{line}</p>;
    });
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="bg-slate-900 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-3">
          <i className="fas fa-file-medical text-blue-400"></i>
          <h2 className="text-white font-bold tracking-wide uppercase text-sm">Clinical Audit Report</h2>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => window.print()} 
            className="text-slate-400 hover:text-white transition-colors p-2"
            title="Export to PDF"
          >
            <i className="fas fa-file-pdf"></i>
          </button>
          <button 
            className="text-slate-400 hover:text-white transition-colors p-2"
            title="Copy to EMR"
            onClick={() => {
                navigator.clipboard.writeText(analysis.reportMarkdown);
                alert('Report copied to clipboard.');
            }}
          >
            <i className="fas fa-copy"></i>
          </button>
        </div>
      </div>

      <div className="p-8 font-serif bg-[url('https://www.transparenttextures.com/patterns/white-diamond.png')]">
        <div className="flex justify-between items-start border-b-2 border-slate-800 pb-4 mb-8">
          <div>
            <div className="text-2xl font-bold text-slate-900 tracking-tight">SonoAudit Pro System</div>
            <div className="text-xs text-slate-500 uppercase font-bold tracking-widest mt-1">Automated Quality Review</div>
          </div>
          <div className="text-right">
            <div className="text-xs font-bold text-slate-400 uppercase">Analysis Date</div>
            <div className="text-sm font-bold text-slate-800">{analysis.timestamp}</div>
          </div>
        </div>

        <div className="report-content prose prose-slate max-w-none">
          {formatMarkdown(analysis.reportMarkdown)}
        </div>

        <div className="mt-12 pt-6 border-t border-dashed border-slate-200 flex justify-between items-end">
          <div className="text-[10px] text-slate-400 italic max-w-xs">
            This report was generated using SonoAudit Pro V3.2.0. Clinical correlation is mandatory.
          </div>
          <div className="text-right">
            <div className="w-32 h-12 border-b border-slate-300 mb-1 flex items-center justify-center italic text-slate-300 font-serif">
                SonoAudit Digital ID
            </div>
            <div className="text-[10px] text-slate-500 font-bold uppercase tracking-tighter">System Authenticated Signature</div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ReportDisplay;

