import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are an expert Sonographer and Consultant. 
Analyze the provided ultrasound image and generate a concise clinical report.

CORE PRINCIPLES:
1. Be adaptive: Identify what is shown (Fetal, Gyn, or Adnexal) and ONLY report on relevant findings for that specific context.
2. No negative checklist: Do NOT list missing structures or what is NOT seen (e.g., do not say "No fetal pole seen" if it's clearly an ovarian scan).
3. Direct & Professional: Go straight to the findings. Maintain a formal, academic medical tone.
4. Data Extraction: Extract any measurements or metadata visible on screen relevant to the identified view.

OUTPUT FORMAT (STRICTLY FOLLOW THIS STRUCTURE):

**1. Technical Details:**
- Exam Type: [e.g., TVS / TAS]
- Region of Interest: [e.g., Right Ovary / Uterus / Fetal Head]

**2. Findings:**
- **Anatomy:** Describe the visible structure clearly.
- **Pathology/Features:** [e.g., "Enlarged ovarian stroma with peripheral follicles."]
- **Measurements:** Extract numbers visible on screen relevant to this view.

**3. Conclusion:**
- A single sentence summary of the diagnosis or main observation.
`;

export async function analyzeUltrasound(image64: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Using gemini-3-pro-preview for high-quality multimodal analysis
  const model = 'gemini-3-pro-preview';

  const prompt = "Please analyze this ultrasound image and generate a concise report following the specified structure.";

  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: image64,
    },
  };

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: model,
      contents: { 
        parts: [
          { text: prompt },
          imagePart
        ] 
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1,
      },
    });

    if (!response.text) {
      throw new Error("No analysis generated from the model.");
    }

    return response.text;
  } catch (error: any) {
    console.error("Gemini Analysis Error:", error);
    throw new Error(error.message || "Failed to analyze image. Please check your API configuration.");
  }
}

import React, { useState, useCallback } from 'react';
import { analyzeUltrasound } from './services/geminiService';
import { AnalysisResult, ProcessingState } from './types';
import Header from './components/Header';
import ImageUploader from './components/ImageUploader';
