import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "OGXAI", an expert AI Consultant in Obstetrics & Gynecology.
Analyze the attached ultrasound image and generate a concise, focused clinical report.

CORE DIRECTIVES:
1. Adaptive Analysis: Identify the specific view (Fetal Biometry, Gyn/Adnexa, Early Pregnancy) and report ONLY on relevant features.
2. No Fluff: Do not list missing structures irrelevant to the view (e.g., do not mention "no fetal heart" if looking at an ovary).
3. Strict Professionalism: Use standard medical terminology (ISUOG/ACOG style).

OUTPUT STRUCTURE:

**1. Scan Type:** [e.g., Transvaginal Gyn / Fetal Transthalamic View]

**2. Findings:**
* **Anatomy:** [Describe the main structure seen, e.g., "Right ovary visualized."]
* **Morphology/Pathology:** [Describe features, e.g., "Ovary is enlarged with >12 peripherally arranged follicles ('string of pearls'). Stroma appears echogenic."]
* **Biometry:** [Extract ONLY relevant on-screen measurements, if any.]

**3. Clinical Impression:**
* [One definitive sentence, e.g., "Features consistent with Polycystic Ovarian Morphology (PCOM)."]

---
*Report generated by OGXAI Analysis System*
`;

export async function analyzeUltrasound(image64: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Using gemini-3-pro-preview for high-level medical reasoning and multimodal analysis
  const model = 'gemini-3-pro-preview';

  const prompt = "Perform clinical analysis on this scan for the OGXAI reporting system.";

  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: image64,
    },
  };

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: model,
      contents: { 
        parts: [
          { text: prompt },
          imagePart
        ] 
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.1, // High precision for medical reports
      },
    });

    if (!response.text) {
      throw new Error("No analysis generated from the OGXAI system.");
    }

    return response.text;
  } catch (error: any) {
    console.error("OGXAI Analysis Error:", error);
    throw new Error(error.message || "Failed to analyze image. Ensure the scan is clear and API is available.");
  }
}

