                  <i className="fas fa-notes-medical text-3xl"></i>
                </div>
                <h3 className="text-slate-800 font-bold text-xl mb-2">Awaiting Image Input</h3>
                <p className="text-slate-400 text-sm max-w-xs leading-relaxed">
                  Please upload a diagnostic ultrasound snapshot to initiate the OGXAI expert analysis pipeline.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay 
                analysis={analysis} 
