          >
            <i className="fas fa-file-pdf"></i>
          </button>
          <button 
            className="text-slate-400 hover:text-white transition-colors p-2"
            title="Copy to EMR"
            onClick={() => {
                navigator.clipboard.writeText(analysis.reportMarkdown);
                alert('Report copied to clipboard.');
            }}
          >
            <i className="fas fa-copy"></i>
          </button>
        </div>
      </div>

      <div className="p-10 font-serif bg-white">
        <div className="flex justify-between items-start border-b-2 border-slate-900 pb-6 mb-8">
          <div>
            <div className="text-3xl font-black text-slate-900 tracking-tighter">OGX<span className="text-indigo-600">AI</span></div>
            <div className="text-xs text-slate-500 uppercase font-bold tracking-widest mt-1">Expert AI OB/GYN Consultation System</div>
          </div>
          <div className="text-right">
            <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Consultation Ref</div>
            <div className="text-sm font-black text-slate-800 tracking-tight">#{Math.random().toString(36).substr(2, 9).toUpperCase()}</div>
            <div className="text-[10px] font-bold text-slate-400 uppercase mt-2 tracking-widest">Timestamp</div>
