import React, { useState } from 'react';
import { analyzeUltrasound } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  const handleImageUpload = (base64: string) => {
    setImage(base64);
    setAnalysis(null);
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (!image) return;

    // Check for API key selection to avoid shared quota limits
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setStatus({ ...status, progressMessage: 'Awaiting project connection...' });
        await window.aistudio.openSelectKey();
      }
    }

    setStatus({
      isAnalyzing: true,
      progressMessage: 'Initializing OGXAI consultation...',
      error: null,
    });

    try {
      const messages = [
        'Classifying scan modality...',
        'Mapping anatomical landmarks...',
        'Analyzing morphology & biometry...',
        'Finalizing consultation report...',
      ];

      let msgIndex = 0;
      const interval = setInterval(() => {
        if (msgIndex < messages.length) {
          setStatus(prev => ({ ...prev, progressMessage: messages[msgIndex++] }));
        }
      }, 1500);

      const reportMarkdown = await analyzeUltrasound(image.split(',')[1]);

      clearInterval(interval);
      setAnalysis({
        reportMarkdown,
        timestamp: new Date().toLocaleString(),
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      console.error("Clinical Analysis Error:", err);
      let errorMsg = err.message || 'The OGXAI core encountered a processing error.';

      // Specifically handle Quota/429 errors from the Gemini API
      if (errorMsg.includes('429') || errorMsg.includes('quota') || errorMsg.includes('RESOURCE_EXHAUSTED')) {
        errorMsg = "QUOTA LIMIT EXCEEDED: The shared free tier for Gemini 3 Pro is currently at capacity. To proceed with your clinical analysis, you must connect a personal API key from a paid Google Cloud project.";
      }

      // Handle invalid or deleted project/key
      if (errorMsg.includes('Requested entity was not found')) {
        errorMsg = "PROJECT NOT FOUND: The connected Google Cloud project is no longer valid. Please re-select a valid project.";
        if (window.aistudio) await window.aistudio.openSelectKey();
      }

      setStatus({
        isAnalyzing: false,
        progressMessage: '',
        error: errorMsg,
      });
    }
  };

  const handleOpenKeySelection = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setStatus(prev => ({ ...prev, error: null }));
    }
  };

  const reset = () => {
    setImage(null);
    setAnalysis(null);
    setStatus({ isAnalyzing: false, progressMessage: '', error: null });
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-10 max-w-5xl">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          <div className="lg:col-span-5 space-y-6">
            <section className="bg-white rounded-xl shadow-md border border-slate-200 p-8">
              <h2 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-3">
                <i className="fas fa-file-import text-indigo-600"></i>
                Input Ultrasound Scan
              </h2>
              <ImageUploader 
                onUpload={handleImageUpload} 
                currentImage={image} 
                disabled={status.isAnalyzing}
              />

              {image && !analysis && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-8 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white font-bold py-4 px-4 rounded-xl shadow-lg shadow-indigo-100 transition-all flex items-center justify-center gap-3"
                >
                  <i className="fas fa-brain"></i>
                  {status.isAnalyzing ? 'Processing...' : 'Start Clinical Consultation'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={reset}
                  className="w-full mt-6 text-slate-400 hover:text-indigo-600 text-sm font-bold uppercase tracking-widest transition-colors flex items-center justify-center gap-2"
                >
                  <i className="fas fa-redo-alt text-[10px]"></i>
                  New Consultation
                </button>
              )}
            </section>

            <section className="bg-indigo-900 text-indigo-100 rounded-xl p-8 shadow-inner overflow-hidden relative">
              <div className="relative z-10">
                <h3 className="text-xs font-black uppercase tracking-[0.2em] mb-4 opacity-70">Diagnostic Protocol</h3>
                <div className="space-y-4">
                    <div className="flex gap-4 items-start">
                        <div className="w-6 h-6 rounded bg-indigo-700 flex items-center justify-center shrink-0">
                            <i className="fas fa-check text-[10px]"></i>
                        </div>
                        <p className="text-xs leading-relaxed">Morphological analysis using Gemini 3 Pro reasoning.</p>
                    </div>
                    <div className="flex gap-4 items-start">
                        <div className="w-6 h-6 rounded bg-indigo-700 flex items-center justify-center shrink-0">
                            <i className="fas fa-check text-[10px]"></i>
                        </div>
                        <p className="text-xs leading-relaxed">Requires dedicated project quota for clinical throughput.</p>
                    </div>
                </div>
              </div>
              <div className="absolute -bottom-10 -right-10 opacity-10">
                 <i className="fas fa-stethoscope text-[160px]"></i>
              </div>
            </section>
          </div>

          <div className="lg:col-span-7">
            {status.error && (
              <div className="bg-red-50 border-l-4 border-red-500 text-red-800 p-6 rounded-r-xl mb-6 shadow-sm flex flex-col gap-4 animate-in fade-in slide-in-from-top-2">
                <div className="flex gap-4 items-start">
                  <i className="fas fa-exclamation-triangle mt-1 text-red-500"></i>
                  <div>
                      <h4 className="font-bold text-sm">Clinical Pipeline Interrupted</h4>
                      <p className="text-xs opacity-90 mt-1 leading-relaxed">{status.error}</p>
                  </div>
                </div>
                <div className="flex flex-wrap gap-3 mt-2">
                  <button 
                    onClick={handleOpenKeySelection}
                    className="text-[10px] font-black uppercase tracking-widest bg-indigo-600 text-white px-5 py-2.5 rounded-lg hover:bg-indigo-700 transition-colors shadow-md"
                  >
                    Connect Personal Project
                  </button>
                  <a 
                    href="https://ai.google.dev/gemini-api/docs/billing" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="text-[10px] font-bold uppercase tracking-widest border border-slate-300 text-slate-600 px-5 py-2.5 rounded-lg hover:bg-slate-50 transition-colors flex items-center gap-2"
                  >
                    <i className="fas fa-external-link-alt text-[8px]"></i>
                    Billing Setup
                  </a>
                </div>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="bg-white border-2 border-dashed border-slate-200 rounded-xl p-16 text-center flex flex-col items-center justify-center min-h-[500px] shadow-sm">
                <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6 text-indigo-200">
                  <i className="fas fa-notes-medical text-3xl"></i>
                </div>
                <h3 className="text-slate-800 font-bold text-xl mb-2">Awaiting Image Input</h3>
                <p className="text-slate-400 text-sm max-w-xs leading-relaxed">
                  Please upload a diagnostic ultrasound snapshot to initiate the OGXAI expert analysis pipeline.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay 
                analysis={analysis} 
              />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="bg-slate-900 text-slate-500 py-10 text-center">
        <div className="container mx-auto px-4">
          <div className="flex justify-center gap-8 mb-6 opacity-30">
            <i className="fas fa-user-md text-xl"></i>
            <i className="fas fa-hospital text-xl"></i>
            <i className="fas fa-microscope text-xl"></i>
          </div>
          <p className="text-xs font-bold uppercase tracking-widest mb-2">OGXAI Consultation Analysis System &copy; {new Date().getFullYear()}</p>
          <p className="max-w-2xl mx-auto text-[10px] leading-relaxed opacity-50 px-4">
            A diagnostic assistive platform. Output requires clinical correlation by qualified professionals. For high-volume usage, ensure a <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline hover:text-white">paid project</a> is connected.
          </p>
        </div>
      </footer>
    </div>
  );
};

