import React, { useState } from 'react';
import { analyzeUltrasound } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  const handleImageUpload = (base64: string) => {
    setImage(base64);
    setAnalysis(null);
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (!image) return;

    // Check for API key selection - trigger dialog if not set
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        setStatus({ ...status, progressMessage: 'Connecting to AI pipeline...' });
        await window.aistudio.openSelectKey();
      }
    }

    setStatus({
      isAnalyzing: true,
      progressMessage: 'Initializing OGXAI consultation...',
      error: null,
    });

    try {
      const messages = [
        'Classifying scan modality...',
        'Mapping anatomical landmarks...',
        'Analyzing morphology & biometry...',
        'Finalizing consultation report...',
      ];

      let msgIndex = 0;
      const interval = setInterval(() => {
        if (msgIndex < messages.length) {
          setStatus(prev => ({ ...prev, progressMessage: messages[msgIndex++] }));
        }
      }, 1500);

      const reportMarkdown = await analyzeUltrasound(image.split(',')[1]);

      clearInterval(interval);
      setAnalysis({
        reportMarkdown,
        timestamp: new Date().toLocaleString(),
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      console.error("Clinical Analysis Error:", err);
      let errorMsg = err.message || 'The OGXAI core encountered a processing error.';

      // Parse JSON error if necessary
      try {
        const parsed = JSON.parse(errorMsg);
        if (parsed.error?.message) errorMsg = parsed.error.message;
      } catch (e) {
        // Not JSON, continue with original string
      }

      // Handle Quota/429 errors
      if (errorMsg.includes('429') || errorMsg.includes('quota') || errorMsg.includes('RESOURCE_EXHAUSTED')) {
        errorMsg = "API Quota exceeded. The shared free tier for Gemini 3 Pro is currently at its limit. To continue, you MUST connect a personal API key from a PAID Google Cloud project.";
      }

      // Handle Expired or Invalid Keys specifically
      if (errorMsg.includes('expired') || errorMsg.includes('INVALID_ARGUMENT') || errorMsg.includes('API_KEY_INVALID')) {
        errorMsg = "API Key Expired or Invalid. Even if you added a card, your existing key session may have expired. Please use 'Connect Paid Project' to refresh your project connection.";
      }

      // Handle missing project
      if (errorMsg.includes('Requested entity was not found')) {
        errorMsg = "Invalid Project Configuration. The selected project was not found. Please re-select your project key.";
      }

      setStatus({
        isAnalyzing: false,
        progressMessage: '',
        error: errorMsg,
      });
    }
  };

  const handleKeySelectionAndRetry = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      // Directly retry the analysis after key selection attempt
      startAnalysis();
    }
  };

  const reset = () => {
    setImage(null);
    setAnalysis(null);
    setStatus({ isAnalyzing: false, progressMessage: '', error: null });
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-10 max-w-5xl">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          <div className="lg:col-span-5 space-y-6">
            <section className="bg-white rounded-xl shadow-md border border-slate-200 p-8">
              <h2 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-3">
                <i className="fas fa-file-import text-indigo-600"></i>
                Input Ultrasound Scan
              </h2>
              <ImageUploader 
                onUpload={handleImageUpload} 
                currentImage={image} 
                disabled={status.isAnalyzing}
              />

              {image && !analysis && !status.error && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-8 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white font-bold py-4 px-4 rounded-xl shadow-lg shadow-indigo-100 transition-all flex items-center justify-center gap-3"
                >
                  <i className="fas fa-brain"></i>
                  {status.isAnalyzing ? 'Processing...' : 'Start Clinical Consultation'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={reset}
                  className="w-full mt-6 text-slate-400 hover:text-indigo-600 text-sm font-bold uppercase tracking-widest transition-colors flex items-center justify-center gap-2"
                >
                  <i className="fas fa-redo-alt text-[10px]"></i>
                  New Consultation
                </button>
              )}
            </section>

            <section className="bg-indigo-900 text-indigo-100 rounded-xl p-8 shadow-inner overflow-hidden relative">
              <div className="relative z-10">
                <h3 className="text-xs font-black uppercase tracking-[0.2em] mb-4 opacity-70">Diagnostic Protocol</h3>
                <div className="space-y-4">
                    <div className="flex gap-4 items-start">
                        <div className="w-6 h-6 rounded bg-indigo-700 flex items-center justify-center shrink-0">
                            <i className="fas fa-check text-[10px]"></i>
                        </div>
                        <p className="text-xs leading-relaxed">Morphological analysis using Gemini 3 Pro.</p>
                    </div>
                    <div className="flex gap-4 items-start">
                        <div className="w-6 h-6 rounded bg-indigo-700 flex items-center justify-center shrink-0">
                            <i className="fas fa-check text-[10px]"></i>
                        </div>
                        <p className="text-xs leading-relaxed">Dedicated billing enables high-priority throughput.</p>
                    </div>
                </div>
              </div>
              <div className="absolute -bottom-10 -right-10 opacity-10">
                 <i className="fas fa-stethoscope text-[160px]"></i>
              </div>
            </section>
          </div>

          <div className="lg:col-span-7">
            {status.error && (
              <div className="bg-red-50 border-l-4 border-red-500 text-red-800 p-8 rounded-r-xl mb-6 shadow-sm flex flex-col gap-6 animate-in fade-in slide-in-from-top-2">
                <div className="flex gap-4 items-start">
                  <i className="fas fa-exclamation-triangle mt-1 text-red-500 text-xl"></i>
                  <div>
                      <h4 className="font-bold text-base">Connection Status: System Error</h4>
                      <p className="text-sm opacity-90 mt-2 leading-relaxed font-mono bg-white/40 p-3 rounded border border-red-100">{status.error}</p>
                  </div>
                </div>

                <div className="flex flex-col gap-4">
                    <div className="p-4 bg-white/50 rounded-lg border border-red-100">
                        <p className="text-[11px] font-bold text-red-900 uppercase tracking-wider mb-2">Instructions for Resolved Billing:</p>
                        <p className="text-xs text-red-700 leading-relaxed">
                            Since you have attached a payment card, you must <strong>re-select the project</strong> in the connection dialog to refresh the API key. Ensure you select a project that has the <strong>Paid Tier</strong> enabled.
                        </p>
                    </div>

                    <div className="flex flex-wrap gap-3">
                        <button 
                            onClick={handleKeySelectionAndRetry}
                            className="flex-1 min-w-[200px] bg-indigo-600 text-white font-bold py-3 px-6 rounded-xl hover:bg-indigo-700 transition-all shadow-md flex items-center justify-center gap-2"
                        >
                            <i className="fas fa-sync-alt text-xs"></i>
                            Refresh & Connect Paid Project
                        </button>
                        <a 
                            href="https://ai.google.dev/gemini-api/docs/billing" 
                            target="_blank" 
                            rel="noopener noreferrer"
                            className="flex-1 min-w-[200px] border border-slate-300 text-slate-600 font-bold py-3 px-6 rounded-xl hover:bg-slate-50 transition-all flex items-center justify-center gap-2"
                        >
                            <i className="fas fa-external-link-alt text-xs"></i>
                            Check Billing Status
                        </a>
                    </div>
                </div>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="bg-white border-2 border-dashed border-slate-200 rounded-xl p-16 text-center flex flex-col items-center justify-center min-h-[500px] shadow-sm">
                <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6 text-indigo-200">
                  <i className="fas fa-notes-medical text-3xl"></i>
                </div>
