import { GoogleGenAI, GenerateContentResponse, Content } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "OGXAI", an expert AI Consultant in Obstetrics & Gynecology.
Analyze the attached ultrasound image and generate a concise, focused clinical report.

CORE DIRECTIVES:
1. Adaptive Analysis: Identify the specific view (Fetal Biometry, Gyn/Adnexa, Early Pregnancy) and report ONLY on relevant features.
2. No Fluff: Do not list missing structures irrelevant to the view (e.g., do not mention "no fetal heart" if looking at an ovary).
3. Strict Professionalism: Use standard medical terminology (ISUOG/ACOG style).

OUTPUT STRUCTURE:
**1. Scan Type:** [e.g., Transvaginal Gyn / Fetal Transthalamic View]

**2. Findings:**
* **Anatomy:** [Describe the main structure seen]
* **Morphology/Pathology:** [Describe features]
* **Biometry:** [Extract ONLY relevant on-screen measurements]

**3. Clinical Impression:**
* [One definitive sentence]

---
*Report generated by OGXAI Analysis System*
`;

export async function analyzeUltrasound(image64: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = "Perform initial clinical analysis on this scan for the OGXAI reporting system. Be concise.";

  const imagePart = {
    inlineData: {
      mimeType: 'image/jpeg',
      data: image64,
    },
  };

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: model,
    contents: [{ parts: [imagePart, { text: prompt }] }],
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.1,
      thinkingConfig: { thinkingBudget: 0 }
    },
  });

  if (!response.text) throw new Error("Analysis failed to generate text.");
  return response.text;
}

export async function refineReport(
  image64: string, 
  previousReport: string, 
  refinement: string
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const contents: Content[] = [
    {
      role: 'user',
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: image64 } },
        { text: "Analyze this scan." }
      ]
    },
    {
      role: 'model',
      parts: [{ text: previousReport }]
    },
    {
      role: 'user',
      parts: [{ text: `Clinical update/correction from attending physician: "${refinement}". Please regenerate the full report incorporating this information accurately.` }]
    }
  ];

  const response = await ai.models.generateContent({
    model: model,
    contents: contents,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.1,
      thinkingConfig: { thinkingBudget: 0 }
    },
  });

  if (!response.text) throw new Error("Refinement failed.");
  return response.text;
}

