import React, { useState } from 'react';
import { AnalysisResult } from '../types.ts';

interface Props {
  analysis: AnalysisResult;
  onUpdate?: (comment: string) => void;
  isUpdating?: boolean;
}

const ReportDisplay: React.FC<Props> = ({ analysis, onUpdate, isUpdating }) => {
  const [comment, setComment] = useState('');

  const handleUpdate = () => {
    if (comment.trim() && onUpdate) {
      onUpdate(comment);
      setComment('');
    }
  };

  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return <h4 key={i} className="text-md font-bold text-slate-900 mt-6 mb-2 uppercase tracking-wide border-b border-slate-100 pb-1">{content}</h4>;
      }

      if (line.match(/^\d\.\s/)) {
        return <h3 key={i} className="text-lg font-bold text-indigo-900 mt-8 mb-3 border-l-4 border-indigo-600 pl-3">{line}</h3>;
      }

      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <li key={i} className="ml-4 text-slate-700 leading-relaxed mb-2 list-none">
                    <span className="font-bold text-slate-800">{parts[0]}:</span> {parts.slice(1).join(':')}
                </li>
            );
        }
        return <li key={i} className="ml-4 text-slate-700 leading-relaxed mb-2">{content}</li>;
      }

      if (line.includes('Report generated by OGXAI')) {
        return <p key={i} className="text-[10px] text-indigo-500 italic font-medium mt-10 mb-2 border-t pt-4 text-center">{line.replace(/[\*-]/g, '')}</p>;
      }

      if (line.trim() === '') return <div key={i} className="h-1" />;

      return <p key={i} className="text-slate-700 leading-relaxed mb-1">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col gap-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
