import React, { useState } from 'react';
import { analyzeUltrasound, refineReport } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';

const App: React.FC = () => {
  const [images, setImages] = useState<string[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isRefining, setIsRefining] = useState(false);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  const handleImagesChange = (newImages: string[]) => {
    setImages(newImages);
    setAnalysis(null);
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) await window.aistudio.openSelectKey();
    }

    setStatus({
      isAnalyzing: true,
      progressMessage: 'Connecting to OGXAI Neural Core...',
      error: null,
    });

    try {
      const messages = [
        `Processing ${images.length} scan data points...`,
        'Mapping morphology...',
        'Extracting biometry...',
        'Synthesizing comprehensive findings...',
        'Finalizing consultation report...',
      ];

      let msgIndex = 0;
      const interval = setInterval(() => {
        if (msgIndex < messages.length - 1) {
          msgIndex++;
          setStatus(prev => ({ ...prev, progressMessage: messages[msgIndex] }));
        }
      }, 2000);

      const reportMarkdown = await analyzeUltrasound(images.map(img => img.split(',')[1]));

      clearInterval(interval);
      setAnalysis({
        reportMarkdown,
        timestamp: new Date().toLocaleString(),
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      handleError(err);
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (images.length === 0 || !analysis) return;

    setIsRefining(true);
    try {
      const updatedReport = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment
      );
      setAnalysis({
        ...analysis,
        reportMarkdown: updatedReport,
        timestamp: new Date().toLocaleString() + " (Updated)"
      });
    } catch (err: any) {
      handleError(err);
    } finally {
      setIsRefining(false);
    }
  };

  const handleError = (err: any) => {
    console.error("Clinical Analysis Error:", err);
    let errorMsg = err.message || 'OGXAI encountered a processing error.';

    if (errorMsg.includes('{')) {
      try {
        const parsed = JSON.parse(errorMsg);
        errorMsg = parsed.error?.message || errorMsg;
      } catch(e) {}
    }

    if (errorMsg.includes("Requested entity was not found.") && window.aistudio) {
      window.aistudio.openSelectKey();
    }

    setStatus({
      isAnalyzing: false,
      progressMessage: '',
      error: errorMsg,
    });
  };

  const handleKeySelectionAndRetry = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      startAnalysis();
    }
  };

  const reset = () => {
    setImages([]);
    setAnalysis(null);
    setStatus({ isAnalyzing: false, progressMessage: '', error: null });
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-10 max-w-5xl">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          <div className="lg:col-span-5 space-y-6">
            <section className="bg-white rounded-xl shadow-md border border-slate-200 p-8">
              <h2 className="text-lg font-bold text-slate-800 mb-6 flex items-center justify-between">
                <span className="flex items-center gap-3">
                  <i className="fas fa-file-import text-indigo-600"></i>
                  Ultrasound Scans
                </span>
                {images.length > 0 && (
                  <span className="text-[10px] bg-indigo-100 text-indigo-700 px-2 py-1 rounded-full font-black uppercase tracking-widest">
                    {images.length} Selected
                  </span>
                )}
              </h2>

              <ImageUploader 
                onImagesChange={handleImagesChange} 
                images={images} 
                disabled={status.isAnalyzing || isRefining}
              />

              {images.length > 0 && !analysis && !status.error && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-8 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white font-bold py-4 px-4 rounded-xl shadow-lg shadow-indigo-100 transition-all flex items-center justify-center gap-3"
                >
                  <i className="fas fa-bolt"></i>
                  {status.isAnalyzing ? 'Analyzing...' : 'Generate Comprehensive Report'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={reset}
                  className="w-full mt-6 text-slate-400 hover:text-indigo-600 text-sm font-bold uppercase tracking-widest transition-colors flex items-center justify-center gap-2"
                >
                  <i className="fas fa-redo-alt text-[10px]"></i>
                  Reset Scans
                </button>
              )}
            </section>
          </div>

          <div className="lg:col-span-7">
            {status.error && (
              <div className="bg-red-50 border-l-4 border-red-500 text-red-800 p-8 rounded-r-xl mb-6 shadow-sm flex flex-col gap-6 animate-in fade-in slide-in-from-top-2">
                <div className="flex gap-4 items-start">
                  <i className="fas fa-exclamation-triangle mt-1 text-red-500 text-xl"></i>
                  <div>
                      <h4 className="font-bold text-base">Analysis Error</h4>
                      <p className="text-sm opacity-90 mt-2 leading-relaxed font-mono bg-white/40 p-3 rounded border border-red-100">{status.error}</p>
                  </div>
                </div>
                <div className="flex flex-wrap gap-3">
                    <button onClick={handleKeySelectionAndRetry} className="bg-indigo-600 text-white font-bold py-3 px-6 rounded-xl hover:bg-indigo-700 transition-all shadow-md flex items-center justify-center gap-2">
                        <i className="fas fa-sync-alt text-xs"></i> Update Project Key
                    </button>
                </div>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="bg-white border-2 border-dashed border-slate-200 rounded-xl p-16 text-center flex flex-col items-center justify-center min-h-[500px] shadow-sm">
                <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center mb-6 text-indigo-200">
                  <i className="fas fa-notes-medical text-3xl"></i>
                </div>
                <h3 className="text-slate-800 font-bold text-xl mb-2">Awaiting Input</h3>
                <p className="text-slate-400 text-sm max-w-xs leading-relaxed">
                  Select one or more diagnostic ultrasound snapshots to initiate a combined clinical report.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay 
                analysis={analysis} 
                onUpdate={onUpdateReport}
                isUpdating={isRefining}
              />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="bg-slate-900 text-slate-500 py-10 text-center">
        <div className="container mx-auto px-4 text-xs">
          <p className="font-bold uppercase tracking-widest mb-2 text-slate-400">OGXAI Consultation Analysis System &copy; {new Date().getFullYear()}</p>
          <p className="max-w-2xl mx-auto opacity-50 px-4">
            A diagnostic assistive platform for synthesis of multiple ultrasound scans. Output requires clinical correlation. 
            High-volume usage requires a <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline hover:text-white">paid project key</a>.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useState } from 'react';
import CameraCapture from './CameraCapture.tsx';

interface Props {
  onImagesChange: (images: string[]) => void;
  images: string[];
  disabled: boolean;
}

const ImageUploader: React.FC<Props> = ({ onImagesChange, images, disabled }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const newImagesBase64 = await Promise.all(
      files.map(file => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
      })
    );

    onImagesChange([...images, ...newImagesBase64]);
    // Reset input so the same file can be added again if needed
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const triggerUpload = () => {
    if (!disabled) {
      fileInputRef.current?.click();
    }
  };

  const handleCapture = (base64: string) => {
    onImagesChange([...images, base64]);
    setIsCameraOpen(false);
  };

  const removeImage = (index: number) => {
    if (disabled) return;
    const updated = images.filter((_, i) => i !== index);
    onImagesChange(updated);
  };

  return (
    <div className="space-y-6">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        accept="image/*"
        multiple
        className="hidden"
        disabled={disabled}
      />

      {isCameraOpen && (
        <CameraCapture onCapture={handleCapture} onClose={() => setIsCameraOpen(false)} />
      )}

      <div className="grid grid-cols-2 gap-4">
        <button 
          onClick={triggerUpload}
          disabled={disabled}
          className={`group border-2 border-dashed border-slate-200 rounded-xl p-4 transition-all flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50 hover:border-indigo-300 disabled:opacity-50 disabled:cursor-not-allowed`}
        >
          <div className="w-10 h-10 bg-white rounded-full shadow-sm flex items-center justify-center mb-2 group-hover:scale-110 transition-transform">
            <i className="fas fa-file-upload text-slate-400 group-hover:text-indigo-500"></i>
          </div>
          <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Upload Scans</p>
        </button>

        <button 
          onClick={() => !disabled && setIsCameraOpen(true)}
          disabled={disabled}
          className={`group border-2 border-dashed border-slate-200 rounded-xl p-4 transition-all flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50 hover:border-indigo-300 disabled:opacity-50 disabled:cursor-not-allowed`}
        >
          <div className="w-10 h-10 bg-white rounded-full shadow-sm flex items-center justify-center mb-2 group-hover:scale-110 transition-transform">
            <i className="fas fa-camera text-slate-400 group-hover:text-indigo-500"></i>
          </div>
          <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Live Capture</p>
        </button>
      </div>

      {images.length > 0 && (
        <div className="grid grid-cols-2 gap-3 max-h-[400px] overflow-y-auto p-1 border border-slate-100 rounded-lg">
          {images.map((img, idx) => (
            <div key={idx} className="relative rounded-lg overflow-hidden border border-slate-200 shadow-sm bg-slate-100 aspect-square group">
              <img 
                src={img} 
                alt={`Scan ${idx + 1}`} 
                className="w-full h-full object-cover"
              />
              {!disabled && (
                <button 
                  onClick={() => removeImage(idx)}
                  className="absolute top-1 right-1 bg-red-500 text-white w-6 h-6 rounded-full flex items-center justify-center text-[10px] shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                  title="Remove Image"
                >
                  <i className="fas fa-trash"></i>
                </button>
              )}
