import React, { useState } from 'react';
import { analyzeUltrasound, refineReport } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';

const App: React.FC = () => {
  const [images, setImages] = useState<string[]>([]);
  const [clinicalContext, setClinicalContext] = useState('');
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isRefining, setIsRefining] = useState(false);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  const handleImagesChange = (newImages: string[]) => {
    setImages(newImages);
    if (newImages.length === 0) {
      setAnalysis(null);
    }
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) await window.aistudio.openSelectKey();
    }

    setStatus({
      isAnalyzing: true,
      progressMessage: 'Initializing OGXAI Clinical Engine...',
      error: null,
    });

    try {
      const messages = [
        `Ingesting ${images.length} diagnostic frames...`,
        'Segmenting anatomical regions...',
        'Cross-referencing morphological markers...',
        'Compiling comprehensive findings...',
        'Validating clinical impression...',
      ];

      let msgIndex = 0;
      const interval = setInterval(() => {
        if (msgIndex < messages.length - 1) {
          msgIndex++;
          setStatus(prev => ({ ...prev, progressMessage: messages[msgIndex] }));
        }
      }, 1800);

      const reportMarkdown = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext
      );

      clearInterval(interval);
      setAnalysis({
        reportMarkdown,
        timestamp: new Date().toLocaleString(),
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      handleError(err);
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (images.length === 0 || !analysis) return;

    setIsRefining(true);
    try {
      const updatedReport = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext
      );
      setAnalysis({
        ...analysis,
        reportMarkdown: updatedReport,
        timestamp: new Date().toLocaleString() + " (Updated)"
      });
    } catch (err: any) {
      handleError(err);
    } finally {
      setIsRefining(false);
    }
  };

  const handleError = (err: any) => {
    console.error("Clinical Analysis Error:", err);
    let errorMsg = err.message || 'OGXAI encountered a processing error.';

    if (errorMsg.includes('{')) {
      try {
        const parsed = JSON.parse(errorMsg);
        errorMsg = parsed.error?.message || errorMsg;
      } catch(e) {}
    }

    if (errorMsg.includes("Requested entity was not found.") && window.aistudio) {
      window.aistudio.openSelectKey();
    }

    setStatus({
      isAnalyzing: false,
      progressMessage: '',
      error: errorMsg,
    });
  };

  const handleKeySelectionAndRetry = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      startAnalysis();
    }
  };

  const reset = () => {
    setImages([]);
    setClinicalContext('');
    setAnalysis(null);
    setStatus({ isAnalyzing: false, progressMessage: '', error: null });
  };

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-6xl">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          <div className="lg:col-span-4 space-y-6">
            <section className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2">
                  <i className="fas fa-microscope text-indigo-600"></i>
                  Data Input
                </h2>
                {images.length > 0 && (
                  <button 
                    onClick={() => handleImagesChange([])}
                    className="text-[10px] text-red-500 font-bold uppercase hover:underline"
                  >
                    Clear All
                  </button>
                )}
              </div>

              <div className="space-y-4">
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2 block">
                    Diagnostic Images
                  </label>
                  <ImageUploader 
                    onImagesChange={handleImagesChange} 
                    images={images} 
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>

                <div className="pt-2">
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-2 block">
                    Clinical Indication (Optional)
                  </label>
                  <textarea 
                    value={clinicalContext}
                    onChange={(e) => setClinicalContext(e.target.value)}
                    placeholder="e.g. 28yo, G1P0, Routine 20wk scan, patient reporting decreased movement..."
                    className="w-full bg-slate-50 border border-slate-200 rounded-xl p-3 text-xs focus:ring-2 focus:ring-indigo-500/20 focus:border-indigo-500 outline-none transition-all h-24 resize-none"
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>
              </div>

              {images.length > 0 && !analysis && !status.error && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-6 bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-300 text-white font-bold py-4 rounded-xl shadow-lg shadow-indigo-100 transition-all flex items-center justify-center gap-3 active:scale-95"
                >
                  <i className={`fas ${status.isAnalyzing ? 'fa-spinner fa-spin' : 'fa-wand-magic-sparkles'}`}></i>
                  {status.isAnalyzing ? 'Generating Report...' : 'Analyze All Scans'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={reset}
                  className="w-full mt-6 text-slate-400 hover:text-indigo-600 text-[11px] font-black uppercase tracking-[0.2em] transition-colors flex items-center justify-center gap-2 py-3 border border-dashed border-slate-200 rounded-xl"
                >
                  <i className="fas fa-redo-alt text-[10px]"></i>
                  New Session
                </button>
              )}
            </section>

            <div className="bg-indigo-900 rounded-2xl p-6 text-white overflow-hidden relative group">
              <div className="relative z-10">
                <h4 className="text-xs font-black uppercase tracking-widest mb-1 opacity-60">System Status</h4>
                <p className="text-xl font-bold">OGXAI v2.1 Pro</p>
                <div className="mt-4 flex items-center gap-2">
                  <div className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse"></div>
                  <span className="text-[10px] font-bold uppercase tracking-widest opacity-80 italic">Precision Core Online</span>
                </div>
              </div>
              <i className="fas fa-stethoscope absolute -bottom-4 -right-4 text-7xl opacity-10 group-hover:scale-110 transition-transform duration-700"></i>
            </div>
          </div>

          <div className="lg:col-span-8">
            {status.error && (
              <div className="bg-red-50 border border-red-100 text-red-800 p-8 rounded-2xl mb-6 shadow-sm animate-in fade-in slide-in-from-top-4">
                <div className="flex gap-4 items-start">
                  <div className="bg-red-100 p-3 rounded-full text-red-600">
                    <i className="fas fa-exclamation-triangle text-xl"></i>
                  </div>
                  <div className="flex-grow">
                      <h4 className="font-bold text-lg">System Interruption</h4>
                      <p className="text-sm opacity-80 mt-1 leading-relaxed">{status.error}</p>

                      <div className="mt-6 flex flex-wrap gap-3">
                        <button onClick={handleKeySelectionAndRetry} className="bg-indigo-600 text-white text-xs font-black uppercase tracking-widest py-3 px-6 rounded-lg hover:bg-indigo-700 transition-all shadow-md">
                           Connect Paid Project
                        </button>
                        <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="bg-white border border-slate-200 text-slate-600 text-xs font-black uppercase tracking-widest py-3 px-6 rounded-lg hover:bg-slate-50 transition-all">
                           Billing Docs
                        </a>
                      </div>
                  </div>
                </div>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="bg-white border-2 border-dashed border-slate-200 rounded-2xl p-16 text-center flex flex-col items-center justify-center min-h-[500px] shadow-sm">
                <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-6 text-slate-200 border border-slate-100">
                  <i className="fas fa-notes-medical text-3xl"></i>
                </div>
                <h3 className="text-slate-800 font-bold text-xl mb-2">Ready for Consultation</h3>
                <p className="text-slate-400 text-sm max-w-xs leading-relaxed">
                  Please upload or capture ultrasound diagnostic images to begin the clinical synthesis.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay 
                analysis={analysis} 
                onUpdate={onUpdateReport}
                isUpdating={isRefining}
              />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="bg-slate-900 text-slate-500 py-12 text-center mt-auto border-t border-slate-800">
        <div className="container mx-auto px-4">
          <p className="font-black uppercase tracking-[0.3em] mb-3 text-slate-400 text-[11px]">OGXAI Clinical Analysis Suite</p>
          <p className="max-w-2xl mx-auto opacity-50 px-4 text-[10px] leading-loose">
            PROPRIETARY SYSTEM. FOR USE BY QUALIFIED MEDICAL PROFESSIONALS ONLY. <br/>
            This software assists in clinical review but does not replace the physician's diagnostic judgment.
          </p>
        </div>
      </footer>
    </div>
  );
};

