import { GoogleGenAI, GenerateContentResponse, Content, Part } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "OGXAI", a Senior Consultant in Maternal-Fetal Medicine and Gynecological Imaging.
Your task is to review ultrasound images and generate a single, integrated clinical report.

CORE REPORTING PRINCIPLES:
1. INTEGRATED SYNTHESIS: If multiple scans are provided, cross-reference them. For example, correlate sagittal and axial views of the same organ.
2. CONCISE PROFESSIONALISM: Use standard international terminology (ISUOG, AIUM, ACOG). Avoid unnecessary descriptors.
3. CONTEXT AWARENESS: Use the provided Clinical Indication to focus your findings (e.g., if checking for fibroids, be detailed on myometrial texture).
4. BIOMETRY FOCUS: Prioritize extracting and listing measurements seen on screen.

REPORT FORMAT:
**1. CLINICAL OVERVIEW**
* **Scan Modality:** [Identify if TAS/TVS, Fetal/Gyn]
* **Indication:** [Echo user provided context]

**2. DETAILED FINDINGS**
* **Anatomy survey:** [Describe structure, position, and echo-texture]
* **Morphology & Pathology:** [Note any abnormalities or lack thereof]
* **Biometry:** [Extract all numerical data from annotations]

**3. CLINICAL IMPRESSION**
* [Integrated diagnostic conclusion in 1-2 sentences]

---
*Report generated via OGXAI Consultation Protocol*
`;

export async function analyzeUltrasound(images64: string[], clinicalContext?: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-pro-preview';

  const prompt = `Perform a comprehensive clinical analysis on these ${images64.length} ultrasound scan(s). ${clinicalContext ? `Clinical Context provided by physician: "${clinicalContext}"` : ''} Synthesize all visual evidence into one professional report.`;

  const imageParts: Part[] = images64.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64,
    },
  }));

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: model,
    contents: { parts: [...imageParts, { text: prompt }] },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.1,
    },
  });

  if (!response.text) throw new Error("Analysis failed to generate text.");
  return response.text;
}

export async function refineReport(
  images64: string[], 
  previousReport: string, 
  refinement: string,
  clinicalContext?: string
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-pro-preview';

  const imageParts: Part[] = images64.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64,
    },
  }));

  const contents: Content[] = [
    {
      role: 'user',
      parts: [
        ...imageParts,
        { text: `Analyze these scans. ${clinicalContext ? `Initial Context: ${clinicalContext}` : ''}` }
      ]
    },
    {
      role: 'model',
      parts: [{ text: previousReport }]
    },
    {
      role: 'user',
      parts: [{ text: `Attending Physician Refinement: "${refinement}". Please update the full report reflecting these specific clinical notes.` }]
    }
  ];

  const response = await ai.models.generateContent({
    model: model,
    contents: contents,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.1,
    },
  });

  if (!response.text) throw new Error("Refinement failed.");
  return response.text;
}

import React, { useState } from 'react';
import { AnalysisResult } from '../types.ts';

interface Props {
  analysis: AnalysisResult;
  onUpdate?: (comment: string) => void;
  isUpdating?: boolean;
}

const ReportDisplay: React.FC<Props> = ({ analysis, onUpdate, isUpdating }) => {
  const [comment, setComment] = useState('');

  const suggestions = [
    "Summarize clinical impression",
    "Detail biometry measurements",
    "Identify anatomical landmarks",
    "Make it more concise"
  ];

  const handleUpdate = (customComment?: string) => {
    const finalComment = customComment || comment;
    if (finalComment.trim() && onUpdate) {
      onUpdate(finalComment);
      setComment('');
    }
  };

  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return <h4 key={i} className="text-sm font-black text-slate-900 mt-8 mb-4 uppercase tracking-[0.2em] border-b border-slate-100 pb-2">{content}</h4>;
      }

      if (line.match(/^\d\.\s/)) {
        return <h3 key={i} className="text-xl font-black text-indigo-900 mt-10 mb-4 border-l-4 border-indigo-600 pl-4">{line}</h3>;
      }

      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <li key={i} className="ml-4 text-slate-700 leading-relaxed mb-3 list-none flex gap-2">
                    <span className="font-bold text-slate-900 min-w-[120px]">{parts[0]}:</span> 
                    <span className="flex-grow">{parts.slice(1).join(':')}</span>
                </li>
            );
        }
        return <li key={i} className="ml-4 text-slate-700 leading-relaxed mb-3 list-none flex gap-2"><i className="fas fa-circle text-[4px] mt-2.5 text-indigo-400"></i>{content}</li>;
      }

      if (line.includes('Report generated via OGXAI')) {
        return (
          <div key={i} className="mt-16 border-t-2 border-double border-slate-100 pt-8 flex justify-between items-end grayscale opacity-50">
            <div>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Electronic Signature</p>
              <div className="font-serif italic text-lg text-slate-800">OGXAI Clinical Core</div>
            </div>
            <p className="text-[9px] text-indigo-500 font-bold uppercase tracking-tighter">{line.replace(/[\*-]/g, '')}</p>
          </div>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-2" />;

      return <p key={i} className="text-slate-700 leading-relaxed mb-2 text-sm">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col gap-6 animate-in fade-in slide-in-from-bottom-8 duration-700">
      <div className="bg-white rounded-2xl shadow-xl border border-slate-200 overflow-hidden ring-1 ring-slate-200">
        <div className="bg-slate-900 px-8 py-5 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center">
               <i className="fas fa-file-contract text-white text-xs"></i>
            </div>
            <h2 className="text-white font-black tracking-[0.2em] uppercase text-[11px]">Integrated Consultation Report</h2>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={() => window.print()} 
              className="text-slate-400 hover:text-white transition-all bg-white/5 hover:bg-white/10 p-2.5 rounded-lg border border-white/5"
            >
              <i className="fas fa-print"></i>
            </button>
            <button 
              onClick={() => { navigator.clipboard.writeText(analysis.reportMarkdown); alert('Report data copied to clipboard.'); }} 
              className="text-slate-400 hover:text-white transition-all bg-white/5 hover:bg-white/10 p-2.5 rounded-lg border border-white/5"
            >
              <i className="fas fa-copy"></i>
            </button>
          </div>
        </div>

        <div className="p-12 font-serif bg-white relative">
          {isUpdating && (
            <div className="absolute inset-0 bg-white/80 backdrop-blur-[4px] z-20 flex items-center justify-center transition-all">
              <div className="flex flex-col items-center gap-6">
                <div className="relative">
                  <div className="w-16 h-16 border-4 border-indigo-100 border-t-indigo-600 rounded-full animate-spin"></div>
                  <i className="fas fa-magic absolute inset-0 flex items-center justify-center text-indigo-600 text-lg"></i>
                </div>
                <p className="text-[11px] font-black text-indigo-900 uppercase tracking-[0.3em] animate-pulse">Recalibrating findings...</p>
              </div>
            </div>
          )}

          <div className="flex justify-between items-start border-b-4 border-slate-900 pb-8 mb-10">
            <div>
              <div className="text-4xl font-black text-slate-900 tracking-tighter leading-none">OGX<span className="text-indigo-600">AI</span></div>
              <div className="text-[11px] text-indigo-600 font-black uppercase tracking-[0.2em] mt-3 bg-indigo-50 px-3 py-1 rounded inline-block">Diagnostic Intelligence Suite</div>
            </div>
            <div className="text-right">
              <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Accession No.</div>
              <div className="text-lg font-black text-slate-800 tabular-nums">#{Math.random().toString(36).substr(2, 8).toUpperCase()}</div>
              <div className="text-[10px] font-black text-slate-400 uppercase mt-4 tracking-widest mb-1">Verified on</div>
              <div className="text-sm font-bold text-slate-800">{analysis.timestamp}</div>
            </div>
          </div>

          <div className="report-content max-w-none selection:bg-indigo-100">
            {formatMarkdown(analysis.reportMarkdown)}
          </div>
        </div>
      </div>

      <div className="bg-white border border-slate-200 rounded-2xl p-8 shadow-sm">
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-xs font-black text-slate-800 uppercase tracking-[0.2em] flex items-center gap-3">
            <i className="fas fa-pen-nib text-indigo-600"></i>
            Clinical Refinement
          </h3>
          <div className="flex gap-2">
            {suggestions.map((s, idx) => (
              <button 
                key={idx}
                onClick={() => handleUpdate(s)}
                className="text-[9px] font-bold text-slate-500 bg-slate-100 hover:bg-indigo-100 hover:text-indigo-700 px-3 py-1.5 rounded-full transition-all border border-slate-200"
              >
                {s}
              </button>
            ))}
          </div>
        </div>
        <div className="flex gap-4">
          <textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            placeholder="Instruct the AI to adjust specific details or add context (e.g., 'Correct left ovary volume to 12cc', 'Summarize the impression for the patient')..."
            className="flex-grow bg-slate-50 border border-slate-200 rounded-xl p-4 text-sm focus:outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none h-24"
            disabled={isUpdating}
          />
          <button
            onClick={() => handleUpdate()}
            disabled={isUpdating || !comment.trim()}
            className="bg-indigo-600 hover:bg-indigo-700 disabled:bg-indigo-200 text-white font-bold px-8 rounded-xl transition-all flex flex-col items-center justify-center gap-2 group h-24 min-w-[140px] shadow-lg shadow-indigo-100 active:scale-95"
          >
            <i className="fas fa-sync-alt text-lg group-hover:rotate-180 transition-transform duration-500"></i>
            <span className="text-[10px] uppercase tracking-widest font-black">Refine</span>
          </button>
        </div>
      </div>
    </div>
  );
};

