import React, { useState } from 'react';
import { AnalysisResult } from '../types.ts';

interface Props {
  analysis: AnalysisResult;
  onUpdate?: (comment: string) => void;
  isUpdating?: boolean;
}

const ReportDisplay: React.FC<Props> = ({ analysis, onUpdate, isUpdating }) => {
  const [comment, setComment] = useState('');

  const suggestions = [
    "Refine Clinical Impression",
    "Expand Biometry",
    "Identify Landmarks",
    "Concise Summary"
  ];

  const handleUpdate = (customComment?: string) => {
    const finalComment = customComment || comment;
    if (finalComment.trim() && onUpdate) {
      onUpdate(finalComment);
      setComment('');
    }
  };

  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return <h4 key={i} className="text-[11px] font-black text-[#002B5B] mt-10 mb-5 uppercase tracking-[0.3em] border-b border-slate-50 pb-3">{content}</h4>;
      }

      if (line.match(/^\d\.\s/)) {
        return <h3 key={i} className="text-lg font-black text-[#002B5B] mt-12 mb-6 tracking-tight border-l-2 border-[#D4AF37] pl-5">{line}</h3>;
      }

      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <div key={i} className="flex gap-4 py-2 border-b border-slate-50 last:border-0">
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest min-w-[140px] pt-1">{parts[0]}</span> 
                    <span className="text-sm text-slate-800 leading-relaxed font-medium">{parts.slice(1).join(':')}</span>
                </div>
            );
        }
        return <p key={i} className="text-sm text-slate-800 leading-relaxed py-2 flex gap-3 items-start"><span className="w-1.5 h-1.5 rounded-full bg-[#D4AF37] mt-2 flex-shrink-0"></span>{content}</p>;
      }

      if (line.includes('Report generated via OGXAI')) {
        return (
          <div key={i} className="mt-20 border-t border-slate-100 pt-10 flex justify-between items-center opacity-40">
            <div>
              <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.4em] mb-2">Electronic Validation</p>
              <div className="font-black text-[#002B5B] text-sm uppercase tracking-widest">OGXAI REPORTING CORE</div>
            </div>
            <div className="h-10 w-px bg-slate-200"></div>
            <p className="text-[9px] text-[#D4AF37] font-black uppercase tracking-widest">System Authenticated</p>
          </div>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-4" />;

      return <p key={i} className="text-sm text-slate-700 leading-relaxed mb-4 font-medium">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col gap-10 animate-in fade-in slide-in-from-bottom-12 duration-1000">
      <div className="bg-white shadow-[0_30px_60px_-15px_rgba(0,0,0,0.08)] border border-slate-50 overflow-hidden">
        <div className="bg-[#002B5B] px-10 py-6 flex justify-between items-center">
          <div className="flex items-center gap-5">
            <div className="w-6 h-6 border-2 border-[#D4AF37] flex items-center justify-center">
               <div className="w-2 h-2 bg-[#D4AF37]"></div>
            </div>
            <h2 className="text-white font-black tracking-[0.4em] uppercase text-[10px]">Ultrasound Reporting System</h2>
          </div>
          <div className="flex gap-4">
            <button 
              onClick={() => window.print()} 
              className="text-slate-400 hover:text-[#D4AF37] transition-all"
            >
              <i className="fas fa-print text-sm"></i>
            </button>
            <button 
              onClick={() => { navigator.clipboard.writeText(analysis.reportMarkdown); }} 
              className="text-slate-400 hover:text-[#D4AF37] transition-all"
            >
              <i className="fas fa-link text-sm"></i>
            </button>
          </div>
        </div>

        <div className="p-16 relative">
          {isUpdating && (
            <div className="absolute inset-0 bg-white/90 backdrop-blur-[2px] z-20 flex items-center justify-center transition-all">
              <div className="flex flex-col items-center gap-6">
                <div className="w-12 h-12 border-2 border-slate-100 border-t-[#D4AF37] rounded-full animate-spin"></div>
                <p className="text-[10px] font-black text-[#002B5B] uppercase tracking-[0.5em] animate-pulse">Revising Case Details</p>
              </div>
            </div>
          )}

          <div className="flex justify-between items-start border-b-2 border-[#002B5B] pb-12 mb-12">
            <div>
              <div className="text-4xl font-black text-[#002B5B] tracking-tight">OGXAI</div>
              <div className="text-[10px] text-[#D4AF37] font-black uppercase tracking-[0.4em] mt-3">Clinical Data System</div>
            </div>
            <div className="text-right">
              <div className="text-[9px] font-black text-slate-300 uppercase tracking-widest mb-1">Dossier ID</div>
              <div className="text-sm font-black text-[#002B5B] tabular-nums">{Math.random().toString(36).substr(2, 6).toUpperCase()}</div>
              <div className="text-[9px] font-black text-slate-300 uppercase mt-5 tracking-widest mb-1">Generated</div>
              <div className="text-[11px] font-bold text-[#002B5B]">{analysis.timestamp}</div>
            </div>
          </div>

          <div className="report-content max-w-none">
            {formatMarkdown(analysis.reportMarkdown)}
          </div>
        </div>
      </div>

      <div className="bg-white border border-slate-100 p-10 shadow-sm">
        <div className="flex items-center justify-between mb-8">
          <h3 className="text-[10px] font-black text-[#002B5B] uppercase tracking-[0.3em] flex items-center gap-4">
            <i className="fas fa-edit text-[#D4AF37]"></i>
            Report Revision
          </h3>
          <div className="flex gap-2">
            {suggestions.map((s, idx) => (
              <button 
                key={idx}
                onClick={() => handleUpdate(s)}
                className="text-[9px] font-bold text-slate-400 bg-slate-50 hover:bg-white hover:text-[#D4AF37] hover:border-[#D4AF37] px-4 py-2 rounded border border-slate-100 transition-all"
              >
                {s}
              </button>
            ))}
          </div>
        </div>
        <div className="flex gap-6">
          <textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            placeholder="Provide specific directives for report refinement..."
            className="flex-grow bg-slate-50 border border-slate-100 rounded p-5 text-sm focus:outline-none focus:border-[#D4AF37] transition-all resize-none h-24 font-medium"
            disabled={isUpdating}
          />
          <button
            onClick={() => handleUpdate()}
            disabled={isUpdating || !comment.trim()}
            className="bg-[#002B5B] hover:bg-slate-800 disabled:opacity-30 text-white font-black px-10 rounded transition-all flex flex-col items-center justify-center gap-3 h-24 min-w-[160px] shadow-lg shadow-slate-100"
          >
            <i className="fas fa-arrows-rotate text-sm"></i>
            <span className="text-[9px] uppercase tracking-widest">Update</span>
          </button>
        </div>
      </div>
    </div>
  );
};

