import React, { useState } from 'react';
import { analyzeUltrasound, refineReport } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';

const App: React.FC = () => {
  const [images, setImages] = useState<string[]>([]);
  const [clinicalContext, setClinicalContext] = useState('');
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isRefining, setIsRefining] = useState(false);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  const handleImagesChange = (newImages: string[]) => {
    setImages(newImages);
    if (newImages.length === 0) {
      setAnalysis(null);
    }
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) await window.aistudio.openSelectKey();
    }

    setStatus({
      isAnalyzing: true,
      progressMessage: 'Initializing OGXAI Diagnostic Engine...',
      error: null,
    });

    try {
      const messages = [
        'Ingesting clinical frames...',
        'Synthesizing morphological data...',
        'Cross-referencing anatomical markers...',
        'Finalizing reporting dossier...',
      ];

      let msgIndex = 0;
      const interval = setInterval(() => {
        if (msgIndex < messages.length - 1) {
          msgIndex++;
          setStatus(prev => ({ ...prev, progressMessage: messages[msgIndex] }));
        }
      }, 1500);

      const reportMarkdown = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext
      );

      clearInterval(interval);
      setAnalysis({
        reportMarkdown,
        timestamp: new Date().toLocaleString(),
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      handleError(err);
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (images.length === 0 || !analysis) return;

    setIsRefining(true);
    try {
      const updatedReport = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext
      );
      setAnalysis({
        ...analysis,
        reportMarkdown: updatedReport,
        timestamp: new Date().toLocaleString() + " (Revision)"
      });
    } catch (err: any) {
      handleError(err);
    } finally {
      setIsRefining(false);
    }
  };

  const handleError = (err: any) => {
    let errorMsg = err.message || 'The system encountered an operational error.';
    if (errorMsg.includes('{')) {
      try {
        const parsed = JSON.parse(errorMsg);
        errorMsg = parsed.error?.message || errorMsg;
      } catch(e) {}
    }

    if (errorMsg.includes("Requested entity was not found.") && window.aistudio) {
      window.aistudio.openSelectKey();
    }

    setStatus({ isAnalyzing: false, progressMessage: '', error: errorMsg });
  };

  const reset = () => {
    setImages([]);
    setClinicalContext('');
    setAnalysis(null);
    setStatus({ isAnalyzing: false, progressMessage: '', error: null });
  };

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Header />

      <main className="flex-grow container mx-auto px-8 py-16 max-w-7xl">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">

          <div className="lg:col-span-4">
            <section className="bg-white border-t-4 border-[#D4AF37] p-10 shadow-[0_20px_60px_rgba(0,0,0,0.04)] sticky top-32">
              <h2 className="text-sm font-black text-[#002B5B] uppercase tracking-[0.4em] mb-12 border-b border-slate-100 pb-6">
                Clinical Directives
              </h2>

              <div className="space-y-10">
                <div>
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 block">
                    Imaging Data
                  </label>
                  <ImageUploader 
                    onImagesChange={handleImagesChange} 
                    images={images} 
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>

                <div className="pt-2">
                  <label className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4 block">
                    Clinical Context
                  </label>
                  <textarea 
                    value={clinicalContext}
                    onChange={(e) => setClinicalContext(e.target.value)}
                    placeholder="Enter patient history, GA, or specific indications..."
                    className="w-full bg-slate-50 border-2 border-slate-100 rounded p-5 text-sm font-medium focus:bg-white focus:border-[#D4AF37] outline-none transition-all h-36 resize-none"
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>
              </div>

              {images.length > 0 && !analysis && !status.error && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-12 bg-[#002B5B] hover:bg-[#003c7e] disabled:opacity-50 text-white text-xs font-black uppercase tracking-[0.3em] py-6 rounded shadow-2xl shadow-[#002B5B]/20 transition-all flex items-center justify-center gap-4"
                >
                  <i className={`fas ${status.isAnalyzing ? 'fa-spinner fa-spin' : 'fa-file-medical'}`}></i>
                  {status.isAnalyzing ? 'Synthesizing...' : 'Run Diagnostics'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={reset}
                  className="w-full mt-10 text-slate-400 hover:text-[#002B5B] text-[11px] font-black uppercase tracking-[0.3em] transition-colors flex items-center justify-center gap-3 py-5 border-2 border-slate-50 rounded"
                >
                  <i className="fas fa-plus"></i>
                  Initialize New Case
                </button>
              )}
