          </div>

          <div className="lg:col-span-8">
            {status.error && (
              <div className="border-l-4 border-red-500 bg-red-50 p-12 rounded shadow-sm">
                <div className="flex gap-8 items-start">
                  <div className="text-red-500 pt-1">
