  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return <h4 key={i} className="text-[13px] font-black text-[#002B5B] mt-16 mb-6 uppercase tracking-[0.4em] border-b-2 border-slate-50 pb-4">{content}</h4>;
