        return <h3 key={i} className="text-2xl font-black text-[#002B5B] mt-20 mb-10 tracking-tighter border-l-4 border-[#D4AF37] pl-8">{line}</h3>;
      }

      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <div key={i} className="flex gap-6 py-4 border-b border-slate-50 last:border-0">
                    <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.2em] min-w-[180px] pt-1.5">{parts[0]}</span> 
