        <div className="bg-[#002B5B] px-12 py-8 flex justify-between items-center">
          <div className="flex items-center gap-6">
            <div className="w-8 h-8 border-2 border-[#D4AF37] flex items-center justify-center">
               <div className="w-3 h-3 bg-[#D4AF37]"></div>
            </div>
            <h2 className="text-white font-black tracking-[0.5em] uppercase text-xs">Official Clinical Report</h2>
          </div>
          <div className="flex gap-6">
            <button 
              onClick={() => window.print()} 
