  const handleUpdate = (customComment?: string) => {
    const finalComment = customComment || comment;
    if (finalComment.trim() && onUpdate) {
      onUpdate(finalComment);
      setComment('');
    }
  };

  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Headers
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return <h4 key={i} className="text-[15px] font-extrabold text-[#002B5B] mt-20 mb-8 uppercase tracking-[0.5em] border-b border-slate-100 pb-5">{content}</h4>;
      }

      // Numbered List Items
      if (line.match(/^\d\.\s/)) {
        return <h3 key={i} className="text-3xl font-extrabold text-[#002B5B] mt-24 mb-12 tracking-tight border-l-[6px] border-[#D4AF37] pl-10">{line}</h3>;
      }

      // Bullet points with Bold Key/Value
      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <div key={i} className="flex gap-10 py-6 border-b border-slate-50 last:border-0">
                    <span className="text-xs font-bold text-slate-400 uppercase tracking-[0.25em] min-w-[220px] pt-1">{parts[0]}</span> 
                    <span className="text-lg text-slate-800 leading-relaxed font-medium">{parts.slice(1).join(':')}</span>
                </div>
            );
        }
        return <p key={i} className="text-lg text-slate-800 leading-relaxed py-4 flex gap-6 items-start"><span className="w-2.5 h-2.5 rounded-full bg-[#D4AF37] mt-3 flex-shrink-0"></span>{content}</p>;
      }

      // Footer phrase
      if (line.includes('Report generated via OGXAI')) {
        return (
          <div key={i} className="mt-32 border-t-2 border-[#002B5B] pt-16 flex justify-between items-start opacity-60">
            <div>
              <p className="text-[11px] font-bold text-slate-400 uppercase tracking-[0.4em] mb-4">Digital Validation Signature</p>
              <div className="font-extrabold text-[#002B5B] text-xl uppercase tracking-[0.1em]">OGXAI CERTIFIED PROTOCOL</div>
            </div>
            <div className="text-right">
              <p className="text-[11px] text-[#D4AF37] font-bold uppercase tracking-[0.3em]">System Authentication Active</p>
              <p className="text-[10px] text-slate-300 mt-2">Dossier Code: {Math.random().toString(36).substr(2, 9).toUpperCase()}</p>
            </div>
          </div>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-8" />;

      return <p key={i} className="text-lg text-slate-700 leading-relaxed mb-8 font-medium">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col gap-16 animate-in fade-in slide-in-from-bottom-20 duration-1000">
      <div className="bg-white shadow-[0_50px_120px_-30px_rgba(0,0,0,0.12)] border border-slate-50 overflow-hidden">
        <div className="bg-[#002B5B] px-16 py-10 flex justify-between items-center">
          <div className="flex items-center gap-8">
            <div className="w-10 h-10 border-[3px] border-[#D4AF37] flex items-center justify-center">
               <div className="w-4 h-4 bg-[#D4AF37]"></div>
            </div>
            <h2 className="text-white font-bold tracking-[0.6em] uppercase text-sm">Clinical Imaging Dossier</h2>
          </div>
          <div className="flex gap-8">
            <button 
              onClick={() => window.print()} 
              className="text-slate-400 hover:text-white transition-all p-3"
            >
              <i className="fas fa-print text-xl"></i>
            </button>
            <button 
              onClick={() => { navigator.clipboard.writeText(analysis.reportMarkdown); }} 
              className="text-slate-400 hover:text-white transition-all p-3"
            >
              <i className="fas fa-file-export text-xl"></i>
            </button>
          </div>
        </div>

        <div className="p-24 relative">
          {isUpdating && (
            <div className="absolute inset-0 bg-white/95 backdrop-blur-[6px] z-20 flex items-center justify-center transition-all">
              <div className="flex flex-col items-center gap-10">
                <div className="w-20 h-20 border-[6px] border-slate-50 border-t-[#D4AF37] rounded-full animate-spin"></div>
                <p className="text-sm font-bold text-[#002B5B] uppercase tracking-[0.7em] animate-pulse">Updating Clinical Evidence</p>
              </div>
            </div>
          )}

          <div className="flex justify-between items-end border-b-[8px] border-[#002B5B] pb-20 mb-20">
            <div>
              <div className="text-8xl font-black text-[#002B5B] tracking-[-0.05em] leading-none">OGXAI</div>
              <div className="text-sm text-[#D4AF37] font-bold uppercase tracking-[0.6em] mt-8">Clinical Reporting Protocol</div>
            </div>
            <div className="text-right">
              <div className="text-xs font-bold text-slate-300 uppercase tracking-[0.4em] mb-3">Report Token</div>
              <div className="text-2xl font-black text-[#002B5B] tracking-widest tabular-nums">{Math.random().toString(36).substr(2, 6).toUpperCase()}</div>
              <div className="text-xs font-bold text-slate-300 uppercase mt-10 tracking-[0.4em] mb-3">Validated On</div>
              <div className="text-sm font-bold text-[#002B5B] uppercase tracking-widest">{analysis.timestamp}</div>
            </div>
          </div>

          <div className="report-content max-w-none">
            {formatMarkdown(analysis.reportMarkdown)}
          </div>
        </div>
      </div>

      <div className="bg-white border-[3px] border-slate-50 p-16 shadow-lg shadow-slate-100/50">
        <div className="flex items-center justify-between mb-12">
          <h3 className="text-sm font-bold text-[#002B5B] uppercase tracking-[0.5em] flex items-center gap-6">
            <i className="fas fa-pen-nib text-[#D4AF37] text-xl"></i>
            Refine Analysis
          </h3>
          <div className="flex gap-4">
            {suggestions.map((s, idx) => (
              <button 
                key={idx}
                onClick={() => handleUpdate(s)}
                className="text-[11px] font-bold text-slate-400 bg-slate-50 hover:bg-white hover:text-[#D4AF37] hover:border-[#D4AF37] px-6 py-4 rounded-sm border-2 border-transparent transition-all"
              >
                {s}
              </button>
            ))}
          </div>
        </div>
        <div className="flex gap-10">
          <textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
