import React, { useState } from 'react';
import { analyzeUltrasound, refineReport } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';

const App: React.FC = () => {
  const [images, setImages] = useState<string[]>([]);
  const [clinicalContext, setClinicalContext] = useState('');
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isRefining, setIsRefining] = useState(false);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  const handleImagesChange = (newImages: string[]) => {
    setImages(newImages);
    if (newImages.length === 0) {
      setAnalysis(null);
    }
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) await window.aistudio.openSelectKey();
    }

    setStatus({
      isAnalyzing: true,
      progressMessage: 'Initializing OGXAI Diagnostic Engine...',
      error: null,
    });

    try {
      const messages = [
        'Ingesting clinical frames...',
        'Synthesizing morphological data...',
        'Cross-referencing anatomical markers...',
        'Finalizing reporting dossier...',
      ];

      let msgIndex = 0;
      const interval = setInterval(() => {
        if (msgIndex < messages.length - 1) {
          msgIndex++;
          setStatus(prev => ({ ...prev, progressMessage: messages[msgIndex] }));
        }
      }, 1500);

      const reportMarkdown = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext
      );

      clearInterval(interval);
      setAnalysis({
        reportMarkdown,
        timestamp: new Date().toLocaleString(),
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      handleError(err);
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (images.length === 0 || !analysis) return;

    setIsRefining(true);
    try {
      const updatedReport = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext
      );
      setAnalysis({
        ...analysis,
        reportMarkdown: updatedReport,
        timestamp: new Date().toLocaleString() + " (Revision)"
      });
    } catch (err: any) {
      handleError(err);
    } finally {
      setIsRefining(false);
    }
  };

  const handleError = (err: any) => {
    let errorMsg = err.message || 'The system encountered an operational error.';
    if (errorMsg.includes('{')) {
      try {
        const parsed = JSON.parse(errorMsg);
        errorMsg = parsed.error?.message || errorMsg;
      } catch(e) {}
    }

    if (errorMsg.includes("Requested entity was not found.") && window.aistudio) {
      window.aistudio.openSelectKey();
    }

    setStatus({ isAnalyzing: false, progressMessage: '', error: errorMsg });
  };

  const reset = () => {
    setImages([]);
    setClinicalContext('');
    setAnalysis(null);
    setStatus({ isAnalyzing: false, progressMessage: '', error: null });
  };

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Header />

      <main className="flex-grow container mx-auto px-10 py-20 max-w-[1400px]">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-20">

          <div className="lg:col-span-4">
            <section className="bg-white border-t-8 border-[#D4AF37] p-12 shadow-[0_30px_90px_rgba(0,0,0,0.03)] sticky top-48">
              <h2 className="text-base font-bold text-[#002B5B] uppercase tracking-[0.5em] mb-16 border-b border-slate-50 pb-8">
                Clinical Parameters
              </h2>

              <div className="space-y-16">
                <div>
                  <label className="text-[11px] font-bold text-slate-400 uppercase tracking-[0.4em] mb-6 block">
                    Imaging Assets
                  </label>
                  <ImageUploader 
                    onImagesChange={handleImagesChange} 
                    images={images} 
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>

                <div className="pt-4">
                  <label className="text-[11px] font-bold text-slate-400 uppercase tracking-[0.4em] mb-6 block">
                    Case Context
                  </label>
                  <textarea 
                    value={clinicalContext}
                    onChange={(e) => setClinicalContext(e.target.value)}
                    placeholder="Patient GA, maternal age, or specific clinical query..."
                    className="w-full bg-slate-50 border-2 border-slate-50 rounded-sm p-6 text-base font-medium focus:bg-white focus:border-[#D4AF37] outline-none transition-all h-48 resize-none shadow-inner"
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>
              </div>

              {images.length > 0 && !analysis && !status.error && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-20 bg-[#002B5B] hover:bg-[#003c7e] disabled:opacity-50 text-white text-xs font-bold uppercase tracking-[0.5em] py-8 rounded-sm shadow-2xl shadow-[#002B5B]/30 transition-all flex items-center justify-center gap-6"
                >
                  <i className={`fas ${status.isAnalyzing ? 'fa-spinner fa-spin' : 'fa-wave-square'}`}></i>
                  {status.isAnalyzing ? 'Analyzing...' : 'Run Diagnostics'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={reset}
                  className="w-full mt-12 text-slate-400 hover:text-[#002B5B] text-xs font-bold uppercase tracking-[0.4em] transition-all flex items-center justify-center gap-4 py-6 border-2 border-slate-50 rounded-sm"
                >
                  <i className="fas fa-plus"></i>
                  New Session
                </button>
              )}
            </section>
          </div>

          <div className="lg:col-span-8">
            {status.error && (
              <div className="border-l-[10px] border-red-500 bg-red-50/50 p-16 rounded-sm shadow-sm">
                <div className="flex gap-12 items-start">
                  <div className="text-red-500 pt-2">
                    <i className="fas fa-exclamation-circle text-4xl"></i>
                  </div>
                  <div className="flex-grow">
                      <h4 className="font-bold text-[#002B5B] uppercase text-sm tracking-[0.6em] mb-6">Process Interruption</h4>
                      <p className="text-xl text-slate-600 leading-relaxed font-medium">{status.error}</p>

                      <div className="mt-12">
                        <button onClick={startAnalysis} className="bg-[#002B5B] text-white text-xs font-bold uppercase tracking-[0.5em] py-5 px-12 rounded-sm hover:bg-slate-800 transition-all">
                           Restart Session
                        </button>
                      </div>
                  </div>
                </div>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="bg-slate-50/30 border-2 border-dashed border-slate-100 rounded-sm p-32 text-center flex flex-col items-center justify-center min-h-[800px]">
                <div className="w-32 h-32 border-[3px] border-slate-100 rounded-full flex items-center justify-center mb-12 text-slate-200">
                  <i className="fas fa-file-alt text-5xl"></i>
                </div>
                <h3 className="text-[#002B5B] font-bold text-lg uppercase tracking-[0.6em] mb-8">Ready for Intake</h3>
                <p className="text-slate-400 text-xs max-w-md leading-loose font-bold uppercase tracking-[0.4em] opacity-40">
                  Import clinical scan data and case context to initiate the automated reporting suite.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay 
                analysis={analysis} 
                onUpdate={onUpdateReport}
                isUpdating={isRefining}
              />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="bg-white py-32 text-center border-t border-slate-50">
        <div className="container mx-auto px-10">
          <p className="font-bold uppercase tracking-[1em] mb-10 text-[#002B5B] text-xs">OGXAI CLINICAL SYSTEMS</p>
          <div className="w-20 h-1.5 bg-[#D4AF37] mx-auto mb-12"></div>
          <p className="max-w-4xl mx-auto opacity-30 text-[11px] leading-loose uppercase tracking-[0.4em] font-bold text-slate-500 px-16">
            Confidential medical reporting output. Professional diagnostic verification is strictly required. This automated system supports but does not replace expert clinical assessment.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio?: AIStudio;
  }
}

const Header: React.FC = () => {
  const [isConnected, setIsConnected] = useState(false);

  useEffect(() => {
    const checkConnection = async () => {
      if (window.aistudio) {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsConnected(hasKey);
      }
    };
    checkConnection();
    window.addEventListener('focus', checkConnection);
    return () => window.removeEventListener('focus', checkConnection);
  }, []);

  const handleKeySetup = async () => {
    try {
      if (window.aistudio) {
        await window.aistudio.openSelectKey();
        setIsConnected(true);
      }
    } catch (err) {
      console.error("Failed to open key selection:", err);
    }
  };

  return (
    <header className="bg-white sticky top-0 z-50 py-12 border-b border-slate-50">
      <div className="container mx-auto px-10 max-w-[1400px] flex items-end justify-between">
        <div className="flex flex-col">
          <h1 className="text-7xl font-extrabold text-[#000000] tracking-[-0.05em] leading-none mb-3">OGXAI</h1>
          <p className="text-[13px] text-[#D4AF37] uppercase font-bold tracking-[0.5em] opacity-80">Ultrasound Reporting System</p>
        </div>

        <nav className="flex items-center gap-12 pb-2">
          <div className="hidden md:flex flex-col items-end gap-1">
            <div className="flex items-center gap-3 text-[11px] font-bold text-slate-400 uppercase tracking-widest">
              <span className={`w-2 h-2 rounded-full ${isConnected ? 'bg-[#D4AF37] shadow-[0_0_12px_#D4AF37]' : 'bg-slate-200'}`}></span>
              {isConnected ? 'Terminal Encrypted' : 'Security Clearance Required'}
            </div>
          </div>
          <button 
            onClick={handleKeySetup}
            className={`text-xs font-bold uppercase tracking-[0.2em] px-10 py-5 rounded-sm transition-all border-2 ${
              isConnected 
                ? 'border-emerald-500 text-emerald-600 bg-emerald-50/30' 
                : 'border-[#D4AF37] text-[#D4AF37] hover:bg-[#D4AF37] hover:text-white shadow-xl shadow-[#D4AF37]/10'
            }`}
          >
            {isConnected ? 'Verified' : 'Initialize Terminal'}
          </button>
        </nav>
      </div>
    </header>
  );
};

