  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Headers
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return <h4 key={i} className="text-[15px] font-extrabold text-[#000000] mt-20 mb-8 uppercase tracking-[0.5em] border-b border-slate-100 pb-5">{content}</h4>;
      }

      // Numbered List Items
      if (line.match(/^\d\.\s/)) {
        return <h3 key={i} className="text-3xl font-extrabold text-[#000000] mt-24 mb-12 tracking-tight border-l-[6px] border-[#D4AF37] pl-10">{line}</h3>;
      }

      // Bullet points with Bold Key/Value
      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <div key={i} className="flex gap-10 py-6 border-b border-slate-50 last:border-0">
                    <span className="text-xs font-bold text-slate-400 uppercase tracking-[0.25em] min-w-[220px] pt-1">{parts[0]}</span> 
