      <div className="bg-white shadow-[0_50px_120px_-30px_rgba(0,0,0,0.12)] border border-slate-50 overflow-hidden">
        <div className="bg-[#000000] px-16 py-10 flex justify-between items-center">
          <div className="flex items-center gap-8">
