import { GoogleGenAI, GenerateContentResponse, Content, Part } from "@google/genai";

const SYSTEM_INSTRUCTION = `
You are "OGXAI", a Senior Consultant in Maternal-Fetal Medicine and Gynecological Imaging.
Your task is to review ultrasound images and generate a single, integrated clinical report.

CORE REPORTING PRINCIPLES:
1. INTEGRATED SYNTHESIS: Correlate findings across all uploaded frames.
2. CONCISE PROFESSIONALISM: Use standard international terminology (ISUOG, AIUM, ACOG).
3. CONTEXT AWARENESS: Prioritize findings based on the provided Clinical Indication.
4. BIOMETRY FOCUS: Extract and list all measurements seen on screen.

REPORT FORMAT:
**1. CLINICAL OVERVIEW**
* **Scan Modality:** [TAS/TVS, Fetal/Gyn/Early Pregnancy]
* **Indication:** [Echo user provided context]

**2. DETAILED FINDINGS**
* **Anatomy survey:** [Structure, position, and echo-texture]
* **Morphology & Pathology:** [Abnormalities or specific normal findings]
* **Biometry:** [Numerical data extracted from annotations]

**3. CLINICAL IMPRESSION**
* [Integrated diagnostic conclusion in 1-2 sentences]

---
*Report generated via OGXAI Consultation Protocol*
`;

/**
 * Performs a clinical analysis on ultrasound scans.
 * Switched to gemini-3-flash-preview for maximum speed and stability.
 */
export async function analyzeUltrasound(images64: string[], clinicalContext?: string): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  // Using gemini-3-flash-preview as the optimized high-speed model allowed by guidelines.
  const model = 'gemini-3-flash-preview';

  const prompt = `Perform a high-speed clinical analysis on these ${images64.length} ultrasound scan(s). ${clinicalContext ? `Clinical Context: "${clinicalContext}"` : ''} 
  Synthesize all visual evidence into one integrated professional report immediately.`;

  const imageParts: Part[] = images64.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64,
    },
  }));

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: model,
    contents: { parts: [...imageParts, { text: prompt }] },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.0,
      thinkingConfig: { thinkingBudget: 0 }
    },
  });

  if (!response.text) throw new Error("Analysis failed to generate text output.");
  return response.text;
}

/**
 * Refines the ultrasound report based on physician input.
 */
export async function refineReport(
  images64: string[], 
  previousReport: string, 
  refinement: string,
  clinicalContext?: string
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const imageParts: Part[] = images64.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64,
    },
  }));

  const contents: Content[] = [
    {
      role: 'user',
      parts: [
        ...imageParts,
        { text: `Initial context for the images: ${clinicalContext || 'No specific clinical indication provided.'}` }
      ]
    },
    {
      role: 'model',
      parts: [{ text: previousReport }]
    },
    {
      role: 'user',
      parts: [{ text: `Attending Physician Input: "${refinement}". Update the report ensuring this new information is integrated.` }]
    }
  ];

  const response = await ai.models.generateContent({
    model: model,
    contents: contents,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.0,
      thinkingConfig: { thinkingBudget: 0 }
    },
  });

  if (!response.text) throw new Error("Refinement failed.");
  return response.text;
}

import React, { useRef, useState } from 'react';
import CameraCapture from './CameraCapture.tsx';

interface Props {
  onImagesChange: (images: string[]) => void;
  images: string[];
  disabled: boolean;
}

const ImageUploader: React.FC<Props> = ({ onImagesChange, images, disabled }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []);
    if (files.length === 0) return;

    const newImagesBase64 = await Promise.all(
      files.map(file => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
      })
    );

    onImagesChange([...images, ...newImagesBase64]);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const triggerUpload = () => {
    if (!disabled) {
      fileInputRef.current?.click();
    }
  };

  const handleCapture = (base64: string) => {
    onImagesChange([...images, base64]);
    setIsCameraOpen(false);
  };

  const removeImage = (index: number) => {
    if (disabled) return;
    const updated = images.filter((_, i) => i !== index);
    onImagesChange(updated);
  };

  return (
    <div className="space-y-8">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        accept="image/*"
        multiple
        className="hidden"
        disabled={disabled}
      />

      {isCameraOpen && (
        <CameraCapture onCapture={handleCapture} onClose={() => setIsCameraOpen(false)} />
      )}

      <div className="grid grid-cols-2 gap-5">
        <button 
          onClick={triggerUpload}
          disabled={disabled}
          className={`group border-2 border-dashed border-slate-100 rounded p-6 transition-all flex flex-col items-center justify-center bg-slate-50 hover:bg-white hover:border-[#D4AF37] disabled:opacity-30`}
        >
          <div className="w-10 h-10 bg-white border border-slate-100 rounded flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
            <i className="fas fa-upload text-slate-300 group-hover:text-[#D4AF37]"></i>
          </div>
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-[#000000]">File Import</p>
        </button>

        <button 
          onClick={() => !disabled && setIsCameraOpen(true)}
          disabled={disabled}
          className={`group border-2 border-dashed border-slate-100 rounded p-6 transition-all flex flex-col items-center justify-center bg-slate-50 hover:bg-white hover:border-[#D4AF37] disabled:opacity-30`}
        >
          <div className="w-10 h-10 bg-white border border-slate-100 rounded flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
            <i className="fas fa-camera text-slate-300 group-hover:text-[#D4AF37]"></i>
          </div>
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-[#000000]">Live Scan</p>
        </button>
      </div>

      {images.length > 0 && (
        <div className="grid grid-cols-2 gap-4 max-h-[450px] overflow-y-auto p-2 scrollbar-hide">
          {images.map((img, idx) => (
            <div key={idx} className="relative rounded overflow-hidden border border-slate-100 shadow-sm aspect-square group">
              <img 
                src={img} 
                alt={`Scan ${idx + 1}`} 
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
              />
              {!disabled && (
                <button 
                  onClick={() => removeImage(idx)}
                  className="absolute top-2 right-2 bg-[#000000] text-white w-7 h-7 rounded flex items-center justify-center text-[10px] shadow-xl opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <i className="fas fa-xmark"></i>
                </button>
              )}
              <div className="absolute bottom-2 left-2 bg-white/90 text-[#000000] text-[8px] px-2 py-1 rounded backdrop-blur-md font-black uppercase tracking-widest shadow-sm">
                Frame {idx + 1}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

