            </div>
          </div>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-4 md:h-8" />;

      return <p key={i} className="text-base md:text-lg text-slate-700 leading-relaxed mb-6 md:mb-8 font-medium">{line}</p>;
    });
