import React, { useRef, useState, useEffect } from 'react';

interface Props {
  onCapture: (base64: string) => void;
  onClose: () => void;
}

const CameraCapture: React.FC<Props> = ({ onCapture, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('environment');

  const startCamera = async () => {
    try {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
      // Relaxed constraints for better mobile compatibility
      const constraints = {
        video: { 
          facingMode: facingMode,
          width: { ideal: 1920 },
          height: { ideal: 1080 }
        }
      };

      const newStream = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(newStream);
      if (videoRef.current) {
        videoRef.current.srcObject = newStream;
      }
      setError(null);
    } catch (err) {
      console.error("Camera access error:", err);
      setError("Unable to access camera. Please ensure HTTPS and permissions.");
    }
  };

  useEffect(() => {
    startCamera();
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [facingMode]);

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg', 0.9);
        onCapture(base64);
      }
    }
  };

  const toggleCamera = () => {
    setFacingMode(prev => prev === 'user' ? 'environment' : 'user');
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center">
      <div className="relative w-full h-full md:max-w-4xl md:h-auto md:aspect-video bg-black overflow-hidden flex items-center justify-center">
        {error ? (
          <div className="text-white text-center p-8">
            <i className="fas fa-exclamation-triangle text-4xl text-[#D4AF37] mb-6"></i>
            <p className="text-sm font-bold uppercase tracking-widest">{error}</p>
            <button 
              onClick={onClose}
              className="mt-8 bg-white/10 hover:bg-white/20 text-white px-8 py-3 rounded-full text-xs font-black uppercase tracking-widest transition-all"
            >
              Close
            </button>
          </div>
        ) : (
          <>
            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted
              className="w-full h-full object-cover"
            />

            {/* Overlay UI */}
            <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none">
              <div className="bg-black/40 backdrop-blur-md px-4 py-2 rounded-sm border border-white/10">
                <p className="text-[10px] text-[#D4AF37] font-black uppercase tracking-[0.3em]">Live Feed</p>
              </div>
              <div className="flex gap-4 pointer-events-auto">
                <button 
                  onClick={toggleCamera}
                  className="w-12 h-12 bg-white/10 backdrop-blur-md text-white rounded-full flex items-center justify-center border border-white/20 active:scale-90 transition-transform"
                >
                  <i className="fas fa-camera-rotate"></i>
                </button>
                <button 
                  onClick={onClose}
                  className="w-12 h-12 bg-white/10 backdrop-blur-md text-white rounded-full flex items-center justify-center border border-white/20 active:scale-90 transition-transform"
                >
                  <i className="fas fa-times"></i>
                </button>
              </div>
            </div>

            <div className="absolute bottom-12 left-0 w-full flex flex-col items-center gap-8 px-6">
              <p className="text-[10px] text-white/40 font-bold uppercase tracking-[0.5em] text-center">Center clinical features in frame</p>
              <button 
                onClick={capturePhoto}
                className="w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-2xl active:scale-90 transition-transform border-4 border-[#D4AF37]/30"
              >
                <div className="w-16 h-16 rounded-full border-4 border-black flex items-center justify-center">
                   <div className="w-14 h-14 bg-black rounded-full"></div>
                </div>
              </button>
            </div>
          </>
        )}
      </div>
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

