interface Props {
  onImagesChange: (images: string[]) => void;
  images: string[];
  disabled: boolean;
}

const ImageUploader: React.FC<Props> = ({ onImagesChange, images, disabled }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    // Fixed: Added explicit type casting to File[] to ensure the map callback correctly identifies 'file' as a Blob/File.
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImagesBase64 = await Promise.all(
      files.map(file => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          // Fixed: 'file' is now correctly typed as File, which is a subtype of Blob.
          reader.readAsDataURL(file);
        });
      })
    );

    onImagesChange([...images, ...newImagesBase64]);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const triggerUpload = () => {
    if (!disabled) {
      fileInputRef.current?.click();
    }
  };

  const handleCapture = (base64: string) => {
    onImagesChange([...images, base64]);
    setIsCameraOpen(false);
  };

  const removeImage = (index: number) => {
    if (disabled) return;
    const updated = images.filter((_, i) => i !== index);
    onImagesChange(updated);
  };

  return (
    <div className="space-y-8">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        accept="image/*"
        multiple
        className="hidden"
        disabled={disabled}
      />

      {isCameraOpen && (
        <CameraCapture onCapture={handleCapture} onClose={() => setIsCameraOpen(false)} />
      )}

      <div className="grid grid-cols-2 gap-5">
        <button 
          onClick={triggerUpload}
          disabled={disabled}
          className={`group border-2 border-dashed border-slate-100 rounded p-6 transition-all flex flex-col items-center justify-center bg-slate-50 hover:bg-white hover:border-[#D4AF37] disabled:opacity-30`}
        >
          <div className="w-10 h-10 bg-white border border-slate-100 rounded flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
            <i className="fas fa-upload text-slate-300 group-hover:text-[#D4AF37]"></i>
          </div>
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-[#000000]">File Import</p>
        </button>

        <button 
          onClick={() => !disabled && setIsCameraOpen(true)}
          disabled={disabled}
          className={`group border-2 border-dashed border-slate-100 rounded p-6 transition-all flex flex-col items-center justify-center bg-slate-50 hover:bg-white hover:border-[#D4AF37] disabled:opacity-30`}
        >
          <div className="w-10 h-10 bg-white border border-slate-100 rounded flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
            <i className="fas fa-camera text-slate-300 group-hover:text-[#D4AF37]"></i>
          </div>
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-[0.3em] group-hover:text-[#000000]">Live Scan</p>
        </button>
      </div>

      {images.length > 0 && (
        <div className="grid grid-cols-2 gap-4 max-h-[450px] overflow-y-auto p-2 scrollbar-hide">
          {images.map((img, idx) => (
            <div key={idx} className="relative rounded overflow-hidden border border-slate-100 shadow-sm aspect-square group">
              <img 
                src={img} 
                alt={`Scan ${idx + 1}`} 
                className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-105"
              />
              {!disabled && (
                <button 
                  onClick={() => removeImage(idx)}
                  className="absolute top-2 right-2 bg-[#000000] text-white w-7 h-7 rounded flex items-center justify-center text-[10px] shadow-xl opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <i className="fas fa-xmark"></i>
                </button>
              )}
              <div className="absolute bottom-2 left-2 bg-white/90 text-[#000000] text-[8px] px-2 py-1 rounded backdrop-blur-md font-black uppercase tracking-widest shadow-sm">
                Frame {idx + 1}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ImageUploader;

import React, { useRef, useState, useEffect } from 'react';

interface Props {
  onCapture: (base64: string) => void;
  onClose: () => void;
}

const CameraCapture: React.FC<Props> = ({ onCapture, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [stream, setStream] = useState<MediaStream | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [facingMode, setFacingMode] = useState<'user' | 'environment'>('environment');
  const [isInitializing, setIsInitializing] = useState(true);

  const startCamera = async (isFallback = false) => {
    setIsInitializing(true);
    try {
      if (!navigator.mediaDevices || !navigator.mediaDevices.getUserMedia) {
        throw new Error("Your browser does not support camera access or you are not using HTTPS.");
      }

      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }

      const constraints: MediaStreamConstraints = {
        video: isFallback ? true : { 
          facingMode: facingMode,
          width: { ideal: 1920 },
          height: { ideal: 1080 }
        },
        audio: false
      };

      const newStream = await navigator.mediaDevices.getUserMedia(constraints);
      setStream(newStream);

      if (videoRef.current) {
        videoRef.current.srcObject = newStream;
        // Ensure video plays once metadata is loaded
        videoRef.current.onloadedmetadata = () => {
          videoRef.current?.play().catch(e => console.error("Video play failed:", e));
        };
      }
      setError(null);
    } catch (err: any) {
      console.error("Camera access error:", err);

      if (!isFallback && err.name !== 'NotAllowedError') {
        // If high-res failed but not because of permissions, try basic video
        console.log("Attempting fallback camera initialization...");
        startCamera(true);
        return;
      }

      let userMessage = "Unable to access camera.";
      if (err.name === 'NotAllowedError' || err.name === 'PermissionDeniedError') {
        userMessage = "Camera permission was denied. Please check your browser settings and site permissions.";
      } else if (err.name === 'NotFoundError' || err.name === 'DevicesNotFoundError') {
        userMessage = "No camera found on this device.";
      } else if (location.protocol !== 'https:' && location.hostname !== 'localhost') {
        userMessage = "Camera access requires a secure connection (HTTPS).";
      } else {
        userMessage = err.message || "An unknown error occurred while accessing the camera.";
      }
      setError(userMessage);
    } finally {
      setIsInitializing(false);
    }
  };

  useEffect(() => {
    startCamera();
    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [facingMode]);

  const capturePhoto = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;

      // Use actual video dimensions
      const width = video.videoWidth || video.clientWidth;
      const height = video.videoHeight || video.clientHeight;

      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, width, height);
        const base64 = canvas.toDataURL('image/jpeg', 0.9);
        onCapture(base64);
      }
    }
  };

  const toggleCamera = () => {
    setFacingMode(prev => prev === 'user' ? 'environment' : 'user');
  };

  return (
    <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center">
      <div className="relative w-full h-full md:max-w-4xl md:h-auto md:aspect-video bg-black overflow-hidden flex items-center justify-center">
        {error ? (
          <div className="text-white text-center p-8 max-w-md">
            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-6">
              <i className="fas fa-exclamation-triangle text-2xl text-red-500"></i>
            </div>
            <h4 className="text-sm font-bold uppercase tracking-[0.2em] mb-4">Hardware Access Blocked</h4>
            <p className="text-xs text-slate-400 font-medium leading-loose uppercase tracking-widest">{error}</p>
            <div className="flex flex-col gap-4 mt-10">
              <button 
                onClick={() => startCamera()}
                className="bg-[#D4AF37] text-black px-8 py-4 rounded-sm text-[10px] font-black uppercase tracking-widest transition-all hover:bg-white"
              >
                Retry Initialization
              </button>
              <button 
                onClick={onClose}
                className="text-white/40 hover:text-white px-8 py-3 text-[10px] font-black uppercase tracking-widest transition-all"
              >
                Return to Dashboard
              </button>
            </div>
          </div>
        ) : (
          <>
            {isInitializing && (
              <div className="absolute inset-0 z-10 flex flex-col items-center justify-center bg-black">
                <div className="w-12 h-12 border-2 border-white/10 border-t-[#D4AF37] rounded-full animate-spin mb-6"></div>
                <p className="text-[10px] text-white/40 font-bold uppercase tracking-[0.5em]">Synchronizing Optical Feed...</p>
              </div>
            )}

            <video 
              ref={videoRef} 
              autoPlay 
              playsInline 
              muted
              className="w-full h-full object-cover"
            />

            <div className="absolute top-0 left-0 w-full p-6 flex justify-between items-start pointer-events-none">
              <div className="bg-black/40 backdrop-blur-md px-4 py-2 rounded-sm border border-white/10">
                <p className="text-[10px] text-[#D4AF37] font-black uppercase tracking-[0.3em]">
                  <i className="fas fa-circle text-[8px] mr-2 animate-pulse text-red-500"></i>
                  Live Feed
                </p>
              </div>
              <div className="flex gap-4 pointer-events-auto">
                <button 
                  onClick={toggleCamera}
                  className="w-12 h-12 bg-white/10 backdrop-blur-md text-white rounded-full flex items-center justify-center border border-white/20 active:scale-95 transition-transform"
                  title="Switch Camera"
                >
                  <i className="fas fa-camera-rotate"></i>
                </button>
                <button 
                  onClick={onClose}
                  className="w-12 h-12 bg-white/10 backdrop-blur-md text-white rounded-full flex items-center justify-center border border-white/20 active:scale-95 transition-transform"
                  title="Close Camera"
                >
                  <i className="fas fa-times"></i>
                </button>
              </div>
            </div>

            <div className="absolute bottom-12 left-0 w-full flex flex-col items-center gap-8 px-6">
              <p className="text-[10px] text-white/40 font-bold uppercase tracking-[0.5em] text-center drop-shadow-md">
                Align morphology in crosshairs
              </p>
              <button 
                onClick={capturePhoto}
                className="group relative w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-2xl active:scale-90 transition-all border-4 border-[#D4AF37]/30"
              >
                <div className="w-16 h-16 rounded-full border-4 border-black flex items-center justify-center group-hover:bg-slate-50 transition-colors">
                   <div className="w-14 h-14 bg-black rounded-full flex items-center justify-center">
                      <div className="w-1 h-1 bg-white rounded-full animate-pulse"></div>
                   </div>
                </div>
              </button>
            </div>
          </>
        )}
      </div>
      <canvas ref={canvasRef} className="hidden" />
    </div>
  );
};

export default CameraCapture;

import React, { useState, useEffect } from 'react';
import { analyzeUltrasound, refineReport } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';
import AccessGate from './components/AccessGate.tsx';

const App: React.FC = () => {
  const [isAuthorized, setIsAuthorized] = useState<boolean>(false);
  const [images, setImages] = useState<string[]>([]);
  const [clinicalContext, setClinicalContext] = useState('');
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isRefining, setIsRefining] = useState(false);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  // Check session storage on mount (similar to Streamlit session_state logic)
  useEffect(() => {
    const authStatus = sessionStorage.getItem('ogxai_authorized');
    if (authStatus === 'true') {
      setIsAuthorized(true);
    }
  }, []);

  const handleLoginSuccess = () => {
    setIsAuthorized(true);
    sessionStorage.setItem('ogxai_authorized', 'true');
  };

  const handleImagesChange = (newImages: string[]) => {
    setImages(newImages);
    if (newImages.length === 0) {
      setAnalysis(null);
    }
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) await window.aistudio.openSelectKey();
    }

    setStatus({
      isAnalyzing: true,
      progressMessage: 'Initializing OGXAI Diagnostic Engine...',
      error: null,
    });

    try {
      const messages = [
        'Ingesting clinical frames...',
        'Synthesizing morphological data...',
        'Cross-referencing anatomical markers...',
        'Finalizing reporting dossier...',
      ];

      let msgIndex = 0;
      const interval = setInterval(() => {
        if (msgIndex < messages.length - 1) {
          msgIndex++;
          setStatus(prev => ({ ...prev, progressMessage: messages[msgIndex] }));
        }
      }, 1500);

      const reportMarkdown = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext
      );

      clearInterval(interval);
      setAnalysis({
        reportMarkdown,
        timestamp: new Date().toLocaleString(),
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      handleError(err);
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (images.length === 0 || !analysis) return;

    setIsRefining(true);
    try {
      const updatedReport = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext
      );
      setAnalysis({
        ...analysis,
        reportMarkdown: updatedReport,
        timestamp: new Date().toLocaleString() + " (Revision)"
      });
    } catch (err: any) {
      handleError(err);
    } finally {
      setIsRefining(false);
    }
  };

  const handleError = (err: any) => {
    let errorMsg = err.message || 'The system encountered an operational error.';
    if (errorMsg.includes('{')) {
      try {
        const parsed = JSON.parse(errorMsg);
        errorMsg = parsed.error?.message || errorMsg;
      } catch(e) {}
    }

    if (errorMsg.includes("Requested entity was not found.") && window.aistudio) {
      window.aistudio.openSelectKey();
    }

    setStatus({ isAnalyzing: false, progressMessage: '', error: errorMsg });
  };

  const reset = () => {
    setImages([]);
    setClinicalContext('');
    setAnalysis(null);
    setStatus({ isAnalyzing: false, progressMessage: '', error: null });
  };

  // Logic: Stop rendering the app if not authorized
  if (!isAuthorized) {
    return <AccessGate onGrantAccess={handleLoginSuccess} />;
  }

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Header />

      <main className="flex-grow container mx-auto px-4 md:px-10 py-10 md:py-20 max-w-[1400px]">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10 md:gap-20">

          <div className="lg:col-span-4 order-2 lg:order-1">
            <section className="bg-white border-t-4 md:border-t-8 border-[#D4AF37] p-6 md:p-12 shadow-[0_30px_90px_rgba(0,0,0,0.03)] sticky top-24 md:top-48">
              <h2 className="text-sm md:text-base font-bold text-[#000000] uppercase tracking-[0.3em] md:tracking-[0.5em] mb-8 md:mb-16 border-b border-slate-50 pb-4 md:pb-8">
                Clinical Parameters
              </h2>

              <div className="space-y-10 md:space-y-16">
                <div>
                  <label className="text-[9px] md:text-[11px] font-bold text-slate-400 uppercase tracking-[0.3em] md:tracking-[0.4em] mb-4 md:mb-6 block">
                    Imaging Assets
                  </label>
                  <ImageUploader 
                    onImagesChange={handleImagesChange} 
                    images={images} 
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>

                <div className="pt-2">
                  <label className="text-[9px] md:text-[11px] font-bold text-slate-400 uppercase tracking-[0.3em] md:tracking-[0.4em] mb-4 md:mb-6 block">
                    Case Context
                  </label>
                  <textarea 
                    value={clinicalContext}
                    onChange={(e) => setClinicalContext(e.target.value)}
                    placeholder="Patient GA, maternal age..."
                    className="w-full bg-slate-50 border-2 border-slate-50 rounded-sm p-4 md:p-6 text-sm md:text-base font-medium focus:bg-white focus:border-[#D4AF37] outline-none transition-all h-32 md:h-48 resize-none shadow-inner"
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>
              </div>

              {images.length > 0 && !analysis && !status.error && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-10 md:mt-20 bg-[#000000] hover:bg-slate-900 disabled:opacity-50 text-white text-[10px] md:text-xs font-bold uppercase tracking-[0.3em] md:tracking-[0.5em] py-6 md:py-8 rounded-sm shadow-2xl shadow-black/30 transition-all flex items-center justify-center gap-4 md:gap-6"
                >
                  <i className={`fas ${status.isAnalyzing ? 'fa-spinner fa-spin' : 'fa-wave-square'}`}></i>
                  {status.isAnalyzing ? 'Analyzing...' : 'Run Diagnostics'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={reset}
                  className="w-full mt-8 md:mt-12 text-slate-400 hover:text-[#000000] text-[10px] md:text-xs font-bold uppercase tracking-[0.3em] md:tracking-[0.4em] transition-all flex items-center justify-center gap-4 py-4 md:py-6 border-2 border-slate-50 rounded-sm"
                >
                  <i className="fas fa-plus"></i>
                  New Session
                </button>
              )}
            </section>
          </div>

          <div className="lg:col-span-8 order-1 lg:order-2">
            {status.error && (
              <div className="border-l-[6px] md:border-l-[10px] border-red-500 bg-red-50/50 p-6 md:p-16 rounded-sm shadow-sm">
                <div className="flex flex-col md:flex-row gap-6 md:gap-12 items-start">
                  <div className="text-red-500 pt-1">
                    <i className="fas fa-exclamation-circle text-2xl md:text-4xl"></i>
                  </div>
                  <div className="flex-grow">
                      <h4 className="font-bold text-[#000000] uppercase text-[10px] md:text-sm tracking-[0.4em] md:tracking-[0.6em] mb-4 md:mb-6">Process Interruption</h4>
                      <p className="text-base md:text-xl text-slate-600 leading-relaxed font-medium">{status.error}</p>

                      <div className="mt-8 md:mt-12">
                        <button onClick={startAnalysis} className="bg-[#000000] text-white text-[10px] md:text-xs font-bold uppercase tracking-[0.3em] md:tracking-[0.5em] py-4 md:py-5 px-8 md:px-12 rounded-sm hover:bg-slate-800 transition-all">
                           Restart Session
                        </button>
                      </div>
                  </div>
                </div>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="bg-slate-50/30 border-2 border-dashed border-slate-100 rounded-sm p-12 md:p-32 text-center flex flex-col items-center justify-center min-h-[400px] md:min-h-[800px]">
                <div className="w-20 h-20 md:w-32 md:h-32 border-[2px] md:border-[3px] border-slate-100 rounded-full flex items-center justify-center mb-8 md:mb-12 text-slate-200">
                  <i className="fas fa-file-alt text-3xl md:text-5xl"></i>
                </div>
                <h3 className="text-[#000000] font-bold text-base md:text-lg uppercase tracking-[0.4em] md:tracking-[0.6em] mb-4 md:mb-8">Ready for Intake</h3>
                <p className="text-slate-400 text-[10px] md:text-xs max-w-md leading-loose font-bold uppercase tracking-[0.2em] md:tracking-[0.4em] opacity-40">
                  Import scan data to initiate reporting.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay 
                analysis={analysis} 
                onUpdate={onUpdateReport}
                isUpdating={isRefining}
              />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="bg-white py-16 md:py-32 text-center border-t border-slate-50">
        <div className="container mx-auto px-6">
          <p className="font-bold uppercase tracking-[0.5em] md:tracking-[1em] mb-6 md:mb-10 text-[#000000] text-[9px] md:text-xs">OGXAI CLINICAL SYSTEMS</p>
          <div className="w-12 md:w-20 h-1 md:h-1.5 bg-[#D4AF37] mx-auto mb-8 md:mb-12"></div>
          <p className="max-w-4xl mx-auto opacity-30 text-[9px] md:text-[11px] leading-loose uppercase tracking-[0.2em] md:tracking-[0.4em] font-bold text-slate-500">
            Professional verification required. Supports but does not replace assessment.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

