            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="ENTER ACCESS CODE"
              autoFocus
              className={`w-full bg-white/5 border-b-2 ${error ? 'border-red-500' : 'border-white/20'} focus:border-[#D4AF37] px-4 py-6 text-center text-white font-bold tracking-[0.6em] text-lg outline-none transition-all placeholder:text-white/10 placeholder:tracking-widest`}
            />
            {error && (
              <p className="absolute -bottom-8 left-0 w-full text-red-500 text-[9px] font-black uppercase tracking-widest animate-pulse">
