import React, { useRef, useState } from 'react';
import CameraCapture from './CameraCapture.tsx';

interface Props {
  onImagesChange: (images: string[]) => void;
  images: string[];
  disabled: boolean;
}

const ImageUploader: React.FC<Props> = ({ onImagesChange, images, disabled }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImagesBase64 = await Promise.all(
      files.map(file => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
      })
    );

    onImagesChange([...images, ...newImagesBase64]);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const triggerUpload = () => {
    if (!disabled) {
      fileInputRef.current?.click();
    }
  };

  const handleCapture = (base64: string) => {
    onImagesChange([...images, base64]);
    setIsCameraOpen(false);
  };

  const removeImage = (index: number) => {
    if (disabled) return;
    const updated = images.filter((_, i) => i !== index);
    onImagesChange(updated);
  };

  return (
    <div className="space-y-10">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        accept="image/*"
        multiple
        className="hidden"
        disabled={disabled}
      />

      {isCameraOpen && (
        <CameraCapture onCapture={handleCapture} onClose={() => setIsCameraOpen(false)} />
      )}

      <div className="grid grid-cols-2 gap-6">
        <button 
          onClick={triggerUpload}
          disabled={disabled}
          className={`group glass-panel rounded-sm p-8 transition-all hover:bg-white/10 hover:border-[#D4AF37] disabled:opacity-30 gold-glow-hover`}
        >
          <div className="w-12 h-12 bg-white/5 border border-white/10 rounded-sm flex items-center justify-center mb-6 mx-auto group-hover:scale-110 group-hover:bg-[#D4AF37]/10 transition-transform">
            <i className="fas fa-upload text-white/20 group-hover:text-[#D4AF37] text-xl"></i>
          </div>
          <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.4em] group-hover:text-[#D4AF37] text-center">Data Import</p>
        </button>

        <button 
          onClick={() => !disabled && setIsCameraOpen(true)}
          disabled={disabled}
          className={`group glass-panel rounded-sm p-8 transition-all hover:bg-white/10 hover:border-[#D4AF37] disabled:opacity-30 gold-glow-hover`}
        >
          <div className="w-12 h-12 bg-white/5 border border-white/10 rounded-sm flex items-center justify-center mb-6 mx-auto group-hover:scale-110 group-hover:bg-[#D4AF37]/10 transition-transform">
            <i className="fas fa-eye text-white/20 group-hover:text-[#D4AF37] text-xl"></i>
          </div>
          <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.4em] group-hover:text-[#D4AF37] text-center">Live Feed</p>
        </button>
      </div>

      {images.length > 0 && (
        <div className="grid grid-cols-2 gap-4 max-h-[500px] overflow-y-auto p-4 glass-panel rounded-sm scrollbar-hide">
          {images.map((img, idx) => (
            <div key={idx} className="relative rounded-sm overflow-hidden border border-white/10 shadow-2xl aspect-[4/3] group bg-black">
              <img 
                src={img} 
                alt={`Scan ${idx + 1}`} 
                className="w-full h-full object-cover transition-transform duration-[2000ms] group-hover:scale-125 opacity-80 group-hover:opacity-100"
              />
              {!disabled && (
                <button 
                  onClick={() => removeImage(idx)}
                  className="absolute top-4 right-4 bg-black/80 text-[#D4AF37] w-8 h-8 rounded-sm flex items-center justify-center text-xs shadow-2xl border border-[#D4AF37]/20 opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <i className="fas fa-times"></i>
                </button>
              )}
              <div className="absolute bottom-4 left-4 bg-black/60 backdrop-blur-md text-[#D4AF37] text-[10px] px-3 py-1.5 rounded-sm font-black uppercase tracking-[0.3em] border border-[#D4AF37]/20">
                LENS {idx + 1}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

