interface Props {
  analysis: AnalysisResult;
  onUpdate?: (comment: string) => void;
  isUpdating?: boolean;
}

const ReportDisplay: React.FC<Props> = ({ analysis, onUpdate, isUpdating }) => {
  const [comment, setComment] = useState('');

  const suggestions = [
    "RE-EVALUATE IMPRESSION",
    "EXPAND MORPHOLOGY",
    "RE-SCAN MEASUREMENTS",
    "SUMMARIZE CASE"
  ];

  const handleUpdate = (customComment?: string) => {
    const finalComment = customComment || comment;
    if (finalComment.trim() && onUpdate) {
      onUpdate(finalComment);
      setComment('');
    }
  };

  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Headers
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return (
          <h4 key={i} className="text-[14px] md:text-[16px] font-black text-[#D4AF37] mt-16 mb-8 uppercase tracking-[0.6em] flex items-center gap-6">
            <span className="w-12 h-[1px] bg-[#D4AF37]/30"></span>
            {content}
          </h4>
        );
      }

      // Major Section Headers (1. 2. 3.)
      if (line.match(/^\d\.\s/)) {
        return (
          <div key={i} className="flex flex-col gap-6 mt-24 mb-16 border-l-4 border-[#D4AF37] pl-10">
            <span className="text-[10px] font-black text-white/20 uppercase tracking-[0.8em]">Section Protocol {line.charAt(0)}</span>
            <h3 className="text-3xl md:text-5xl font-black text-white tracking-tighter uppercase">{line.substring(3)}</h3>
          </div>
        );
      }

      // Bullet points (Key/Value mapping)
      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <div key={i} className="flex flex-col lg:flex-row gap-4 lg:gap-12 py-6 border-b border-white/5 last:border-0 hover:bg-white/5 transition-colors px-6 group rounded-sm">
                    <span className="text-[11px] font-black text-white/30 uppercase tracking-[0.4em] lg:min-w-[280px] group-hover:text-[#D4AF37] transition-colors">{parts[0]}</span> 
                    <span className="text-lg md:text-xl text-white/90 leading-relaxed font-light">{parts.slice(1).join(':')}</span>
                </div>
            );
        }
        return (
          <p key={i} className="text-lg md:text-xl text-white/80 leading-relaxed py-4 flex gap-6 items-start">
            <span className="w-1.5 h-1.5 bg-[#D4AF37] mt-3 flex-shrink-0 gold-glow"></span>
            {content}
          </p>
        );
      }

      // Footer
      if (line.includes('Report generated via OGXAI')) {
        return (
          <div key={i} className="mt-32 pt-20 border-t border-white/10 flex flex-col md:flex-row justify-between items-end gap-10 opacity-30 group">
            <div className="text-left">
              <p className="text-[10px] font-black text-white/40 uppercase tracking-[0.5em] mb-4">Diagnostic Verification ID</p>
              <div className="font-black text-[#D4AF37] text-lg uppercase tracking-[0.3em]">QUANTUM-X-CORE-{Math.random().toString(36).substr(2, 6).toUpperCase()}</div>
            </div>
            <div className="text-right">
              <p className="text-[9px] font-black uppercase tracking-[0.4em]">Proprietary OGXAI Intelligence Protocol</p>
            </div>
          </div>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-8" />;

      return <p key={i} className="text-lg md:text-xl text-white/60 leading-relaxed mb-10 font-light italic">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col gap-16 animate-in fade-in slide-in-from-bottom-20 duration-1000">
      <div className="glass-panel overflow-hidden rounded-xl">
        <div className="bg-black/80 border-b border-white/5 px-10 md:px-20 py-10 flex justify-between items-center">
          <div className="flex items-center gap-8">
            <div className="w-10 h-10 border border-[#D4AF37]/40 flex items-center justify-center p-2">
               <div className="w-full h-full bg-[#D4AF37] gold-glow animate-pulse"></div>
            </div>
            <h2 className="text-white font-black tracking-[0.8em] uppercase text-xs">Diagnostic Ingestion</h2>
          </div>
          <div className="flex gap-10">
            <button onClick={() => window.print()} className="text-white/20 hover:text-[#D4AF37] transition-all hover:scale-125">
              <i className="fas fa-print text-xl"></i>
            </button>
            <button onClick={() => { navigator.clipboard.writeText(analysis.reportMarkdown); }} className="text-white/20 hover:text-[#D4AF37] transition-all hover:scale-125">
              <i className="fas fa-fingerprint text-xl"></i>
            </button>
          </div>
        </div>

        <div className="p-12 md:p-32 relative">
          {isUpdating && (
            <div className="absolute inset-0 bg-black/95 backdrop-blur-xl z-50 flex items-center justify-center transition-all">
              <div className="flex flex-col items-center gap-10">
                <div className="w-20 h-20 border border-white/10 border-t-[#D4AF37] rounded-full animate-spin"></div>
                <p className="text-sm font-black text-[#D4AF37] uppercase tracking-[0.8em] animate-pulse">Refining Neural Patterns</p>
              </div>
            </div>
          )}

          <div className="flex flex-col xl:flex-row justify-between items-start xl:items-end border-b-2 border-white/5 pb-20 mb-20 gap-12">
            <div>
              <div className="text-6xl md:text-9xl font-black text-white tracking-tighter leading-none">D-DOSSIER</div>
              <div className="text-[12px] md:text-sm text-[#D4AF37] font-black uppercase tracking-[1em] mt-8 flex items-center gap-6">
                <div className="w-10 h-[1px] bg-[#D4AF37]/30"></div>
                INTELLIGENCE REPORT
              </div>
            </div>
            <div className="text-left xl:text-right font-black uppercase tracking-[0.4em]">
              <div className="text-[10px] text-white/10 mb-2">VALIDATION TIMESTAMP</div>
              <div className="text-sm md:text-lg text-[#D4AF37] tabular-nums">{analysis.timestamp}</div>
              <div className="text-[10px] text-white/10 mt-10 mb-2">ACCESS CLEARANCE</div>
              <div className="text-xs md:text-sm text-white/40">LEVEL 4 - PHYSICIAN ONLY</div>
            </div>
          </div>

          <div className="report-content max-w-none">
            {formatMarkdown(analysis.reportMarkdown)}
          </div>
        </div>
      </div>

      <div className="glass-panel p-10 md:p-20 rounded-xl">
        <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-16 gap-10">
          <h3 className="text-[12px] font-black text-white uppercase tracking-[0.6em] flex items-center gap-6">
            <i className="fas fa-brain text-[#D4AF37]"></i>
            Neural Adaptation
          </h3>
          <div className="flex flex-wrap gap-4">
            {suggestions.map((s, idx) => (
              <button 
                key={idx}
                onClick={() => handleUpdate(s)}
                className="text-[10px] font-black text-white/30 bg-white/5 hover:bg-[#D4AF37] hover:text-black px-6 py-4 rounded-sm border border-white/5 transition-all uppercase tracking-widest"
              >
                {s}
              </button>
            ))}
          </div>
        </div>
        <div className="flex flex-col xl:flex-row gap-10">
          <textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            placeholder="ENTER REFINEMENT COMMAND..."
            className="flex-grow input-dark rounded-sm p-8 text-xs font-bold tracking-[0.2em] uppercase leading-loose h-40 xl:h-auto resize-none"
            disabled={isUpdating}
          />
          <button
            onClick={() => handleUpdate()}
            disabled={isUpdating || !comment.trim()}
            className="btn-gold min-w-full xl:min-w-[300px] h-32 xl:h-auto rounded-sm flex flex-col items-center justify-center gap-6"
          >
            <i className="fas fa-sync-alt text-2xl"></i>
            <span className="text-[11px] font-black uppercase tracking-[0.6em]">Process Update</span>
          </button>
        </div>
      </div>
    </div>
  );
};

