    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;

    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) await window.aistudio.openSelectKey();
    }

    setStatus({
      isAnalyzing: true,
      progressMessage: 'Initializing Diagnostic Sequence...',
      error: null,
    });

    try {
      const messages = [
        'Uploading imaging data...',
        'Segmenting anatomical regions...',
        'Synthesizing clinical findings...',
        'Generating medical report...',
      ];

      let msgIndex = 0;
      const interval = setInterval(() => {
        if (msgIndex < messages.length - 1) {
          msgIndex++;
          setStatus(prev => ({ ...prev, progressMessage: messages[msgIndex] }));
        }
      }, 1500);

      const reportMarkdown = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext,
        patientName,
        maternalAge
      );

      clearInterval(interval);
      setAnalysis({
        reportMarkdown,
        timestamp: new Date().toLocaleString(),
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      handleError(err);
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (images.length === 0 || !analysis) return;

    setIsRefining(true);
    try {
      const updatedReport = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({
        ...analysis,
        reportMarkdown: updatedReport,
        timestamp: new Date().toLocaleString() + " (Revision)"
      });
    } catch (err: any) {
      handleError(err);
    } finally {
      setIsRefining(false);
    }
  };

  const handleError = (err: any) => {
    let errorMsg = err.message || 'System error encountered.';
    setStatus({ isAnalyzing: false, progressMessage: '', error: errorMsg });
  };

  const reset = () => {
    setImages([]);
    setClinicalContext('');
    setPatientName('');
    setMaternalAge(30);
    setAnalysis(null);
    setStatus({ isAnalyzing: false, progressMessage: '', error: null });
  };

  if (!isAuthorized) {
    return <AccessGate onGrantAccess={handleLoginSuccess} />;
  }

  return (
    <div className="min-h-screen flex flex-col">
      <Header />

      <main className="flex-grow container mx-auto px-4 md:px-8 py-8 md:py-12 max-w-[1200px]">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-12">

          <div className="lg:col-span-4 order-2 lg:order-1">
            <section className="clinical-card p-6 md:p-8 sticky top-24">
              <h2 className="text-sm font-bold text-slate-800 uppercase tracking-widest mb-8 flex items-center gap-3">
                <i className="fas fa-clipboard-list text-blue-600"></i>
                Clinical Data
              </h2>

              <div className="space-y-8">
                <div className="grid grid-cols-1 gap-6">
                  <div>
                    <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2 block">
                      Patient Name
                    </label>
                    <input 
                      type="text"
                      value={patientName}
                      onChange={(e) => setPatientName(e.target.value)}
                      placeholder="Jane Doe"
                      className="w-full input-clinical rounded-md p-3 text-sm"
                      disabled={status.isAnalyzing || isRefining}
                    />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2 block">
                      Maternal Age
                    </label>
                    <input 
                      type="number"
                      value={maternalAge}
                      onChange={(e) => setMaternalAge(parseInt(e.target.value) || 30)}
                      className="w-full input-clinical rounded-md p-3 text-sm"
                      disabled={status.isAnalyzing || isRefining}
                    />
                  </div>
                </div>

                <div>
                  <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2 block">
                    Upload Scans
                  </label>
                  <ImageUploader 
                    onImagesChange={handleImagesChange} 
                    images={images} 
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>

                <div>
                  <label className="text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2 block">
                    Clinical Context
                  </label>
                  <textarea 
                    value={clinicalContext}
                    onChange={(e) => setClinicalContext(e.target.value)}
                    placeholder="Enter clinical history or scan indication..."
                    className="w-full input-clinical rounded-md p-4 text-sm leading-relaxed h-32 resize-none"
                    disabled={status.isAnalyzing || isRefining}
                  />
                </div>
              </div>

              {images.length > 0 && !analysis && !status.error && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-10 btn-primary py-4 rounded-md shadow-sm flex items-center justify-center gap-3 transition-all"
                >
                  <i className={`fas ${status.isAnalyzing ? 'fa-spinner fa-spin' : 'fa-stethoscope'}`}></i>
                  {status.isAnalyzing ? 'Analyzing...' : 'Generate Report'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={reset}
                  className="w-full mt-6 text-slate-500 hover:text-blue-600 text-xs font-bold uppercase tracking-wider transition-all flex items-center justify-center gap-2 py-3 border border-dashed border-slate-200 rounded-md"
                >
                  <i className="fas fa-undo"></i>
                  New Patient
                </button>
              )}
            </section>
          </div>

          <div className="lg:col-span-8 order-1 lg:order-2">
            {status.error && (
              <div className="bg-red-50 border border-red-200 p-8 rounded-lg">
                <div className="flex gap-4 items-start">
                  <div className="text-red-500 pt-1">
                    <i className="fas fa-exclamation-circle text-xl"></i>
                  </div>
                  <div>
                      <h4 className="text-red-800 font-bold text-sm uppercase tracking-wider mb-2">Processing Error</h4>
                      <p className="text-slate-600 text-sm mb-6">{status.error}</p>
                      <button onClick={startAnalysis} className="text-white bg-red-600 px-6 py-2 rounded-md text-xs font-bold uppercase tracking-wider hover:bg-red-700">
                         Retry
                      </button>
                  </div>
                </div>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="bg-white border-2 border-dashed border-slate-200 rounded-lg p-16 text-center flex flex-col items-center justify-center min-h-[500px]">
                <div className="w-16 h-16 bg-slate-50 text-slate-300 rounded-full flex items-center justify-center mb-6">
                  <i className="fas fa-file-medical text-3xl"></i>
                </div>
                <h3 className="text-slate-800 font-bold text-lg mb-2">Awaiting Diagnosis</h3>
                <p className="text-slate-500 text-sm max-w-xs mx-auto">
                  Upload ultrasound imagery and enter patient details to generate a clinical report.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay 
                analysis={analysis} 
                onUpdate={onUpdateReport}
                isUpdating={isRefining}
              />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="py-12 text-center bg-white border-t border-slate-200 mt-auto">
        <div className="container mx-auto px-4">
          <p className="font-bold uppercase tracking-widest mb-4 text-slate-400 text-[10px]">OGXAI Clinical Intelligence Systems</p>
          <p className="max-w-2xl mx-auto text-slate-400 text-[11px] leading-relaxed">
            This tool is intended for professional use only. Artificial intelligence provides clinical decision support and does not replace the judgment of a qualified medical practitioner.
          </p>
        </div>
      </footer>
    </div>
  );
};

