import React, { useState } from 'react';
import { AnalysisResult } from '../types.ts';

interface Props {
  analysis: AnalysisResult;
  onUpdate?: (comment: string) => void;
  isUpdating?: boolean;
}

const ReportDisplay: React.FC<Props> = ({ analysis, onUpdate, isUpdating }) => {
  const [comment, setComment] = useState('');

  const handleUpdate = (customComment?: string) => {
    const finalComment = customComment || comment;
    if (finalComment.trim() && onUpdate) {
      onUpdate(finalComment);
      setComment('');
    }
  };

  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Headers
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return (
          <h4 key={i} className="text-[13px] font-bold text-slate-800 mt-10 mb-4 uppercase tracking-wider border-b border-slate-100 pb-2">
            {content}
          </h4>
        );
      }

      // Major Section Headers (1. 2. 3.)
      if (line.match(/^\d\.\s/)) {
        return (
          <h3 key={i} className="text-lg font-bold text-blue-800 mt-8 mb-4 border-l-4 border-blue-600 pl-3">
            {line.substring(3)}
          </h3>
        );
      }

      // Bullet points
      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <div key={i} className="flex gap-2 py-2 border-b border-slate-50 last:border-0 hover:bg-slate-50 px-2 rounded">
                    <span className="text-xs font-semibold text-slate-500 w-1/3 min-w-[150px]">{parts[0]}</span> 
                    <span className="text-sm text-slate-800 w-2/3">{parts.slice(1).join(':')}</span>
                </div>
            );
        }
        return (
          <p key={i} className="text-sm text-slate-700 py-1.5 flex gap-2 items-start ml-2">
            <span className="text-blue-600">•</span>
            {content}
          </p>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-4" />;

      return <p key={i} className="text-sm text-slate-600 leading-relaxed mb-4">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col gap-8 animate-in fade-in duration-500">
      <div className="clinical-card bg-white overflow-hidden">
        <div className="bg-slate-50 border-b border-slate-200 px-6 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <i className="fas fa-file-alt text-blue-600"></i>
            <h2 className="text-slate-800 font-bold text-xs uppercase tracking-wider">Clinical Consultation Report</h2>
          </div>
          <div className="flex gap-4">
            <button onClick={() => window.print()} className="text-slate-400 hover:text-blue-600 transition-all" title="Print Report">
              <i className="fas fa-print"></i>
            </button>
            <button onClick={() => { navigator.clipboard.writeText(analysis.reportMarkdown); }} className="text-slate-400 hover:text-blue-600 transition-all" title="Copy Text">
              <i className="fas fa-copy"></i>
            </button>
          </div>
        </div>

        <div className="p-8 md:p-12 relative min-h-[600px]">
          {isUpdating && (
            <div className="absolute inset-0 bg-white/80 backdrop-blur-sm z-50 flex items-center justify-center">
              <div className="flex flex-col items-center gap-4">
                <div className="w-10 h-10 border-2 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
                <p className="text-xs font-bold text-blue-600 uppercase tracking-widest">Updating Analysis...</p>
              </div>
            </div>
          )}

          <div className="flex flex-col md:flex-row justify-between items-start border-b-2 border-slate-100 pb-8 mb-8">
            <div className="mb-6 md:mb-0">
              <h1 className="text-2xl font-bold text-slate-900 mb-1">OGXAI REPORT</h1>
              <p className="text-[10px] text-blue-600 font-bold uppercase tracking-widest">Integrated Diagnostic Protocol</p>
            </div>
            <div className="text-right text-[11px] text-slate-500 font-medium">
              <div>REPORT TIMESTAMP: {analysis.timestamp}</div>
              <div className="mt-1">STATUS: FINALIZED VERIFICATION</div>
            </div>
          </div>

          <div className="report-content">
            {formatMarkdown(analysis.reportMarkdown)}
          </div>
        </div>
      </div>

      <div className="clinical-card p-6 bg-slate-50">
        <h3 className="text-xs font-bold text-slate-700 uppercase tracking-wider mb-6 flex items-center gap-2">
          <i className="fas fa-edit text-blue-600"></i>
          Report Amendment
        </h3>
        <div className="flex flex-col md:flex-row gap-4">
          <textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            placeholder="Suggest updates or add physician observations..."
            className="flex-grow input-clinical rounded-md p-4 text-sm leading-relaxed h-24 resize-none"
            disabled={isUpdating}
          />
          <button
            onClick={() => handleUpdate()}
            disabled={isUpdating || !comment.trim()}
            className="btn-primary px-8 rounded-md flex items-center justify-center gap-3 h-auto md:h-24 whitespace-nowrap"
          >
            <i className="fas fa-sync-alt"></i>
            Update Analysis
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReportDisplay;

