import React, { useRef, useState } from 'react';
import CameraCapture from './CameraCapture.tsx';

interface Props {
  onImagesChange: (images: string[]) => void;
  images: string[];
  disabled: boolean;
}

const ImageUploader: React.FC<Props> = ({ onImagesChange, images, disabled }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    if (files.length === 0) return;

    const newImagesBase64 = await Promise.all(
      files.map(file => {
        return new Promise<string>((resolve) => {
          const reader = new FileReader();
          reader.onloadend = () => resolve(reader.result as string);
          reader.readAsDataURL(file);
        });
      })
    );

    onImagesChange([...images, ...newImagesBase64]);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const triggerUpload = () => {
    if (!disabled) {
      fileInputRef.current?.click();
    }
  };

  const handleCapture = (base64: string) => {
    onImagesChange([...images, base64]);
    setIsCameraOpen(false);
  };

  const removeImage = (index: number) => {
    if (disabled) return;
    const updated = images.filter((_, i) => i !== index);
    onImagesChange(updated);
  };

  return (
    <div className="space-y-6">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        accept="image/*"
        multiple
        className="hidden"
        disabled={disabled}
      />

      {isCameraOpen && (
        <CameraCapture onCapture={handleCapture} onClose={() => setIsCameraOpen(false)} />
      )}

      <div className="grid grid-cols-2 gap-4">
        <button 
          onClick={triggerUpload}
          disabled={disabled}
          className="group bg-slate-50 hover:bg-white border border-slate-200 hover:border-blue-300 rounded-md p-6 transition-all disabled:opacity-50 text-center"
        >
          <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mb-3 mx-auto transition-colors group-hover:bg-blue-600 group-hover:text-white">
            <i className="fas fa-file-upload text-lg"></i>
          </div>
          <p className="text-[11px] font-bold text-slate-500 uppercase tracking-wider group-hover:text-blue-600">Import Files</p>
        </button>

        <button 
          onClick={() => !disabled && setIsCameraOpen(true)}
          disabled={disabled}
          className="group bg-slate-50 hover:bg-white border border-slate-200 hover:border-blue-300 rounded-md p-6 transition-all disabled:opacity-50 text-center"
        >
          <div className="w-10 h-10 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mb-3 mx-auto transition-colors group-hover:bg-blue-600 group-hover:text-white">
            <i className="fas fa-camera text-lg"></i>
          </div>
          <p className="text-[11px] font-bold text-slate-500 uppercase tracking-wider group-hover:text-blue-600">Live Camera</p>
        </button>
      </div>

      {images.length > 0 && (
        <div className="grid grid-cols-2 gap-3 max-h-[400px] overflow-y-auto p-3 bg-slate-50 border border-slate-200 rounded-md">
          {images.map((img, idx) => (
            <div key={idx} className="relative rounded bg-white overflow-hidden border border-slate-200 aspect-[4/3] group">
              <img 
                src={img} 
                alt={`Scan ${idx + 1}`} 
                className="w-full h-full object-cover transition-opacity duration-300 group-hover:opacity-80"
              />
              {!disabled && (
                <button 
                  onClick={() => removeImage(idx)}
                  className="absolute top-2 right-2 bg-white/90 text-red-500 w-6 h-6 rounded flex items-center justify-center text-[10px] shadow-sm border border-slate-100 opacity-0 group-hover:opacity-100 transition-opacity"
                >
                  <i className="fas fa-trash"></i>
                </button>
              )}
              <div className="absolute bottom-2 left-2 bg-slate-900/60 text-white text-[9px] px-2 py-1 rounded font-bold uppercase tracking-widest">
                IMG {idx + 1}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ImageUploader;

