import React, { useState, useEffect } from 'react';
import { analyzeUltrasound, refineReport } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';
import AccessGate from './components/AccessGate.tsx';

const App: React.FC = () => {
  const [isAuthorized, setIsAuthorized] = useState<boolean>(false);
  const [images, setImages] = useState<string[]>([]);
  const [clinicalContext, setClinicalContext] = useState('');
  const [patientName, setPatientName] = useState('');
  const [maternalAge, setMaternalAge] = useState<number>(30);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isRefining, setIsRefining] = useState(false);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  useEffect(() => {
    const authStatus = sessionStorage.getItem('ogxai_authorized');
    if (authStatus === 'true') {
      setIsAuthorized(true);
    }
  }, []);

  const handleLoginSuccess = () => {
    setIsAuthorized(true);
    sessionStorage.setItem('ogxai_authorized', 'true');
  };

  const handleImagesChange = (newImages: string[]) => {
    setImages(newImages);
    if (newImages.length === 0) setAnalysis(null);
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) await window.aistudio.openSelectKey();
    }

    setStatus({ isAnalyzing: true, progressMessage: 'INITIALIZING DIAGNOSTIC SEQUENCE...', error: null });
    try {
      const reportMarkdown = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ reportMarkdown, timestamp: new Date().toLocaleString() });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      setStatus({ isAnalyzing: false, progressMessage: '', error: err.message || 'Operational failure.' });
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (!analysis) return;
    setIsRefining(true);
    try {
      const updatedReport = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ ...analysis, reportMarkdown: updatedReport, timestamp: new Date().toLocaleString() + " (REVISED)" });
    } catch (err: any) {
      setStatus({ ...status, error: 'Revision failed.' });
    } finally {
      setIsRefining(false);
    }
  };

  if (!isAuthorized) return <AccessGate onGrantAccess={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-[#F9F9F9]">
      <Header />

      <main className="flex-grow container mx-auto px-6 py-12 max-w-[1400px]">
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-12">

          <div className="xl:col-span-4 order-2 xl:order-1">
            <section className="card-bold p-10 sticky top-36">
              <h2 className="text-2xl font-black mb-10 flex items-center gap-4">
                <span className="w-8 h-8 bg-black text-[#D4AF37] flex items-center justify-center text-xs">01</span>
                INPUT DATA
              </h2>

              <div className="space-y-10">
                <div className="grid grid-cols-1 gap-6">
                  <div>
                    <label className="text-[10px] font-black uppercase tracking-widest mb-3 block">Patient Identification</label>
                    <input 
                      type="text"
                      value={patientName}
                      onChange={(e) => setPatientName(e.target.value)}
                      placeholder="ENTER FULL NAME"
                      className="w-full input-bold p-5 text-sm uppercase tracking-widest"
                      disabled={status.isAnalyzing}
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-black uppercase tracking-widest mb-3 block">Maternal Age (YEARS)</label>
                    <input 
                      type="number"
                      value={maternalAge}
                      onChange={(e) => setMaternalAge(parseInt(e.target.value) || 30)}
                      className="w-full input-bold p-5 text-sm"
                      disabled={status.isAnalyzing}
                    />
                  </div>
                </div>

                <div>
                  <label className="text-[10px] font-black uppercase tracking-widest mb-3 block">Imaging Assets</label>
                  <ImageUploader onImagesChange={handleImagesChange} images={images} disabled={status.isAnalyzing} />
                </div>

                <div>
                  <label className="text-[10px] font-black uppercase tracking-widest mb-3 block">Clinical Context</label>
                  <textarea 
                    value={clinicalContext}
                    onChange={(e) => setClinicalContext(e.target.value)}
                    placeholder="ENTER MEDICAL HISTORY OR SCAN INDICATION..."
                    className="w-full input-bold p-6 text-sm leading-relaxed h-40 resize-none uppercase tracking-widest"
                    disabled={status.isAnalyzing}
                  />
                </div>
              </div>

              {images.length > 0 && !analysis && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-12 btn-gold py-8 text-lg shadow-[8px_8px_0px_#000000] flex items-center justify-center gap-4 active:translate-x-1 active:translate-y-1 active:shadow-none"
                >
                  <i className={`fas ${status.isAnalyzing ? 'fa-spinner fa-spin' : 'fa-play'}`}></i>
                  {status.isAnalyzing ? 'PROCESSING' : 'RUN DIAGNOSTICS'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={() => { setImages([]); setAnalysis(null); setPatientName(''); setClinicalContext(''); }}
                  className="w-full mt-8 bg-black text-white font-black py-4 uppercase text-xs tracking-[0.3em] hover:bg-zinc-800"
                >
                  New Consultation
                </button>
              )}
            </section>
          </div>

          <div className="xl:col-span-8 order-1 xl:order-2">
            {status.error && (
              <div className="bg-white border-4 border-red-500 p-10 mb-12 shadow-[12px_12px_0px_#ef4444]">
                  <h4 className="text-red-600 font-black text-xl mb-4">CRITICAL ERROR</h4>
                  <p className="font-bold text-lg mb-8">{status.error}</p>
                  <button onClick={startAnalysis} className="bg-black text-white px-8 py-4 font-black text-xs uppercase tracking-widest">Restart System</button>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="card-bold p-24 text-center flex flex-col items-center justify-center min-h-[700px]">
                <div className="w-32 h-32 bg-zinc-100 flex items-center justify-center mb-10 border-4 border-black">
                  <i className="fas fa-microscope text-5xl"></i>
                </div>
                <h3 className="text-4xl font-black mb-6">STANDBY MODE</h3>
                <p className="text-zinc-500 font-bold uppercase tracking-widest max-w-sm leading-loose">
                  Upload patient scan data to initiate the diagnostic protocol.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay analysis={analysis} onUpdate={onUpdateReport} isUpdating={isRefining} />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="bg-white py-20 border-t-8 border-black text-center">
        <div className="container mx-auto px-6">
          <div className="text-4xl font-black mb-6">OGXAI</div>
          <div className="w-20 h-2 bg-[#D4AF37] mx-auto mb-10"></div>
          <p className="max-w-4xl mx-auto font-black uppercase text-[10px] tracking-[0.5em] text-zinc-400 leading-loose">
            Professional Verification Required • Diagnostic Support Protocol v4.2.0 • Confidential
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { AnalysisResult } from '../types.ts';

interface Props {
  analysis: AnalysisResult;
  onUpdate?: (comment: string) => void;
  isUpdating?: boolean;
}

const ReportDisplay: React.FC<Props> = ({ analysis, onUpdate, isUpdating }) => {
  const [comment, setComment] = useState('');

  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return (
          <h4 key={i} className="text-xl font-black text-[#D4AF37] bg-black px-6 py-4 mt-12 mb-6 inline-block uppercase tracking-widest">
            {content}
          </h4>
        );
      }

      if (line.match(/^\d\.\s/)) {
        return (
          <h3 key={i} className="text-4xl md:text-5xl font-black text-black mt-20 mb-10 border-b-8 border-black pb-4">
            {line}
          </h3>
        );
      }

      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <div key={i} className="flex flex-col md:flex-row gap-4 py-6 border-b-2 border-zinc-100 hover:bg-zinc-50 px-4 transition-colors">
                    <span className="text-xs font-black text-zinc-400 uppercase tracking-widest md:w-1/3">{parts[0]}</span> 
                    <span className="text-xl font-bold text-black md:w-2/3">{parts.slice(1).join(':')}</span>
                </div>
            );
        }
        return (
          <p key={i} className="text-xl font-bold text-zinc-700 py-3 flex gap-4 items-center">
            <span className="w-3 h-3 bg-[#D4AF37]"></span>
            {content}
          </p>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-6" />;
      return <p key={i} className="text-xl font-bold text-zinc-500 leading-relaxed mb-6 italic">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col gap-12">
      <div className="card-bold overflow-hidden">
        <div className="bg-black text-white px-10 py-6 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <div className="w-8 h-8 bg-[#D4AF37] text-black flex items-center justify-center font-black">!</div>
            <h2 className="font-black text-sm uppercase tracking-[0.3em]">Official Diagnostic Dossier</h2>
          </div>
          <div className="flex gap-6">
            <button onClick={() => window.print()} className="hover:text-[#D4AF37]"><i className="fas fa-print"></i></button>
            <button onClick={() => navigator.clipboard.writeText(analysis.reportMarkdown)} className="hover:text-[#D4AF37]"><i className="fas fa-copy"></i></button>
          </div>
        </div>

        <div className="p-12 md:p-20 relative bg-white">
          {isUpdating && (
            <div className="absolute inset-0 bg-white/90 z-50 flex items-center justify-center">
              <div className="text-center">
                <div className="w-16 h-16 border-8 border-black border-t-[#D4AF37] rounded-full animate-spin mx-auto mb-6"></div>
                <p className="font-black uppercase tracking-widest text-black">Updating Dossier</p>
              </div>
            </div>
          )}

          <div className="flex flex-col md:flex-row justify-between items-start border-b-8 border-black pb-12 mb-12 gap-8">
            <div>
              <h1 className="text-6xl md:text-8xl font-black leading-none mb-4">REPORT</h1>
              <div className="bg-[#D4AF37] text-black px-4 py-1 inline-block font-black text-xs uppercase tracking-widest">Validated Analysis</div>
            </div>
            <div className="text-right font-black uppercase text-xs tracking-widest text-zinc-400">
              <div className="mb-2">TIMESTAMP: {analysis.timestamp}</div>
              <div>AUTH: OGXAI-TERMINAL-402</div>
            </div>
          </div>

          <div className="report-content">
            {formatMarkdown(analysis.reportMarkdown)}
          </div>
        </div>
      </div>

      <div className="card-bold p-10 bg-zinc-50">
        <h3 className="text-xl font-black mb-8 flex items-center gap-4 uppercase">
          <i className="fas fa-pen-nib text-[#D4AF37]"></i>
          Report Revision
        </h3>
        <div className="flex flex-col xl:flex-row gap-6">
          <textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            placeholder="ENTER REVISION COMMANDS OR OBSERVATIONS..."
            className="flex-grow input-bold p-6 text-sm leading-relaxed h-32 resize-none uppercase tracking-widest"
            disabled={isUpdating}
          />
          <button
            onClick={() => { if(comment.trim() && onUpdate) onUpdate(comment); setComment(''); }}
            disabled={isUpdating || !comment.trim()}
            className="btn-gold px-12 py-6 min-w-[300px] flex items-center justify-center gap-4 shadow-[6px_6px_0px_#000000] active:translate-x-1 active:translate-y-1 active:shadow-none"
          >
            <i className="fas fa-sync"></i>
            Process Revision
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReportDisplay;

import React, { useRef, useState } from 'react';
import CameraCapture from './CameraCapture.tsx';

interface Props {
  onImagesChange: (images: string[]) => void;
  images: string[];
  disabled: boolean;
}

const ImageUploader: React.FC<Props> = ({ onImagesChange, images, disabled }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    const newImages = await Promise.all(files.map(file => new Promise<string>((res) => {
      const reader = new FileReader();
      reader.onloadend = () => res(reader.result as string);
      reader.readAsDataURL(file);
    })));
    onImagesChange([...images, ...newImages]);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-6">
      <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" multiple className="hidden" />
      {isCameraOpen && <CameraCapture onCapture={(b64) => { onImagesChange([...images, b64]); setIsCameraOpen(false); }} onClose={() => setIsCameraOpen(false)} />}

      <div className="grid grid-cols-2 gap-4">
        <button 
          onClick={() => !disabled && fileInputRef.current?.click()}
          disabled={disabled}
          className="bg-white border-4 border-black p-6 font-black text-[10px] uppercase tracking-widest hover:bg-[#D4AF37] transition-colors flex flex-col items-center gap-3"
        >
          <i className="fas fa-file-upload text-xl"></i>
          Import Assets
        </button>

        <button 
          onClick={() => !disabled && setIsCameraOpen(true)}
          disabled={disabled}
          className="bg-white border-4 border-black p-6 font-black text-[10px] uppercase tracking-widest hover:bg-[#D4AF37] transition-colors flex flex-col items-center gap-3"
        >
          <i className="fas fa-camera text-xl"></i>
          Capture Live
        </button>
      </div>

      {images.length > 0 && (
        <div className="grid grid-cols-2 gap-4 p-4 bg-zinc-100 border-4 border-black max-h-[400px] overflow-y-auto">
          {images.map((img, idx) => (
            <div key={idx} className="relative aspect-video border-4 border-black bg-black group overflow-hidden">
              <img src={img} className="w-full h-full object-cover group-hover:opacity-70 transition-opacity" />
              <button 
                onClick={() => onImagesChange(images.filter((_, i) => i !== idx))}
                className="absolute top-2 right-2 bg-red-600 text-white w-8 h-8 flex items-center justify-center font-black border-2 border-black opacity-0 group-hover:opacity-100 transition-opacity"
              >
                X
              </button>
              <div className="absolute bottom-2 left-2 bg-black text-[#D4AF37] font-black text-[9px] px-2 py-1 uppercase tracking-widest border border-[#D4AF37]/50">
                LENS {idx + 1}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

