    error: null,
  });

  useEffect(() => {
    const authStatus = sessionStorage.getItem('ogxai_authorized');
    if (authStatus === 'true') {
      setIsAuthorized(true);
    }
  }, []);

  const handleLoginSuccess = () => {
    setIsAuthorized(true);
    sessionStorage.setItem('ogxai_authorized', 'true');
  };

  const handleImagesChange = (newImages: string[]) => {
    setImages(newImages);
    if (newImages.length === 0) setAnalysis(null);
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) await window.aistudio.openSelectKey();
    }

    setStatus({ isAnalyzing: true, progressMessage: 'Synthesizing clinical data...', error: null });
    try {
      const reportMarkdown = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ reportMarkdown, timestamp: new Date().toLocaleString() });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      setStatus({ isAnalyzing: false, progressMessage: '', error: err.message || 'Operational interruption.' });
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (!analysis) return;
    setIsRefining(true);
    try {
      const updatedReport = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ ...analysis, reportMarkdown: updatedReport, timestamp: new Date().toLocaleString() + " (Revised)" });
    } catch (err: any) {
      setStatus({ ...status, error: 'Revision encountered an error.' });
    } finally {
      setIsRefining(false);
    }
  };

  if (!isAuthorized) return <AccessGate onGrantAccess={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-[#FCFCFC]">
      <Header />

      <main className="flex-grow container mx-auto px-10 py-20 max-w-[1400px]">
        <div className="grid grid-cols-1 xl:grid-cols-12 gap-20">

          <div className="xl:col-span-4 order-2 xl:order-1">
            <section className="card-elegant p-12 sticky top-40 rounded-sm">
              <h2 className="text-sm font-medium tracking-[0.3em] mb-12 flex items-center gap-5 text-gray-400">
                <span className="w-6 h-[1px] bg-gold"></span>
                CLINICAL INTAKE
              </h2>

              <div className="space-y-12">
                <div className="grid grid-cols-1 gap-8">
                  <div>
                    <label className="text-[10px] font-medium text-gray-300 uppercase tracking-[0.2em] mb-4 block">Patient Information</label>
                    <input 
                      type="text"
                      value={patientName}
                      onChange={(e) => setPatientName(e.target.value)}
                      placeholder="Enter Full Name"
                      className="w-full input-elegant p-4 text-xs tracking-widest uppercase focus:border-gold"
                      disabled={status.isAnalyzing}
                    />
                  </div>
                  <div>
                    <label className="text-[10px] font-medium text-gray-300 uppercase tracking-[0.2em] mb-4 block">Maternal Age</label>
                    <input 
                      type="number"
                      value={maternalAge}
                      onChange={(e) => setMaternalAge(parseInt(e.target.value) || 30)}
                      className="w-full input-elegant p-4 text-xs focus:border-gold"
                      disabled={status.isAnalyzing}
                    />
                  </div>
                </div>

                <div>
                  <label className="text-[10px] font-medium text-gray-300 uppercase tracking-[0.2em] mb-4 block">Imaging Assets</label>
                  <ImageUploader onImagesChange={handleImagesChange} images={images} disabled={status.isAnalyzing} />
                </div>

                <div>
                  <label className="text-[10px] font-medium text-gray-300 uppercase tracking-[0.2em] mb-4 block">Clinical Narrative</label>
                  <textarea 
                    value={clinicalContext}
                    onChange={(e) => setClinicalContext(e.target.value)}
                    placeholder="Provide clinical indication..."
                    className="w-full input-elegant p-5 text-xs leading-relaxed h-32 resize-none uppercase tracking-widest focus:border-gold"
                    disabled={status.isAnalyzing}
                  />
                </div>
              </div>

              {images.length > 0 && !analysis && (
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="w-full mt-16 btn-gold py-6 text-[10px] flex items-center justify-center gap-6"
                >
                  {status.isAnalyzing ? (
                    <i className="fas fa-spinner fa-spin"></i>
                  ) : (
                    <i className="fas fa-search"></i>
                  )}
                  {status.isAnalyzing ? 'Processing' : 'Analyze Case'}
                </button>
              )}

              {analysis && (
                <button
                  onClick={() => { setImages([]); setAnalysis(null); setPatientName(''); setClinicalContext(''); }}
                  className="w-full mt-10 text-[9px] font-medium uppercase tracking-[0.3em] text-gray-300 hover:text-gold transition-colors"
                >
                  Begin New Consultation
                </button>
              )}
            </section>
          </div>

          <div className="xl:col-span-8 order-1 xl:order-2">
            {status.error && (
              <div className="card-elegant p-12 mb-12 border-red-50 relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-1 h-full bg-red-400"></div>
                  <h4 className="text-red-400 font-elegant italic text-xl mb-4">Operational Interruption</h4>
                  <p className="text-gray-500 text-xs tracking-wide leading-relaxed mb-8">{status.error}</p>
                  <button onClick={startAnalysis} className="text-[10px] font-medium uppercase tracking-[0.2em] text-black hover:text-gold">Retry Initialization</button>
              </div>
            )}

            {!analysis && !status.isAnalyzing && !status.error && (
              <div className="card-elegant p-20 text-center flex flex-col items-center justify-center min-h-[800px] border-dashed">
                <div className="w-20 h-20 border border-gray-100 flex items-center justify-center mb-12 rotate-45 group hover:border-gold transition-all duration-700">
                  <i className="fas fa-feather text-gray-200 -rotate-45 group-hover:text-gold transition-colors"></i>
                </div>
                <h3 className="text-2xl font-elegant italic text-gray-300 mb-6">Awaiting Observation</h3>
                <p className="text-gray-300 text-[10px] font-medium uppercase tracking-[0.4em] max-w-xs leading-loose">
                  Please upload optical diagnostic data to proceed.
                </p>
              </div>
            )}

            {analysis && (
              <ReportDisplay analysis={analysis} onUpdate={onUpdateReport} isUpdating={isRefining} />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="bg-white py-32 border-t border-gray-50 text-center">
        <div className="container mx-auto px-10">
          <div className="text-2xl font-elegant tracking-[0.2em] mb-8">OGXAI</div>
          <div className="w-12 h-[1px] bg-gold mx-auto mb-10"></div>
          <p className="max-w-4xl mx-auto font-medium uppercase text-[9px] tracking-[0.4em] text-gray-300 leading-loose">
            Clinician Oversight Required • Proprietary Diagnostic Intelligence v4.2.0 • Restricted Use
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { AnalysisResult } from '../types.ts';

interface Props {
  analysis: AnalysisResult;
  onUpdate?: (comment: string) => void;
  isUpdating?: boolean;
}

const ReportDisplay: React.FC<Props> = ({ analysis, onUpdate, isUpdating }) => {
  const [comment, setComment] = useState('');

  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return (
          <h4 key={i} className="text-xs font-medium text-gold border-b border-gold/10 inline-block pb-1 mt-10 mb-6 uppercase tracking-[0.2em]">
            {content}
          </h4>
        );
      }

      if (line.match(/^\d\.\s/)) {
        return (
          <h3 key={i} className="text-3xl font-elegant text-black mt-24 mb-12 pb-6 border-b border-gray-50">
            {line}
          </h3>
        );
      }

      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <div key={i} className="flex flex-col md:flex-row gap-6 py-6 border-b border-gray-50/50 hover:bg-gray-50/30 px-4 transition-colors">
                    <span className="text-[10px] font-medium text-gray-300 uppercase tracking-[0.2em] md:w-1/4 pt-1">{parts[0]}</span> 
                    <span className="text-lg font-light text-gray-700 md:w-3/4 leading-relaxed">{parts.slice(1).join(':')}</span>
                </div>
            );
        }
        return (
          <p key={i} className="text-lg font-light text-gray-600 py-3 flex gap-6 items-start">
            <span className="w-1 h-1 bg-gold mt-3 flex-shrink-0"></span>
            {content}
          </p>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-4" />;
      return <p key={i} className="text-lg font-light italic text-gray-400 leading-relaxed mb-8">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col gap-16 animate-in fade-in duration-1000">
      <div className="card-elegant overflow-hidden">
        <div className="bg-white border-b border-gray-50 px-12 py-8 flex justify-between items-center">
          <div className="flex items-center gap-6">
            <div className="w-4 h-4 bg-gold/10 border border-gold/20 flex items-center justify-center">
              <div className="w-1 h-1 bg-gold"></div>
            </div>
            <h2 className="font-medium text-[10px] text-gray-400 uppercase tracking-[0.4em]">Clinical Consultation File</h2>
          </div>
          <div className="flex gap-10">
            <button onClick={() => window.print()} className="text-gray-300 hover:text-gold transition-colors"><i className="fas fa-print text-sm"></i></button>
            <button onClick={() => navigator.clipboard.writeText(analysis.reportMarkdown)} className="text-gray-300 hover:text-gold transition-colors"><i className="fas fa-copy text-sm"></i></button>
          </div>
        </div>

        <div className="p-16 md:p-24 relative bg-white">
          {isUpdating && (
            <div className="absolute inset-0 bg-white/90 z-50 flex items-center justify-center transition-all">
              <div className="text-center">
                <div className="w-12 h-12 border-2 border-gray-50 border-t-gold rounded-full animate-spin mx-auto mb-8"></div>
                <p className="text-[10px] font-medium uppercase tracking-[0.3em] text-gold">Refining Narrative</p>
              </div>
            </div>
          )}

          <div className="flex flex-col md:flex-row justify-between items-start border-b border-gray-50 pb-16 mb-16 gap-10">
            <div>
              <h1 className="text-5xl font-elegant text-black mb-6">Observation Report</h1>
              <div className="text-gold text-[10px] font-medium uppercase tracking-[0.4em]">Integrated Intelligence Synthesis</div>
            </div>
            <div className="text-right font-medium uppercase text-[9px] tracking-[0.2em] text-gray-300">
              <div className="mb-2">Timestamp: {analysis.timestamp}</div>
              <div className="text-gray-200">ID: OGX-CLN-PRT-402</div>
            </div>
          </div>

          <div className="report-content">
            {formatMarkdown(analysis.reportMarkdown)}
          </div>
        </div>
      </div>

      <div className="card-elegant p-12 bg-white">
        <h3 className="text-sm font-medium mb-10 flex items-center gap-4 uppercase tracking-[0.2em] text-gray-400">
          <i className="fas fa-pen-fancy text-gold text-xs"></i>
          Clinical Amendment
        </h3>
        <div className="flex flex-col xl:flex-row gap-10">
          <textarea
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            placeholder="Document additional clinical observations..."
            className="flex-grow input-elegant p-6 text-xs leading-relaxed h-32 resize-none tracking-widest focus:border-gold"
            disabled={isUpdating}
          />
          <button
            onClick={() => { if(comment.trim() && onUpdate) onUpdate(comment); setComment(''); }}
            disabled={isUpdating || !comment.trim()}
            className="btn-gold px-12 py-6 min-w-[300px] flex items-center justify-center gap-6"
          >
            <i className="fas fa-sync-alt text-xs"></i>
            <span className="text-[10px]">Update Report</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default ReportDisplay;

import React, { useRef, useState } from 'react';
import CameraCapture from './CameraCapture.tsx';

interface Props {
  onImagesChange: (images: string[]) => void;
  images: string[];
  disabled: boolean;
}

const ImageUploader: React.FC<Props> = ({ onImagesChange, images, disabled }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    const newImages = await Promise.all(files.map(file => new Promise<string>((res) => {
      const reader = new FileReader();
      reader.onloadend = () => res(reader.result as string);
      reader.readAsDataURL(file);
    })));
    onImagesChange([...images, ...newImages]);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-8">
      <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" multiple className="hidden" />
      {isCameraOpen && <CameraCapture onCapture={(b64) => { onImagesChange([...images, b64]); setIsCameraOpen(false); }} onClose={() => setIsCameraOpen(false)} />}

      <div className="grid grid-cols-2 gap-6">
        <button 
          onClick={() => !disabled && fileInputRef.current?.click()}
          disabled={disabled}
          className="bg-white border border-gray-100 p-8 text-[10px] font-medium uppercase tracking-[0.2em] text-gray-400 hover:text-gold hover:border-gold transition-all flex flex-col items-center gap-5 group"
        >
          <i className="fas fa-file-alt text-lg group-hover:scale-110 transition-transform"></i>
          Import Assets
        </button>

        <button 
          onClick={() => !disabled && setIsCameraOpen(true)}
          disabled={disabled}
          className="bg-white border border-gray-100 p-8 text-[10px] font-medium uppercase tracking-[0.2em] text-gray-400 hover:text-gold hover:border-gold transition-all flex flex-col items-center gap-5 group"
        >
          <i className="fas fa-camera text-lg group-hover:scale-110 transition-transform"></i>
          Live Feed
        </button>
      </div>

      {images.length > 0 && (
        <div className="grid grid-cols-2 gap-6 p-6 bg-gray-50/50 border border-gray-50 max-h-[400px] overflow-y-auto">
          {images.map((img, idx) => (
            <div key={idx} className="relative aspect-video border border-gray-100 bg-white group overflow-hidden">
              <img src={img} className="w-full h-full object-cover group-hover:opacity-50 transition-opacity duration-700" />
              <button 
                onClick={() => onImagesChange(images.filter((_, i) => i !== idx))}
                className="absolute top-3 right-3 text-gray-400 hover:text-red-400 w-8 h-8 flex items-center justify-center transition-all opacity-0 group-hover:opacity-100"
              >
                <i className="fas fa-times text-xs"></i>
              </button>
              <div className="absolute bottom-3 left-3 bg-white/90 backdrop-blur-sm text-gold font-medium text-[8px] px-3 py-1 uppercase tracking-widest border border-gold/10">
                FRAME {idx + 1}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

export default ImageUploader;

