import React, { useRef, useState } from 'react';
import CameraCapture from './CameraCapture.tsx';

interface Props {
  onImagesChange: (images: string[]) => void;
  images: string[];
  disabled: boolean;
}

const ImageUploader: React.FC<Props> = ({ onImagesChange, images, disabled }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isCameraOpen, setIsCameraOpen] = useState(false);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = Array.from(e.target.files || []) as File[];
    const newImages = await Promise.all(files.map(file => new Promise<string>((res) => {
      const reader = new FileReader();
      reader.onloadend = () => res(reader.result as string);
      reader.readAsDataURL(file);
    })));
    onImagesChange([...images, ...newImages]);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  return (
    <div className="space-y-8">
      <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" multiple className="hidden" />
      {isCameraOpen && <CameraCapture onCapture={(b64) => { onImagesChange([...images, b64]); setIsCameraOpen(false); }} onClose={() => setIsCameraOpen(false)} />}

      <div className="grid grid-cols-2 gap-4">
        <button 
          onClick={() => !disabled && fileInputRef.current?.click()}
          disabled={disabled}
          className="bg-[#f5f5f7] rounded-xl p-8 text-center hover:bg-[#ebebed] transition-colors group"
        >
          <i className="fas fa-file-upload text-2xl text-[#d2d2d7] mb-3 block group-hover:text-black transition-colors"></i>
          <span className="text-xs font-semibold text-[#86868b] uppercase tracking-wider group-hover:text-black">Upload Files</span>
        </button>

        <button 
          onClick={() => !disabled && setIsCameraOpen(true)}
          disabled={disabled}
          className="bg-[#f5f5f7] rounded-xl p-8 text-center hover:bg-[#ebebed] transition-colors group"
        >
          <i className="fas fa-camera text-2xl text-[#d2d2d7] mb-3 block group-hover:text-black transition-colors"></i>
          <span className="text-xs font-semibold text-[#86868b] uppercase tracking-wider group-hover:text-black">Live Capture</span>
        </button>
      </div>

      {images.length > 0 && (
        <div className="grid grid-cols-2 gap-4 p-4 bg-[#f5f5f7] rounded-xl max-h-[400px] overflow-y-auto">
          {images.map((img, idx) => (
            <div key={idx} className="relative aspect-video rounded-lg bg-black overflow-hidden group">
              <img src={img} className="w-full h-full object-cover group-hover:opacity-70 transition-opacity" />
              <button 
                onClick={() => onImagesChange(images.filter((_, i) => i !== idx))}
                className="absolute top-2 right-2 bg-white/90 text-black w-6 h-6 rounded-full flex items-center justify-center shadow-sm opacity-0 group-hover:opacity-100 transition-opacity"
              >
                <i className="fas fa-times text-[10px]"></i>
              </button>
              <div className="absolute bottom-2 left-2 bg-black/40 backdrop-blur-md text-white font-bold text-[8px] px-2 py-0.5 rounded tracking-widest">
                ASSET {idx + 1}
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

