function extractGroundingSources(response: GenerateContentResponse): GroundingSource[] {
  const sources: GroundingSource[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;

  if (chunks) {
    chunks.forEach((chunk: any) => {
      if (chunk.web && chunk.web.uri && chunk.web.title) {
        sources.push({
          title: chunk.web.title,
          uri: chunk.web.uri
        });
      }
    });
  }

  // Return unique sources by URI
  return Array.from(new Map(sources.map(item => [item.uri, item])).values());
}

/**
 * Performs a clinical analysis on ultrasound scans with patient demographics.
 */
export async function analyzeUltrasound(
  images64: string[], 
  clinicalContext: string,
  patientName: string,
  maternalAge: number
): Promise<{ reportMarkdown: string; groundingSources: GroundingSource[] }> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const prompt = `Perform a high-speed clinical analysis on these ${images64.length} ultrasound scan(s). 

  PATIENT DATA:
  - Name: ${patientName || 'Not Specified'}
  - Maternal Age: ${maternalAge}

  CLINICAL CONTEXT:
  "${clinicalContext || 'No specific clinical indication provided.'}"

  Utilize Google Search to verify findings against the latest (2024-2025) ISUOG and ACOG guidelines for fetal biometry and morphological risk.`;

  const imageParts: Part[] = images64.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64,
    },
  }));

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: model,
    contents: { parts: [...imageParts, { text: prompt }] },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.0,
      tools: [{ googleSearch: {} }]
    },
  });

  if (!response.text) throw new Error("Analysis failed to generate text output.");

  return {
    reportMarkdown: response.text,
    groundingSources: extractGroundingSources(response)
  };
}

/**
 * Refines the ultrasound report based on physician input.
 */
export async function refineReport(
  images64: string[], 
  previousReport: string, 
  refinement: string,
  clinicalContext: string,
  patientName: string,
  maternalAge: number
): Promise<{ reportMarkdown: string; groundingSources: GroundingSource[] }> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-flash-preview';

  const imageParts: Part[] = images64.map(base64 => ({
    inlineData: {
      mimeType: 'image/jpeg',
      data: base64,
    },
  }));

  const contents: Content[] = [
    {
      role: 'user',
      parts: [
        ...imageParts,
        { text: `Initial context: Patient ${patientName}, Age ${maternalAge}. Indication: ${clinicalContext}` }
      ]
    },
    {
      role: 'model',
      parts: [{ text: previousReport }]
    },
    {
      role: 'user',
      parts: [{ text: `Attending Physician Input: "${refinement}". Update the report ensuring this new information is integrated. Use search to verify any new clinical assertions.` }]
    }
  ];

  const response = await ai.models.generateContent({
    model: model,
    contents: contents,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.0,
      tools: [{ googleSearch: {} }]
    },
  });

  if (!response.text) throw new Error("Refinement failed.");

  return {
    reportMarkdown: response.text,
    groundingSources: extractGroundingSources(response)
  };
}

import React, { useState, useEffect } from 'react';
import { analyzeUltrasound, refineReport } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';
import AccessGate from './components/AccessGate.tsx';

const App: React.FC = () => {
  const [isAuthorized, setIsAuthorized] = useState<boolean>(false);
  const [images, setImages] = useState<string[]>([]);
  const [clinicalContext, setClinicalContext] = useState('');
  const [patientName, setPatientName] = useState('');
  const [maternalAge, setMaternalAge] = useState<number>(30);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isRefining, setIsRefining] = useState(false);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  useEffect(() => {
    const authStatus = sessionStorage.getItem('ogxai_authorized');
    if (authStatus === 'true') {
      setIsAuthorized(true);
    }
  }, []);

  const handleLoginSuccess = () => {
    setIsAuthorized(true);
    sessionStorage.setItem('ogxai_authorized', 'true');
  };

  const handleImagesChange = (newImages: string[]) => {
    setImages(newImages);
    if (newImages.length === 0) setAnalysis(null);
    setStatus({ ...status, error: null });
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;
    if (window.aistudio) {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) await window.aistudio.openSelectKey();
    }

    setStatus({ isAnalyzing: true, progressMessage: 'Accessing latest clinical guidelines...', error: null });
    try {
      const result = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ 
        reportMarkdown: result.reportMarkdown, 
        timestamp: new Date().toLocaleString(),
        groundingSources: result.groundingSources
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      setStatus({ isAnalyzing: false, progressMessage: '', error: err.message || 'Analysis failed.' });
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (!analysis) return;
    setIsRefining(true);
    try {
      const result = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ 
        ...analysis, 
        reportMarkdown: result.reportMarkdown, 
        timestamp: new Date().toLocaleString() + " (Revised)",
        groundingSources: result.groundingSources
      });
    } catch (err: any) {
      setStatus({ ...status, error: 'Revision failed.' });
    } finally {
      setIsRefining(false);
    }
  };

  if (!isAuthorized) return <AccessGate onGrantAccess={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col">
      <Header />

      <main className="flex-grow container mx-auto px-6 py-12 md:py-24 max-w-[1100px]">
        <div className="text-center mb-16 md:mb-24 animate-in fade-in slide-in-from-bottom-4 duration-1000">
           <h2 className="text-4xl md:text-6xl font-bold tracking-tight text-[#1d1d1f] mb-6">Clinical Intelligence. Redefined.</h2>
           <p className="text-xl md:text-2xl text-[#86868b] font-medium max-w-2xl mx-auto tracking-tight">
             Sophisticated reporting for Maternal-Fetal medicine, powered by OGXAI with real-time guideline verification.
           </p>
        </div>

        <div className="grid grid-cols-1 gap-12">

          <div className="order-2 lg:order-1">
            <section className="apple-card p-10 md:p-16">
              <div className="flex items-center gap-4 mb-12">
                <span className="text-[14px] font-bold text-black bg-black/5 px-3 py-1 rounded-full uppercase tracking-tight">Diagnostics</span>
                <h3 className="text-2xl font-bold">Input Session</h3>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-8">
                  <div>
                    <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-3 block">Patient Information</label>
                    <input 
                      type="text"
                      value={patientName}
                      onChange={(e) => setPatientName(e.target.value)}
                      placeholder="Name"
                      className="w-full apple-input text-base"
                      disabled={status.isAnalyzing}
                    />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-3 block">Age</label>
                    <input 
                      type="number"
                      value={maternalAge}
                      onChange={(e) => setMaternalAge(parseInt(e.target.value) || 30)}
                      className="w-full apple-input text-base"
                      disabled={status.isAnalyzing}
                    />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-3 block">Indication</label>
                    <textarea 
                      value={clinicalContext}
                      onChange={(e) => setClinicalContext(e.target.value)}
                      placeholder="Clinical context or scan indication..."
                      className="w-full apple-input text-base leading-relaxed h-32 resize-none"
                      disabled={status.isAnalyzing}
                    />
                  </div>
                </div>

                <div>
                  <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-3 block">Scan Assets</label>
                  <ImageUploader onImagesChange={handleImagesChange} images={images} disabled={status.isAnalyzing} />
                </div>
              </div>

              {images.length > 0 && !analysis && (
                <div className="mt-16 flex justify-center">
                  <button
                    onClick={startAnalysis}
                    disabled={status.isAnalyzing}
                    className="apple-button-gold text-lg transition-transform hover:scale-105 active:scale-95 flex items-center gap-4 disabled:opacity-50"
                  >
                    {status.isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-search"></i>}
                    {status.isAnalyzing ? 'Consulting Online Guidelines...' : 'Start Diagnostic Run'}
                  </button>
                </div>
              )}

              {analysis && (
                <div className="mt-12 pt-12 border-t border-black/5 text-center">
                  <button
                    onClick={() => { setImages([]); setAnalysis(null); setPatientName(''); setClinicalContext(''); }}
                    className="text-sm font-semibold text-[#0066cc] hover:underline"
                  >
                    Start New Session
                  </button>
                </div>
              )}
            </section>
          </div>

          <div className="order-1 lg:order-2">
            {status.error && (
              <div className="apple-card p-10 bg-red-50/50 border border-red-100 mb-12">
                  <h4 className="text-red-600 font-bold text-lg mb-2">Operational Interruption</h4>
                  <p className="text-gray-600 text-sm">{status.error}</p>
              </div>
            )}

            {analysis && (
              <ReportDisplay analysis={analysis} onUpdate={onUpdateReport} isUpdating={isRefining} />
            )}

            {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
          </div>
        </div>
      </main>

      <footer className="bg-[#f5f5f7] py-24 border-t border-black/5 text-center">
        <div className="container mx-auto px-6 max-w-[1100px]">
          <div className="text-2xl font-bold tracking-tight mb-8">OGXAI</div>
          <p className="max-w-2xl mx-auto text-[#86868b] text-[12px] leading-relaxed font-medium">
            Clinical validation required. All interpretations must be reviewed by an authorized Fetal Medicine Consultant. Professional use only. 
            <br />
            © 2026 OGXAI Medical Systems.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

