const ReportDisplay: React.FC<Props> = ({ analysis, onUpdate, isUpdating }) => {
  const formatMarkdown = (text: string) => {
    return text.split('\n').map((line, i) => {
      if (line.startsWith('**') && line.endsWith('**')) {
        const content = line.replace(/\*\*/g, '');
        return (
          <h4 key={i} className="text-[12px] font-bold text-[#86868b] mt-10 mb-4 uppercase tracking-[0.05em]">
            {content}
          </h4>
        );
      }

      if (line.match(/^\d\.\s/)) {
        return (
          <h3 key={i} className="text-3xl font-bold text-black mt-16 mb-8 border-b border-black/5 pb-4">
            {line.substring(3)}
          </h3>
        );
      }

      if (line.trim().startsWith('* ')) {
        const content = line.trim().substring(2);
        const parts = content.split(':');
        if (parts.length > 1) {
            return (
                <div key={i} className="flex flex-col md:flex-row gap-4 py-6 border-b border-black/5 last:border-0 hover:bg-black/[0.01] px-2 transition-colors">
                    <span className="text-sm font-semibold text-[#86868b] md:w-1/3">{parts[0]}</span> 
                    <span className="text-base font-medium text-black md:w-2/3 leading-relaxed">{parts.slice(1).join(':')}</span>
                </div>
            );
        }
        return (
          <p key={i} className="text-base text-black/80 py-2 flex gap-4 items-start">
            <span className="text-[#d2d2d7] mt-1">•</span>
            {content}
          </p>
        );
      }

      if (line.trim() === '') return <div key={i} className="h-4" />;
      return <p key={i} className="text-base text-black/60 leading-relaxed mb-6 font-medium italic">{line}</p>;
    });
  };

  return (
    <div className="flex flex-col gap-12 animate-in fade-in duration-1000">
      <div className="apple-card overflow-hidden">
        <div className="bg-[#f5f5f7]/50 border-b border-black/5 px-10 py-6 flex justify-between items-center">
          <div className="flex items-center gap-4">
            <i className="fas fa-file-alt text-[#d2d2d7]"></i>
            <h2 className="text-xs font-bold text-[#86868b] uppercase tracking-wider">Clinical Dossier</h2>
          </div>
          <div className="flex gap-6">
            <button onClick={() => window.print()} className="text-[#d2d2d7] hover:text-black transition-colors"><i className="fas fa-print"></i></button>
            <button onClick={() => navigator.clipboard.writeText(analysis.reportMarkdown)} className="text-[#d2d2d7] hover:text-black transition-colors"><i className="fas fa-copy"></i></button>
          </div>
        </div>

        <div className="p-10 md:p-16 relative bg-white">
          {isUpdating && (
            <div className="absolute inset-0 bg-white/80 z-50 flex items-center justify-center transition-all">
              <div className="w-8 h-8 border-2 border-black/5 border-t-black rounded-full animate-spin"></div>
            </div>
          )}

          <div className="flex flex-col md:flex-row justify-between items-start border-b border-black/5 pb-12 mb-12">
            <div>
              <h1 className="text-4xl font-bold tracking-tight mb-4">Diagnostic Review</h1>
              <p className="text-sm font-semibold text-[#d4af37] uppercase tracking-widest">Verified Session with Search Grounding</p>
            </div>
            <div className="text-right text-[11px] font-semibold text-[#86868b] tracking-tight">
              <div>VERIFIED: {analysis.timestamp}</div>
              <div className="mt-2 text-[#d2d2d7]">NODE: OGX-CLN-402</div>
            </div>
          </div>

          <div className="report-content">
            {formatMarkdown(analysis.reportMarkdown)}
          </div>

          {analysis.groundingSources && analysis.groundingSources.length > 0 && (
            <div className="mt-20 pt-10 border-t border-black/5">
              <h4 className="text-[12px] font-bold text-[#86868b] mb-6 uppercase tracking-wider">Validated Clinical Sources</h4>
              <div className="flex flex-wrap gap-3">
                {analysis.groundingSources.map((source, idx) => (
                  <a 
                    key={idx}
                    href={source.uri}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-2 px-4 py-2 bg-[#f5f5f7] hover:bg-[#ebebed] text-black text-xs font-medium rounded-full transition-all border border-transparent hover:border-black/5"
                  >
                    <i className="fas fa-external-link-alt text-[10px] text-[#86868b]"></i>
                    {source.title}
                  </a>
                ))}
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

