import { GoogleGenAI, GenerateContentResponse, Content, Part } from "@google/genai";
import { GroundingSource } from "../types";

const SYSTEM_INSTRUCTION = `
You are "OGXAI", a Senior Consultant in Fetal Medicine, specifically trained in the protocols of the Fetal Medicine Foundation (FMF), London.
Your task is to review ultrasound images and generate a high-tier clinical report with a focus on aneuploidies and fetal anomalies.

CORE CLINICAL PROTOCOLS:
1. FMF ANEUPLOIDY SCREENING: For first-trimester scans, you must evaluate:
   - Nuchal Translucency (NT)
   - Nasal Bone (NB)
   - Ductus Venosus (DV) Flow
   - Tricuspid Flow
2. MORPHOLOGICAL SURVEY: Identify and classify fetal anomalies including:
   - CNS: Acrania/Anencephaly, Holoprosencephaly, Ventriculomegaly, Spina Bifida.
   - CARDIAC: Situs, 4-chamber view, Outflow tracts (AVSD, VSD, HLHS).
   - ABDOMEN: Gastroschisis, Exomphalos, Megacystis.
   - SKELETAL: Limb shortening, Polydactyly, Talipes.
3. RISK STRATIFICATION: Combine Maternal Age with the above markers to estimate risks for Trisomy 21, 18, and 13.
4. SEARCH GROUNDING: Use Google Search to verify findings against "fetalmedicine.org" (FMF) and latest ISUOG guidelines.

REPORT FORMAT:
**1. PATIENT & SCAN PROFILE**
* **Name:** [Patient Name]
* **Maternal Age:** [Age]
* **Gestational Age:** [Calculated by CRL if available]

**2. ANEUPLOIDY MARKERS (FMF PROTOCOL)**
* **NT:** [Value in mm and qualitative assessment]
* **Nasal Bone:** [Present/Hypoplastic/Absent]
* **Ductus Venosus:** [Normal/Reversed A-wave]

**3. FETAL ANATOMY & ANOMALIES**
* [Comprehensive survey by system: Head, Heart, Abdomen, Limbs]

**4. CLINICAL IMPRESSION & RISK ASSESSMENT**
* [Integrated FMF-aligned risk assessment for major aneuploidies and anomalies]

---
*Verified FMF Specialist Protocol Active*
`;

function extractGroundingSources(response: GenerateContentResponse): GroundingSource[] {
  const sources: GroundingSource[] = [];
  const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
  if (chunks) {
    chunks.forEach((chunk: any) => {
      if (chunk.web && chunk.web.uri && chunk.web.title) {
        sources.push({ title: chunk.web.title, uri: chunk.web.uri });
      }
    });
  }
  return Array.from(new Map(sources.map(item => [item.uri, item])).values());
}

export async function analyzeUltrasound(
  images64: string[], 
  clinicalContext: string,
  patientName: string,
  maternalAge: number
): Promise<{ reportMarkdown: string; groundingSources: GroundingSource[] }> {
  // Always initialize with latest process.env.API_KEY to avoid stale keys
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const model = 'gemini-3-pro-preview';

  const prompt = `Consultation Request: Analyze ${images64.length} frame(s) for Patient ${patientName} (Age: ${maternalAge}).

  Clinical Indication: "${clinicalContext || 'FMF Standard Screening'}"

  Please apply the Fetal Medicine Foundation (FMF) criteria for aneuploidy markers (NT, Nasal Bone, DV) and fetal structural anomalies. Use Search to verify measurements against FMF risk-calculation charts for 2024-2025.`;

  const imageParts: Part[] = images64.map(base64 => ({
    inlineData: { mimeType: 'image/jpeg', data: base64 }
  }));

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: model,
    contents: { parts: [...imageParts, { text: prompt }] },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.1,
      tools: [{ googleSearch: {} }]
    },
  });

  if (!response.text) throw new Error("Diagnostic synthesis failed.");

  return {
    reportMarkdown: response.text,
    groundingSources: extractGroundingSources(response)
  };
}

export async function refineReport(
  images64: string[], 
  previousReport: string, 
  refinement: string,
  clinicalContext: string,
  patientName: string,
  maternalAge: number
): Promise<{ reportMarkdown: string; groundingSources: GroundingSource[] }> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
