import LoadingOverlay from './components/LoadingOverlay.tsx';
import AccessGate from './components/AccessGate.tsx';

const App: React.FC = () => {
  const [isAuthorized, setIsAuthorized] = useState<boolean>(false);
  const [images, setImages] = useState<string[]>([]);
  const [clinicalContext, setClinicalContext] = useState('');
  const [patientName, setPatientName] = useState('');
  const [maternalAge, setMaternalAge] = useState<number>(30);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isRefining, setIsRefining] = useState(false);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  useEffect(() => {
    try {
      const authStatus = sessionStorage.getItem('ogxai_authorized');
      if (authStatus === 'true') {
        setIsAuthorized(true);
      }
    } catch (e) {
      console.warn("Session storage unavailable", e);
    }
  }, []);

  const handleLoginSuccess = () => {
    setIsAuthorized(true);
    try {
      sessionStorage.setItem('ogxai_authorized', 'true');
    } catch (e) {}
  };

  const handleImagesChange = (newImages: string[]) => {
    setImages(newImages);
    if (newImages.length === 0) setAnalysis(null);
    setStatus(prev => ({ ...prev, error: null }));
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;

    // API Key logic for AI Studio environment
    if (window.aistudio) {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) {
          await window.aistudio.openSelectKey();
        }
      } catch (e) {
        console.error("AI Studio key manager failed", e);
      }
    }

    setStatus({ isAnalyzing: true, progressMessage: 'Verifying markers against FMF protocols...', error: null });

    try {
      const result = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ 
        reportMarkdown: result.reportMarkdown, 
        timestamp: new Date().toLocaleString(),
        groundingSources: result.groundingSources
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      console.error("Analysis error:", err);

      const errorMessage = err.message || "";
      if (errorMessage.includes("Requested entity was not found")) {
        setStatus({ isAnalyzing: false, progressMessage: '', error: "Session expired or API key invalid. Please re-authorize." });
        if (window.aistudio) {
          await window.aistudio.openSelectKey();
        }
      } else {
        setStatus({ isAnalyzing: false, progressMessage: '', error: err.message || 'Diagnostic cycle failed. Please check your network connection.' });
      }
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (!analysis) return;
    setIsRefining(true);
    try {
      const result = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ 
        ...analysis, 
        reportMarkdown: result.reportMarkdown, 
        timestamp: new Date().toLocaleString() + " (Revised)",
        groundingSources: result.groundingSources
      });
    } catch (err: any) {
      setStatus(prev => ({ ...prev, error: 'Clinical revision failed. Please try again.' }));
    } finally {
      setIsRefining(false);
    }
  };

  if (!isAuthorized) return <AccessGate onGrantAccess={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-[#f5f5f7]">
      <Header />

      <main className="flex-grow container mx-auto px-6 py-12 md:py-24 max-w-[1100px]">
        <div className="text-center mb-16 md:mb-24">
           <h2 className="text-4xl md:text-6xl font-bold tracking-tight text-[#1d1d1f] mb-6">Fetal Intelligence. Advanced.</h2>
           <p className="text-xl md:text-2xl text-[#86868b] font-medium max-w-2xl mx-auto tracking-tight leading-relaxed">
             Diagnostic excellence in aneuploidy screening and fetal morphology, powered by FMF Specialist AI.
           </p>
        </div>

        <div className="grid grid-cols-1 gap-12">

          <div className="order-2 lg:order-1">
            <section className="apple-card p-8 md:p-16">
              <div className="flex items-center gap-4 mb-12">
                <span className="text-[14px] font-bold text-[#D4AF37] bg-[#D4AF37]/5 px-3 py-1 rounded-full uppercase tracking-tight">Specialist Protocol</span>
                <h3 className="text-2xl font-bold">Clinical Data Entry</h3>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-8">
                  <div>
                    <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-3 block">Patient Information</label>
                    <input 
                      type="text"
                      value={patientName}
                      onChange={(e) => setPatientName(e.target.value)}
                      placeholder="Enter Patient Full Name"
                      className="apple-input"
                      disabled={status.isAnalyzing}
                    />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-3 block">Maternal Age (Years)</label>
                    <input 
                      type="number"
                      value={maternalAge}
                      onChange={(e) => setMaternalAge(parseInt(e.target.value) || 30)}
                      className="apple-input"
                      disabled={status.isAnalyzing}
                    />
                  </div>
                  <div>
                    <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-3 block">Scan Context / CRL / LMP</label>
                    <textarea 
                      value={clinicalContext}
                      onChange={(e) => setClinicalContext(e.target.value)}
                      placeholder="Provide LMP, CRL, or specific clinical concerns..."
                      className="apple-input leading-relaxed h-32 resize-none"
