                <div>
                  <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-3 block">Ultrasound Scan Assets</label>
                  <ImageUploader onImagesChange={handleImagesChange} images={images} disabled={status.isAnalyzing} />
                </div>
