                  >
                    {status.isAnalyzing ? <i className="fas fa-spinner fa-spin"></i> : <i className="fas fa-microscope"></i>}
                    {status.isAnalyzing ? 'Analyzing FMF Markers...' : 'Initiate Fetal Survey'}
                  </button>
