const ReportDisplay: React.FC<Props> = ({ analysis, onUpdate, isUpdating, onReset }) => {

  // Helper to bold text inside a string (e.g. "Values are **Normal**")
  const parseInlineBold = (text: string) => {
    const parts = text.split(/(\*\*.*?\*\*)/g);
    return parts.map((part, index) => {
      if (part.startsWith('**') && part.endsWith('**')) {
        return <span key={index} className="font-semibold text-black">{part.slice(2, -2)}</span>;
      }
      return part;
    });
  };

  const parseContent = (text: string) => {
    // Clean up excessive punctuation artifacts
    const cleanText = text.replace(/!!/g, '.').replace(/\.{2,}/g, '.');

    return cleanText.split('\n').map((line, i) => {
      const trimmed = line.trim();
      if (!trimmed) return <div key={i} className="h-2" />;

      // 1. Headers (### or ##) -> Clean, small subtitles
      if (trimmed.startsWith('#')) {
        const content = trimmed.replace(/^#+\s*/, '').replace(/\*\*/g, '');
        return (
          <h4 key={i} className="text-xs font-bold text-[#86868b] uppercase tracking-widest mt-8 mb-3 border-b border-black/5 pb-2">
            {content}
          </h4>
        );
      }

      // 2. Bold Line Headers (Alternative subtitle format often used by AI)
      // e.g. "**Head & Brain:**" on its own line
      if (trimmed.startsWith('**') && trimmed.endsWith('**') && trimmed.length < 60) {
        const content = trimmed.replace(/\*\*/g, '');
        return (
          <h5 key={i} className="text-sm font-bold text-black mt-6 mb-2 tracking-tight">
            {content}
          </h5>
        );
      }

      // 3. Key-Value pairs (e.g., "**Nasal Bone:** Present")
      // Check if line starts with bolded text followed by colon
      const keyValMatch = trimmed.match(/^\*\*([^*]+)\*\*:(.*)/);
      if (keyValMatch) {
         return (
            <div key={i} className="flex flex-col sm:flex-row gap-1 sm:gap-4 mb-3 text-sm">
                <span className="font-semibold text-[#86868b] sm:w-36 shrink-0 text-xs sm:text-sm uppercase sm:normal-case tracking-wide sm:tracking-normal pt-1 sm:pt-0">
                  {keyValMatch[1]}
                </span>
                <span className="text-black/90 leading-relaxed font-medium">
                  {parseInlineBold(keyValMatch[2])}
                </span>
            </div>
         );
      }

      // 4. List Items (* or -)
      if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
        const content = trimmed.replace(/^[\*\-]\s*/, '');
        return (
          <div key={i} className="flex gap-3 mb-2 pl-2">
            <span className="text-[#d4af37] text-[10px] mt-1.5 shrink-0">●</span>
            <p className="text-sm text-black/80 leading-relaxed">
              {parseInlineBold(content)}
            </p>
          </div>
        );
      }

      // 5. Numbered Lists (1. )
      if (/^\d+\./.test(trimmed)) {
        const match = trimmed.match(/^(\d+)\.\s+(.*)/);
        if (match) {
            return (
                <div key={i} className="flex gap-3 mb-3 mt-2">
                    <span className="text-sm font-bold text-[#d4af37]">{match[1]}.</span>
                    <p className="text-sm text-black/90 leading-relaxed font-medium">
                        {parseInlineBold(match[2])}
                    </p>
                </div>
            );
        }
      }

      // 6. Regular paragraphs
      return (
        <p key={i} className="text-sm text-black/70 leading-7 mb-4">
          {parseInlineBold(line)}
        </p>
      );
    });
  };

  return (
    <div className="flex flex-col gap-12 animate-in fade-in duration-1000">
      <div className="apple-card overflow-hidden">
        {/* Header Section */}
        <div className="bg-[#f5f5f7]/50 border-b border-black/5 px-8 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="w-2 h-2 rounded-full bg-[#34c759]"></div>
            <h2 className="text-[10px] font-bold text-[#86868b] uppercase tracking-widest">Clinical Dossier</h2>
          </div>
          <div className="flex gap-4">
            <button onClick={() => window.print()} className="text-[#d2d2d7] hover:text-black transition-colors" title="Print"><i className="fas fa-print"></i></button>
            <button onClick={() => navigator.clipboard.writeText(analysis.reportMarkdown)} className="text-[#d2d2d7] hover:text-black transition-colors" title="Copy"><i className="fas fa-copy"></i></button>
          </div>
        </div>

        <div className="p-8 md:p-12 relative bg-white">
          {isUpdating && (
            <div className="absolute inset-0 bg-white/90 z-50 flex flex-col items-center justify-center transition-all backdrop-blur-sm">
              <div className="w-8 h-8 border-2 border-black/10 border-t-[#d4af37] rounded-full animate-spin mb-4"></div>
              <p className="text-[10px] font-bold text-[#86868b] uppercase tracking-widest">Updating Clinical Context...</p>
            </div>
          )}

          {/* Title Area */}
          <div className="flex flex-col md:flex-row justify-between items-end border-b border-black/5 pb-8 mb-8">
            <div>
              <h1 className="text-2xl md:text-3xl font-bold tracking-tight mb-2 text-[#1d1d1f]">Diagnostic Report</h1>
              <p className="text-[10px] font-bold text-[#d4af37] uppercase tracking-[0.2em]">Fetal Medicine Foundation Protocol</p>
            </div>
            <div className="text-right mt-4 md:mt-0">
               <div className="text-[10px] font-medium text-[#86868b]">Generated: {analysis.timestamp}</div>
            </div>
          </div>

          {/* Content Area */}
          <div className="report-content max-w-4xl mx-auto">
            {parseContent(analysis.reportMarkdown)}
          </div>

          {/* Footer / Grounding */}
          {analysis.groundingSources && analysis.groundingSources.length > 0 && (
            <div className="mt-16 pt-8 border-t border-black/5">
              <h4 className="text-[9px] font-bold text-[#86868b] mb-4 uppercase tracking-widest">Verified References</h4>
              <div className="flex flex-wrap gap-2">
                {analysis.groundingSources.map((source, idx) => (
                  <a 
                    key={idx}
                    href={source.uri}
                    target="_blank"
                    rel="noopener noreferrer"
                    className="inline-flex items-center gap-2 px-3 py-1.5 bg-[#f5f5f7] hover:bg-[#ebebed] text-black text-[10px] font-medium rounded-md transition-all truncate max-w-[200px]"
                  >
                    <i className="fas fa-link text-[#d4af37]"></i>
                    <span className="truncate">{source.title}</span>
