import { GoogleGenAI, GenerateContentResponse, Content, Part } from "@google/genai";
import { GroundingSource } from "../types.ts";

const SYSTEM_INSTRUCTION = `
You are "OGXAI", a Senior Consultant in Fetal Medicine.
Review ultrasound images and generate clinical reports focused on aneuploidy screening and fetal morphology based on FMF (London) protocols.
Evaluate NT, Nasal Bone, and major organs (Heart, Brain, Abdomen).
Estimated risks for T21, T18, T13 should be discussed relative to maternal age and sonographic markers.
Always use Google Search to cross-reference findings with ISUOG and FMF guidelines.

FORMATTING RULES:
1. Use standard Markdown.
2. Use '###' for Section Headers (e.g. ### Fetal Biometry).
3. Use '**' for key findings (e.g. **Nasal Bone:** Present).
4. Do NOT use '!!' or excessive punctuation.
5. Be professional, concise, and clinical.
`;

function extractGroundingSources(response: GenerateContentResponse): GroundingSource[] {
  const sources: GroundingSource[] = [];
  try {
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (chunks) {
      chunks.forEach((chunk: any) => {
        if (chunk.web && chunk.web.uri) {
          sources.push({ title: chunk.web.title || "Clinical Reference", uri: chunk.web.uri });
        }
      });
    }
  } catch (e) {
    console.warn("Grounding extraction failed", e);
  }
  return Array.from(new Map(sources.map(item => [item.uri, item])).values());
}

function getAIClient() {
  // Safely access process.env.API_KEY
  let apiKey = "";
  try {
    if (typeof process !== "undefined" && process.env) {
      apiKey = process.env.API_KEY || "";
    }
  } catch (e) {
    // Ignore reference errors
  }

  if (!apiKey) {
    throw new Error("Clinical API Key missing. Please click 'Authorize Session' in the top right corner to select your key.");
  }
  return new GoogleGenAI({ apiKey });
}

export async function analyzeUltrasound(
  images64: string[], 
  clinicalContext: string,
  patientName: string,
  maternalAge: number
): Promise<{ reportMarkdown: string; groundingSources: GroundingSource[] }> {
  const ai = getAIClient();
  const model = 'gemini-3-pro-preview';

  const prompt = `Fetal Medicine Consultation:
  Patient: ${patientName}
  Age: ${maternalAge}
  Indication: ${clinicalContext || 'Routine Screening'}
  Analyze attached ${images64.length} ultrasound frames. Use search to verify clinical markers against latest fetal medicine standards.`;

  const imageParts: Part[] = images64.map(base64 => ({
    inlineData: { mimeType: 'image/jpeg', data: base64 }
  }));

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: model,
    contents: { parts: [...imageParts, { text: prompt }] },
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.1,
      tools: [{ googleSearch: {} }]
    },
  });

  if (!response.text) throw new Error("Synthesis failed. No diagnostic data returned.");

  return {
    reportMarkdown: response.text,
    groundingSources: extractGroundingSources(response)
  };
}

export async function refineReport(
  images64: string[], 
  previousReport: string, 
  refinement: string,
  clinicalContext: string,
  patientName: string,
  maternalAge: number
): Promise<{ reportMarkdown: string; groundingSources: GroundingSource[] }> {
  const ai = getAIClient();
  const model = 'gemini-3-pro-preview';

  const imageParts: Part[] = images64.map(base64 => ({
    inlineData: { mimeType: 'image/jpeg', data: base64 }
  }));

  const contents: Content[] = [
    {
      role: 'user',
      parts: [...imageParts, { text: `Refinement request for Patient ${patientName}.` }]
    },
    { role: 'model', parts: [{ text: previousReport }] },
    { role: 'user', parts: [{ text: refinement }] }
  ];

  const response = await ai.models.generateContent({
    model: model,
    contents: contents,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      temperature: 0.1,
      tools: [{ googleSearch: {} }]
    },
  });

  if (!response.text) throw new Error("Refinement cycle failed.");
  return { reportMarkdown: response.text, groundingSources: extractGroundingSources(response) };
}

