      if (window.aistudio) {
        await window.aistudio.openSelectKey();
        const hasKey = await window.aistudio.hasSelectedApiKey();
        setIsConnected(hasKey);
      } else {
        alert("Clinical Environment Error: AI Studio integration is missing. Please ensure you are running this within the correct secure context.");
      }
    } catch (err) {
      console.error("Failed to open key selection:", err);
      alert("Authorization interface failed to load. Please refresh.");
    }
  };

  return (
    <header className="sticky top-0 z-50 border-b border-black/5 h-[64px] flex items-center bg-[#E5E5EA]/80 backdrop-blur-md">
      <div className="container mx-auto px-6 max-w-[1200px] flex items-center justify-between">
