          <div className="flex flex-col">
            <h1 className="text-lg font-bold tracking-tight leading-none text-[#1C1C1E]">
              OGX AI <span className="font-normal opacity-60 ml-1 hidden sm:inline">| Intelligent Ultrasound</span>
            </h1>
          </div>
        </div>

        <div className="flex items-center gap-6">
          <button 
            onClick={handleKeySetup}
            className={`text-[12px] font-medium tracking-tight px-4 py-1.5 rounded-full transition-all border ${
              isConnected 
                ? 'bg-white/50 text-[#1C1C1E] border-transparent hover:bg-white/80' 
                : 'bg-[#1C1C1E] text-white border-transparent hover:opacity-90'
            }`}
          >
            {isConnected ? 'Consultant Verified' : 'Authorize Session'}
          </button>
        </div>
      </div>
    </header>
  );
};

