import React, { useState, useEffect } from 'react';
import { analyzeUltrasound, refineReport } from './services/geminiService.ts';
import { AnalysisResult, ProcessingState } from './types.ts';
import Header from './components/Header.tsx';
import ImageUploader from './components/ImageUploader.tsx';
import ReportDisplay from './components/ReportDisplay.tsx';
import LoadingOverlay from './components/LoadingOverlay.tsx';
import AccessGate from './components/AccessGate.tsx';

const App: React.FC = () => {
  const [isAuthorized, setIsAuthorized] = useState<boolean>(false);
  const [images, setImages] = useState<string[]>([]);
  const [clinicalContext, setClinicalContext] = useState('');
  const [patientName, setPatientName] = useState('');
  const [maternalAge, setMaternalAge] = useState<number>(30);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [isRefining, setIsRefining] = useState(false);
  const [status, setStatus] = useState<ProcessingState>({
    isAnalyzing: false,
    progressMessage: '',
    error: null,
  });

  useEffect(() => {
    try {
      const authStatus = sessionStorage.getItem('ogxai_authorized');
      if (authStatus === 'true') {
        setIsAuthorized(true);
      }
    } catch (e) {
      console.warn("Storage restricted", e);
    }
  }, []);

  const handleLoginSuccess = () => {
    setIsAuthorized(true);
    try {
      sessionStorage.setItem('ogxai_authorized', 'true');
    } catch (e) {}
  };

  const startAnalysis = async () => {
    if (images.length === 0) return;

    if (window.aistudio) {
      try {
        const hasKey = await window.aistudio.hasSelectedApiKey();
        if (!hasKey) await window.aistudio.openSelectKey();
      } catch (e) {
        console.warn("AI Studio key error", e);
      }
    }

    setStatus({ isAnalyzing: true, progressMessage: 'Initiating Specialist Protocol...', error: null });

    try {
      const result = await analyzeUltrasound(
        images.map(img => img.split(',')[1]),
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ 
        reportMarkdown: result.reportMarkdown, 
        timestamp: new Date().toLocaleString(),
        groundingSources: result.groundingSources
      });
      setStatus({ isAnalyzing: false, progressMessage: '', error: null });
    } catch (err: any) {
      console.error("Clinical error:", err);
      const msg = err.message || "";
      if (msg.includes("Requested entity was not found")) {
        setStatus({ isAnalyzing: false, progressMessage: '', error: "Auth session expired. Please re-authorize via button above." });
        if (window.aistudio) await window.aistudio.openSelectKey();
      } else {
        setStatus({ isAnalyzing: false, progressMessage: '', error: err.message || 'Diagnostic cycle interrupted.' });
      }
    }
  };

  const onUpdateReport = async (comment: string) => {
    if (!analysis) return;
    setIsRefining(true);
    try {
      const result = await refineReport(
        images.map(img => img.split(',')[1]),
        analysis.reportMarkdown,
        comment,
        clinicalContext,
        patientName,
        maternalAge
      );
      setAnalysis({ 
        ...analysis, 
        reportMarkdown: result.reportMarkdown, 
        timestamp: new Date().toLocaleString() + " (Updated)",
        groundingSources: result.groundingSources
      });
    } catch (err: any) {
      setStatus(s => ({ ...s, error: 'Refinement rejected by model.' }));
    } finally {
      setIsRefining(false);
    }
  };

  const resetSession = () => {
    if (window.confirm("End current clinical session? This will clear all patient data and images.")) {
      setImages([]);
      setClinicalContext('');
      setPatientName('');
      setMaternalAge(30);
      setAnalysis(null);
      setIsRefining(false);
      setStatus({
        isAnalyzing: false,
        progressMessage: '',
        error: null,
      });
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  if (!isAuthorized) return <AccessGate onGrantAccess={handleLoginSuccess} />;

  return (
    <div className="min-h-screen flex flex-col bg-[#F2F2F7]">
      <Header />
      <main className="flex-grow container mx-auto px-6 py-12 md:py-20 max-w-[1100px]">
        {/* Hero Section */}
        <div className="text-center mb-16">
           <h2 className="text-4xl md:text-5xl font-bold tracking-tight text-[#1C1C1E] mb-4">Clinical Intelligence</h2>
           <p className="text-lg text-[#3A3A3C] font-normal max-w-xl mx-auto leading-relaxed">
             Advanced morphology and aneuploidy screening protocol.
           </p>
        </div>

        <div className="grid grid-cols-1 gap-8">
          {/* Main Input Card */}
          <section className="apple-card p-6 md:p-10 bg-white">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
              <div className="space-y-6">
                <div>
                  <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-2 block">Patient Identification</label>
                  <input 
                    type="text"
                    value={patientName}
                    onChange={(e) => setPatientName(e.target.value)}
                    placeholder="Name or ID"
                    className="apple-input"
                    disabled={status.isAnalyzing}
                  />
                </div>
                <div>
                  <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-2 block">Maternal Age</label>
                  <input 
                    type="number"
                    value={maternalAge}
                    onChange={(e) => setMaternalAge(parseInt(e.target.value) || 30)}
                    className="apple-input"
                    disabled={status.isAnalyzing}
                  />
                </div>
                <div>
                  <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-2 block">Clinical Indications</label>
                  <textarea 
                    value={clinicalContext}
                    onChange={(e) => setClinicalContext(e.target.value)}
                    placeholder="Enter LMP, CRL, or specific diagnostic concerns..."
                    className="apple-input h-32 resize-none"
                    disabled={status.isAnalyzing}
                  />
                </div>
              </div>
              <div>
                <label className="text-xs font-semibold text-[#86868b] uppercase tracking-wider mb-2 block">Imaging Data</label>
                <ImageUploader onImagesChange={(imgs) => { setImages(imgs); setStatus(s => ({ ...s, error: null })); }} images={images} disabled={status.isAnalyzing} />
              </div>
            </div>

            {images.length > 0 && !analysis && (
              <div className="mt-12 flex justify-center">
                <button
                  onClick={startAnalysis}
                  disabled={status.isAnalyzing}
                  className="apple-button w-full md:w-auto px-12 bg-[#5B6876] hover:bg-[#4A5562]"
                >
                  {status.isAnalyzing ? 'Processing Protocol...' : 'Generate Clinical Report'}
                </button>
              </div>
            )}
          </section>

          {/* Disclaimer Section */}
          <div className="bg-[#FFF4E5] border border-[#FFDbb0] rounded-xl p-6 flex flex-col md:flex-row gap-4 items-start shadow-sm">
             <div className="text-[#D97706] text-xl mt-1"><i className="fas fa-exclamation-triangle"></i></div>
             <div>
                <h4 className="text-[#9A3412] font-bold text-sm uppercase tracking-wide mb-1">Important Disclaimer</h4>
                <p className="text-[#9A3412]/80 text-xs leading-relaxed">
                  This application (OGXAI) is currently in a <strong>training and development phase</strong>. The results provided are for research and testing purposes only. 
                  This AI system <strong>DOES NOT replace the professional medical judgment of a human doctor</strong>. All findings must be verified by a qualified OB/GYN specialist.
                </p>
             </div>
          </div>

          {status.error && (
            <div className="apple-card p-6 bg-red-50 border border-red-100 text-red-600 text-sm font-medium">
              <i className="fas fa-info-circle mr-2"></i> {status.error}
            </div>
          )}

          {analysis && <ReportDisplay analysis={analysis} onUpdate={onUpdateReport} isUpdating={isRefining} onReset={resetSession} />}
          {status.isAnalyzing && <LoadingOverlay message={status.progressMessage} />}
        </div>
      </main>
      <footer className="py-12 border-t border-black/5 text-center">
        <p className="text-xs text-[#86868b] font-medium tracking-tight">
          © 2024 OGXAI Systems. All rights reserved.
        </p>
      </footer>
    </div>
  );
};

export default App;

