              className={`w-full bg-[#f5f5f7] rounded-2xl p-5 text-center text-black font-semibold tracking-widest text-lg outline-none transition-all ${error ? 'border-red-500 border' : 'border-transparent border focus:border-black/10'}`}
              style={{ fontSize: '18px' }} // Explicit for iOS
